INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-1', 'main-1', 'main-1', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§1.0 Regelunklarheiten & Nachfragpflicht', 1, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-1-v1', 'rule-main-1', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§1.1 Sollte eine Regel unklar sein oder Ungewissheit darüber bestehen, ob eine bestimmte Handlung im Roleplay erlaubt ist, darf nicht eigenständig entschieden werden."}]},{"type":"paragraph","content":[{"type":"text","text":"§1.2 In solchen Fällen ist unverzüglich ein Mitglied des Staff Teams zu kontaktieren, um eine verbindliche Klärung zu erhalten."}]},{"type":"paragraph","content":[{"type":"text","text":"§1.3 Ausnahmen, Sonderregelungen oder mündliche Zusagen durch Staff oder Fraktionsmanagement sind nicht gültig. Verstöße werden unabhängig davon geahndet; die Verantwortung liegt stets bei der handelnden Person."}]},{"type":"paragraph","content":[{"type":"text","text":"§1.4 Das absichtliche Ausnutzen unklarer Regelungen oder das eigenständige Auslegen von Regeln ohne Rücksprache wird als Regelbruch gewertet und entsprechend bestraft."}]},{"type":"paragraph","content":[{"type":"text","text":"§1.5 Verantwortlich für die Nachfrage ist immer der jeweilige Spieler selbst – Unwissenheit schützt nicht vor Konsequenzen."}]},{"type":"paragraph","content":[{"type":"text","text":"§1.6 Für Anfragen stehen das Ticketsystem im Discord, oder ein On-Duty Staff Mitglied zur Verfügung."}]},{"type":"paragraph","content":[{"type":"text","text":"§1.7 Wer trotz Unsicherheit handelt, ohne das Team zu informieren, riskiert eine Verwarnung oder härtere Sanktionen – unabhängig davon, wie die Situation im Nachhinein bewertet wird."}]},{"type":"paragraph","content":[{"type":"text","text":"§1.8 Die Roblox ToS Die Nutzerbedingungen (Terms of Service) sind jederzeit und uneingeschränkt einzuhalten."}]},{"type":"paragraph","content":[{"type":"text","text":"§1.9 Keine Person steht über diese Niedergeschriebenen Regeln, die ausnahme ist der Founder (Keys) und die Co-Founder Firefox. Jeder hat stehts diese Regeln einzuhalten."}]},{"type":"paragraph","content":[{"type":"text","text":"§1.10 Jeder Spieler ist verpflichtet, im gesamten Roleplay sowie im Umgang miteinander den gesunden Menschenverstand anzuwenden."}]},{"type":"paragraph","content":[{"type":"text","text":"§1.11 Alle Regelverstöße werden situativ und einzelfallbezogen bewertet. Es gibt keine vollständig starren Strafen, die unabhängig vom Kontext angewendet werden."}]},{"type":"paragraph","content":[{"type":"text","text":"§1.12 Das Regelwerk gilt jederzeit uneingeschränkt – unabhängig davon, ob aktuell aktives Roleplay stattfindet oder nicht."}]},{"type":"paragraph","content":[{"type":"text","text":"Ein sogenannter „RP-Start“ oder „RP-Stop“ setzt keine Regeln außer Kraft und stellt keine Ausnahme von bestehenden Vorschriften dar."}]},{"type":"paragraph","content":[{"type":"text","text":"§1.13 Das Regelwerk gilt für alle Spieler gleichermaßen. CC, CF, Fraktionsleitungen noch andere Personen sind befugt, eigenständig Ausnahmen von bestehenden Regeln zu erteilen. Nicht genehmigte Ausnahmen sind unwirksam. Regelverstöße werden unabhängig von Funktion, Rang oder Status entsprechend geahndet."}]}]}'::jsonb, '§1.0 Regelunklarheiten & Nachfragpflicht §1.1 Sollte eine Regel unklar sein oder Ungewissheit darüber bestehen, ob eine bestimmte Handlung im Roleplay erlaubt ist, darf nicht eigenständig entschieden werden. §1.2 In solchen Fällen ist unverzüglich ein Mitglied des Staff Teams zu kontaktieren, um eine verbindliche Klärung zu erhalten. §1.3 Ausnahmen, Sonderregelungen oder mündliche Zusagen durch Staff oder Fraktionsmanagement sind nicht gültig. Verstöße werden unabhängig davon geahndet; die Verantwortung liegt stets bei der handelnden Person. §1.4 Das absichtliche Ausnutzen unklarer Regelungen oder das eigenständige Auslegen von Regeln ohne Rücksprache wird als Regelbruch gewertet und entsprechend bestraft. §1.5 Verantwortlich für die Nachfrage ist immer der jeweilige Spieler selbst – Unwissenheit schützt nicht vor Konsequenzen. §1.6 Für Anfragen stehen das Ticketsystem im Discord, oder ein On-Duty Staff Mitglied zur Verfügung. §1.7 Wer trotz Unsicherheit handelt, ohne das Team zu informieren, riskiert eine Verwarnung oder härtere Sanktionen – unabhängig davon, wie die Situation im Nachhinein bewertet wird. §1.8 Die Roblox ToS Die Nutzerbedingungen (Terms of Service) sind jederzeit und uneingeschränkt einzuhalten. §1.9 Keine Person steht über diese Niedergeschriebenen Regeln, die ausnahme ist der Founder (Keys) und die Co-Founder Firefox. Jeder hat stehts diese Regeln einzuhalten. §1.10 Jeder Spieler ist verpflichtet, im gesamten Roleplay sowie im Umgang miteinander den gesunden Menschenverstand anzuwenden. §1.11 Alle Regelverstöße werden situativ und einzelfallbezogen bewertet. Es gibt keine vollständig starren Strafen, die unabhängig vom Kontext angewendet werden. §1.12 Das Regelwerk gilt jederzeit uneingeschränkt – unabhängig davon, ob aktuell aktives Roleplay stattfindet oder nicht. Ein sogenannter „RP-Start“ oder „RP-Stop“ setzt keine Regeln außer Kraft und stellt keine Ausnahme von bestehenden Vorschriften dar. §1.13 Das Regelwerk gilt für alle Spieler gleichermaßen. CC, CF, Fraktionsleitungen noch andere Personen sind befugt, eigenständig Ausnahmen von bestehenden Regeln zu erteilen. Nicht genehmigte Ausnahmen sind unwirksam. Regelverstöße werden unabhängig von Funktion, Rang oder Status entsprechend geahndet.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-2', 'main-2', 'main-2', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§2.0 OOC Talk', 2, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-2-v1', 'rule-main-2', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§2.1 Während einer aktiven Roleplay-Situation darf ausschließlich im Rahmen der eigenen Rolle gesprochen und gehandelt werden. Aussagen oder Verhalten, die nichts mit dem Charakter zu tun haben, stören den Spielfluss und sind nicht erlaubt. Ziel ist ein realistisches und immersives RP-Erlebnis für alle Beteiligten."}]},{"type":"paragraph","content":[{"type":"text","text":"§2.2 Jegliche Handlungen und Entscheidungen müssen innerhalb der Charakters erfolgen; das bewusste vermischen von In-Character- (IC) und Out-Of-Character- (OOC) Informationen ist strengstens untersagt."}]},{"type":"paragraph","content":[{"type":"text","text":"§2.3 Wenn es ausnahmsweise notwendig ist, außerhalb des Rollenspiels (OOC) etwas zu sagen oder zu schreiben, muss dies klar mit Klammern () gekennzeichnet werden. So bleibt erkennbar, was Teil des RP ist – und was nicht. Dauerhafte oder unnötige OOC-Kommentare innerhalb des RP sind zu vermeiden."}]}]}'::jsonb, '§2.0 OOC Talk §2.1 Während einer aktiven Roleplay-Situation darf ausschließlich im Rahmen der eigenen Rolle gesprochen und gehandelt werden. Aussagen oder Verhalten, die nichts mit dem Charakter zu tun haben, stören den Spielfluss und sind nicht erlaubt. Ziel ist ein realistisches und immersives RP-Erlebnis für alle Beteiligten. §2.2 Jegliche Handlungen und Entscheidungen müssen innerhalb der Charakters erfolgen; das bewusste vermischen von In-Character- (IC) und Out-Of-Character- (OOC) Informationen ist strengstens untersagt. §2.3 Wenn es ausnahmsweise notwendig ist, außerhalb des Rollenspiels (OOC) etwas zu sagen oder zu schreiben, muss dies klar mit Klammern () gekennzeichnet werden. So bleibt erkennbar, was Teil des RP ist – und was nicht. Dauerhafte oder unnötige OOC-Kommentare innerhalb des RP sind zu vermeiden.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-3', 'main-3', 'main-3', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§3.0 Voice Chat (VC), Discord Talk´s Nutzung', 3, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-3-v1', 'rule-main-3', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§3.1 Die Nutzung von Voice-Chat (VC), sei es über Discord oder andere Plattformen, ist im Zusammenhang mit Roleplay-Situationen auf unserem Server grundsätzlicherlaubt. Dennoch ist auf fairnes zu achten und ggf. auch auf den Ingame Chat zurückzugreifen sofern nicht alle Discord / Voice Chat besitzen."}]},{"type":"paragraph","content":[{"type":"text","text":"§3.2 Die RP-Regeln sind im gesamten Chat bindend. Spieler dürfen nach Absprache schriftliches Rollenspiel im Chat durchführen."}]},{"type":"paragraph","content":[{"type":"text","text":"§3.3 Sowohl im VC (Voice Chat) als auch auf den RP-Talks auf den Discord ist auf Höflichkeit und die jeweiligen ToS zu achten."}]}]}'::jsonb, '§3.0 Voice Chat (VC), Discord Talk´s Nutzung §3.1 Die Nutzung von Voice-Chat (VC), sei es über Discord oder andere Plattformen, ist im Zusammenhang mit Roleplay-Situationen auf unserem Server grundsätzlicherlaubt. Dennoch ist auf fairnes zu achten und ggf. auch auf den Ingame Chat zurückzugreifen sofern nicht alle Discord / Voice Chat besitzen. §3.2 Die RP-Regeln sind im gesamten Chat bindend. Spieler dürfen nach Absprache schriftliches Rollenspiel im Chat durchführen. §3.3 Sowohl im VC (Voice Chat) als auch auf den RP-Talks auf den Discord ist auf Höflichkeit und die jeweiligen ToS zu achten.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-4', 'main-4', 'main-4', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§4.0 Meta Gaming', 4, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-4-v1', 'rule-main-4', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§4.1 Das Verwenden von Informationen, die dein Charakter im Roleplay nicht wissen kann – zum Beispiel durch Livestreams, Drittplattformen oder OOC-Gespräche – ist strengstens verboten. Alle Handlungen und Entscheidungen im RP müssen auf dem Wissen deines Charakters basieren, nicht auf deinem eigenen Wissen als Spieler."}]},{"type":"paragraph","content":[{"type":"text","text":"§4.2 Das Nutzen von Informationen, die dein Charakter im Roleplay nicht auf legitime Weise erhalten kann – z. B. durch Livestreams, Drittplattformen oder OOC-Gespräche – ist verboten."}]},{"type":"paragraph","content":[{"type":"text","text":"§4.3 Dazu zählt auch das Verwenden von Discord-Chats, externen Voice-Channels oder anderen Kommunikationswegen außerhalb des Ingame-Chats, um sich einen Vorteil im RP zu verschaffen."}]},{"type":"paragraph","content":[{"type":"text","text":"§4.4 Alle Handlungen müssen auf dem Wissen deines Charakters basieren, nicht auf deinem Wissen als Spieler."}]},{"type":"paragraph","content":[{"type":"text","text":"§4.5 Ausnahmen gelten ausschließlich für offizielle Fraktionen oder registrierte Gangs, die einen zugewiesenen Funk-Channel auf dem Discord-Server besitzen und diesen auch aktiv für ihre RP-Kommunikation nutzen dürfen."}]},{"type":"paragraph","content":[{"type":"text","text":"§4.6 Alle Handlungen müssen dennoch auf dem Wissen des RP-Charakters basieren, nicht auf dem Wissen des Spielers."}]},{"type":"paragraph","content":[{"type":"text","text":"§4.7 Diese \"Funk Channel´s\" sind ausschließlich für den RP-Zweck gedacht."}]},{"type":"paragraph","content":[{"type":"text","text":"§4.8 Zudem ist das Programm \"Zello\" erlaubt und darf von Fraktionen und Gang´s genutzt werden. Für den RP Zweck."}]},{"type":"paragraph","content":[{"type":"text","text":"§4.9 Das Nutzen der \"Wanted\" Liste im MDT fällt unteranderem auch unter Metagaming, da man die Personen immer dabei sehen muss wenn sie was \"Verbotenes\" tun."}]},{"type":"paragraph","content":[{"type":"text","text":"§4.10 Stream Sniping ist ebenfalls Verboten. Dies bedeutet einen Stream anzuschauen und dann zu dem Streamer hinzufahren um ihn zu erschießen, Geiseln etc."}]}]}'::jsonb, '§4.0 Meta Gaming §4.1 Das Verwenden von Informationen, die dein Charakter im Roleplay nicht wissen kann – zum Beispiel durch Livestreams, Drittplattformen oder OOC-Gespräche – ist strengstens verboten. Alle Handlungen und Entscheidungen im RP müssen auf dem Wissen deines Charakters basieren, nicht auf deinem eigenen Wissen als Spieler. §4.2 Das Nutzen von Informationen, die dein Charakter im Roleplay nicht auf legitime Weise erhalten kann – z. B. durch Livestreams, Drittplattformen oder OOC-Gespräche – ist verboten. §4.3 Dazu zählt auch das Verwenden von Discord-Chats, externen Voice-Channels oder anderen Kommunikationswegen außerhalb des Ingame-Chats, um sich einen Vorteil im RP zu verschaffen. §4.4 Alle Handlungen müssen auf dem Wissen deines Charakters basieren, nicht auf deinem Wissen als Spieler. §4.5 Ausnahmen gelten ausschließlich für offizielle Fraktionen oder registrierte Gangs, die einen zugewiesenen Funk-Channel auf dem Discord-Server besitzen und diesen auch aktiv für ihre RP-Kommunikation nutzen dürfen. §4.6 Alle Handlungen müssen dennoch auf dem Wissen des RP-Charakters basieren, nicht auf dem Wissen des Spielers. §4.7 Diese "Funk Channel´s" sind ausschließlich für den RP-Zweck gedacht. §4.8 Zudem ist das Programm "Zello" erlaubt und darf von Fraktionen und Gang´s genutzt werden. Für den RP Zweck. §4.9 Das Nutzen der "Wanted" Liste im MDT fällt unteranderem auch unter Metagaming, da man die Personen immer dabei sehen muss wenn sie was "Verbotenes" tun. §4.10 Stream Sniping ist ebenfalls Verboten. Dies bedeutet einen Stream anzuschauen und dann zu dem Streamer hinzufahren um ihn zu erschießen, Geiseln etc.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-5', 'main-5', 'main-5', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§5.0 New Life Rule', 5, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-5-v1', 'rule-main-5', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§5.1 Sobald dein RP-Charakter stirbt und respawnt, darfst du dich nicht mehr an die vorherige RP-Situation erinnern."}]},{"type":"paragraph","content":[{"type":"text","text":"§5.2 Das bedeutet: Du darfst nicht zum Ort deines Todes zurückkehren, keine Rache üben, keine Namen oder Informationen weitergeben und keine laufenden Konflikte erneut aufnehmen."}]},{"type":"paragraph","content":[{"type":"text","text":"§5.3 Mit dem Respawn beginnt für deinen Charakter ein „neues Leben“ – vergangene Ereignisse gelten als vergessen."}]},{"type":"paragraph","content":[{"type":"text","text":"§5.4 Wenn man Gestorben ist (Respawn) dann darf man zu der Situation nicht zurückkehren an der man Gestorben ist, die Gilt für 5 minuten."}]},{"type":"paragraph","content":[{"type":"text","text":"§5.5 Wirst du durch einen Sanitäter, Notfallsanitäter oder Notarzt medizinisch versorgt („gehealt“) und nicht respawned, so gilt dein Charakter als nicht verstorben. In diesem Fall darfst du dich an alles erinnern und das RP ganz normal fortsetzen."}]}]}'::jsonb, '§5.0 New Life Rule §5.1 Sobald dein RP-Charakter stirbt und respawnt, darfst du dich nicht mehr an die vorherige RP-Situation erinnern. §5.2 Das bedeutet: Du darfst nicht zum Ort deines Todes zurückkehren, keine Rache üben, keine Namen oder Informationen weitergeben und keine laufenden Konflikte erneut aufnehmen. §5.3 Mit dem Respawn beginnt für deinen Charakter ein „neues Leben“ – vergangene Ereignisse gelten als vergessen. §5.4 Wenn man Gestorben ist (Respawn) dann darf man zu der Situation nicht zurückkehren an der man Gestorben ist, die Gilt für 5 minuten. §5.5 Wirst du durch einen Sanitäter, Notfallsanitäter oder Notarzt medizinisch versorgt („gehealt“) und nicht respawned, so gilt dein Charakter als nicht verstorben. In diesem Fall darfst du dich an alles erinnern und das RP ganz normal fortsetzen.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-6', 'main-6', 'main-6', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§6.0 Fail Roleplay', 6, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-6-v1', 'rule-main-6', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§6.1 Unter Fail Roleplay versteht man das Ausspielen von unrealistischen oder nicht nachvollziehbaren Handlungen, die gegen jede logische oder reale Grundlage verstoßen und somit das RP-Erlebnis stören."}]},{"type":"paragraph","content":[{"type":"text","text":"Beispiele: – Aus 30 Metern Höhe springen und ohne Verletzung weiterlaufen – Nach einem schweren Unfall ohne jegliche Ausspielung einfach aussteigen und weglaufen – Sich im RP wie eine „Superheldenfigur“ verhalten oder das eigene Verletzungs- und Schmerzempfinden ignorieren"}]},{"type":"paragraph","content":[{"type":"text","text":"§6.2 Alle Situationen im RP müssen realitätsnah und nachvollziehbar dargestellt werden. Wer FRP betreibt, muss mit einer Verwarnung oder – bei Wiederholung – mit härteren Konsequenzen rechnen."}]},{"type":"paragraph","content":[{"type":"text","text":"§6.3 Zudem ist das einmischen in eine Laufende Roleplay (RP) Situation nicht gestattet an der man nicht beteiligt ist, dies fällt dann unter Drittpartei."}]},{"type":"paragraph","content":[{"type":"text","text":"§6.4 Bunny Hopping (Das mehrfache Hüpfen) Wären einer Schießerei fällt auch unter FRP. Es muss mind 3 x schnell hintereinander Gehüpft werden, damit man es als Bunny Hopping gesehen werden kann."}]},{"type":"paragraph","content":[{"type":"text","text":"§6.5 Sportwagen dürfen nicht im Gelände gefahren werden. Diese Handlungsweise wird als unrealistisches Rollenspiel (FRP) gewertet."}]},{"type":"paragraph","content":[{"type":"text","text":"§6.6 Das unfaire Herausziehen von gefesselten Spielern (mit Cuffs) aus einem Fahrzeug ist untersagt. Solche Aktionen werden als unrealistisches Rollenspiel (FRP) gewertet, da die realistische Interaktion fehlt."}]}]}'::jsonb, '§6.0 Fail Roleplay §6.1 Unter Fail Roleplay versteht man das Ausspielen von unrealistischen oder nicht nachvollziehbaren Handlungen, die gegen jede logische oder reale Grundlage verstoßen und somit das RP-Erlebnis stören. Beispiele: – Aus 30 Metern Höhe springen und ohne Verletzung weiterlaufen – Nach einem schweren Unfall ohne jegliche Ausspielung einfach aussteigen und weglaufen – Sich im RP wie eine „Superheldenfigur“ verhalten oder das eigene Verletzungs- und Schmerzempfinden ignorieren §6.2 Alle Situationen im RP müssen realitätsnah und nachvollziehbar dargestellt werden. Wer FRP betreibt, muss mit einer Verwarnung oder – bei Wiederholung – mit härteren Konsequenzen rechnen. §6.3 Zudem ist das einmischen in eine Laufende Roleplay (RP) Situation nicht gestattet an der man nicht beteiligt ist, dies fällt dann unter Drittpartei. §6.4 Bunny Hopping (Das mehrfache Hüpfen) Wären einer Schießerei fällt auch unter FRP. Es muss mind 3 x schnell hintereinander Gehüpft werden, damit man es als Bunny Hopping gesehen werden kann. §6.5 Sportwagen dürfen nicht im Gelände gefahren werden. Diese Handlungsweise wird als unrealistisches Rollenspiel (FRP) gewertet. §6.6 Das unfaire Herausziehen von gefesselten Spielern (mit Cuffs) aus einem Fahrzeug ist untersagt. Solche Aktionen werden als unrealistisches Rollenspiel (FRP) gewertet, da die realistische Interaktion fehlt.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-7', 'main-7', 'main-7', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§7.0 Baiting/Cop Baiting', 7, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-7-v1', 'rule-main-7', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§7.1 Provokations-RP / Fail Roleplay durch gezieltes Provozieren Das absichtliche Provozieren von Polizisten oder anderen Spielern, nur um Aufmerksamkeit zu erlangen oder eine Reaktion zu erzwingen, stellt eine Form von Fail Roleplay dar und ist auf unserem Server nicht gestattet."}]},{"type":"paragraph","content":[{"type":"text","text":"Dazu zählt unter anderem: – Das aktive Bedrängen oder Belästigen von Polizeieinheiten, – Das absichtliche Rammen von Einsatzfahrzeugen, – Über rote Ampeln fahren, nur um verfolgt zu werden, – Ausbremsen oder Blockieren von Streifenfahrzeugen, – Sowie das gezielte Hineinlocken von Polizei in Gang-Gebiete mit dem Ziel, eine Auseinandersetzung zu provozieren."}]},{"type":"paragraph","content":[{"type":"text","text":"Solches Verhalten widerspricht dem Grundgedanken von realistischem und fairem Roleplay. Verstöße werden entsprechend geahndet – je nach Schwere mit Verwarnungen."}]}]}'::jsonb, '§7.0 Baiting/Cop Baiting §7.1 Provokations-RP / Fail Roleplay durch gezieltes Provozieren Das absichtliche Provozieren von Polizisten oder anderen Spielern, nur um Aufmerksamkeit zu erlangen oder eine Reaktion zu erzwingen, stellt eine Form von Fail Roleplay dar und ist auf unserem Server nicht gestattet. Dazu zählt unter anderem: – Das aktive Bedrängen oder Belästigen von Polizeieinheiten, – Das absichtliche Rammen von Einsatzfahrzeugen, – Über rote Ampeln fahren, nur um verfolgt zu werden, – Ausbremsen oder Blockieren von Streifenfahrzeugen, – Sowie das gezielte Hineinlocken von Polizei in Gang-Gebiete mit dem Ziel, eine Auseinandersetzung zu provozieren. Solches Verhalten widerspricht dem Grundgedanken von realistischem und fairem Roleplay. Verstöße werden entsprechend geahndet – je nach Schwere mit Verwarnungen.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-8', 'main-8', 'main-8', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§8.0 Power RP', 8, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-8-v1', 'rule-main-8', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§8.1 Power Roleplay (Power-RP) ist untersagt. Power-RP beschreibt das einseitige Erzwingen einer RP-Situation, bei der anderen Spielern keine realistische Möglichkeit zur Reaktion oder zum Ausstieg gegeben wird. Jeder Spieler muss im RP die Gelegenheit haben, angemessen und frei zu handeln."}]},{"type":"paragraph","content":[{"type":"text","text":"Beispiel: – Jemand wird ohne Vorwarnung sofort festgenommen oder bewusstlos geschlagen, ohne Chance zur Reaktion."}]},{"type":"paragraph","content":[{"type":"text","text":"Wichtig: – Das bloße Zuparken von Fahrzeugen (PKW, LKW) fällt nicht mehr unter diese Regel, sondern wird separat bewertet. – Geiselnahmen stellen eine Sonderform im RP dar und fallen nicht unter Power-RP, da hier die Einschränkung der Handlungsfreiheit fester Bestandteil der RP-Situation ist. Dabei muss jedoch ein angemessener und realistischer Ablauf eingehalten werden."}]},{"type":"paragraph","content":[{"type":"text","text":"Verstöße gegen diese Regel führen je nach Ausmaß zu einer Verwarnung oder temporären Sanktionen."}]}]}'::jsonb, '§8.0 Power RP §8.1 Power Roleplay (Power-RP) ist untersagt. Power-RP beschreibt das einseitige Erzwingen einer RP-Situation, bei der anderen Spielern keine realistische Möglichkeit zur Reaktion oder zum Ausstieg gegeben wird. Jeder Spieler muss im RP die Gelegenheit haben, angemessen und frei zu handeln. Beispiel: – Jemand wird ohne Vorwarnung sofort festgenommen oder bewusstlos geschlagen, ohne Chance zur Reaktion. Wichtig: – Das bloße Zuparken von Fahrzeugen (PKW, LKW) fällt nicht mehr unter diese Regel, sondern wird separat bewertet. – Geiselnahmen stellen eine Sonderform im RP dar und fallen nicht unter Power-RP, da hier die Einschränkung der Handlungsfreiheit fester Bestandteil der RP-Situation ist. Dabei muss jedoch ein angemessener und realistischer Ablauf eingehalten werden. Verstöße gegen diese Regel führen je nach Ausmaß zu einer Verwarnung oder temporären Sanktionen.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-9', 'main-9', 'main-9', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§9.0 Kinder RP', 9, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-9-v1', 'rule-main-9', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§9.1 Kinder-RP ist unter bestimmten Voraussetzungen erlaubt. Das Ausspielen von Kindern im RP ist auf unserem Server grundsätzlich gestattet, jedoch gelten hierbei besondere Einschränkungen, um ein realistisches und regelkonformes Rollenspiel sicherzustellen. Kinder RP darf nur noch ausgepsielt werden wenn Mindest 1 Elternteil dabei ist."}]},{"type":"paragraph","content":[{"type":"text","text":"§9.2 Folgende Regeln sind beim Kinder-RP unbedingt einzuhalten: – Kinder dürfen keine Schusswaffen (z. B. Pistolen, Gewehre, etc.) führen oder benutzen. Darunter fallen auch Messer, Basballschläger etc. – Das Führen von motorisierten Fahrzeugen wie PKW, LKW ist nicht gestattet. – Ausnahme: Kinder dürfen Quads und Rasenmäher nutzen, solange dies im RP nachvollziehbar ausgespielt wird (z. B. privates Spielen im Garten, Mithilfe bei der Gartenarbeit oder einfaches umherfahren)."}]},{"type":"paragraph","content":[{"type":"text","text":"Zuwiderhandlungen gegen diese Regelung können je nach Schwere mit einer Verwarnung bis hin zu temporären RP-Sperren geahndet werden."}]}]}'::jsonb, '§9.0 Kinder RP §9.1 Kinder-RP ist unter bestimmten Voraussetzungen erlaubt. Das Ausspielen von Kindern im RP ist auf unserem Server grundsätzlich gestattet, jedoch gelten hierbei besondere Einschränkungen, um ein realistisches und regelkonformes Rollenspiel sicherzustellen. Kinder RP darf nur noch ausgepsielt werden wenn Mindest 1 Elternteil dabei ist. §9.2 Folgende Regeln sind beim Kinder-RP unbedingt einzuhalten: – Kinder dürfen keine Schusswaffen (z. B. Pistolen, Gewehre, etc.) führen oder benutzen. Darunter fallen auch Messer, Basballschläger etc. – Das Führen von motorisierten Fahrzeugen wie PKW, LKW ist nicht gestattet. – Ausnahme: Kinder dürfen Quads und Rasenmäher nutzen, solange dies im RP nachvollziehbar ausgespielt wird (z. B. privates Spielen im Garten, Mithilfe bei der Gartenarbeit oder einfaches umherfahren). Zuwiderhandlungen gegen diese Regelung können je nach Schwere mit einer Verwarnung bis hin zu temporären RP-Sperren geahndet werden.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-10', 'main-10', 'main-10', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§10.0 RP Verweigerung', 10, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-10-v1', 'rule-main-10', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Verpflichtung zur aktiven Teilnahme an RP-Situationen"}]},{"type":"paragraph","content":[{"type":"text","text":"§10.1 Jeder Spieler ist dazu verpflichtet, an einer laufenden Roleplay-Situation aktiv teilzunehmen, sobald er direkt oder indirekt in diese eingebunden ist. Dazu gehört unter anderem auch, Detain-Anfragen (Festnahmen oder Festhaltungen) ordnungsgemäß anzunehmen."}]},{"type":"paragraph","content":[{"type":"text","text":"§10.2 Sollte es notwendig sein, kurzfristig AFK (Away from Keyboard) zu gehen, ist Folgendes zu beachten: – Man muss sich in eine Safezone begeben, – Die Hände nach oben halten (z. B. durch eine entsprechende Animation), – Und zusätzlich im Ingame-Chat die Nachricht \"(AFK)\" hinterlassen, damit andere Spieler informiert sind."}]},{"type":"paragraph","content":[{"type":"text","text":"Wichtig: Wer sich verweigert, das RP korrekt auszuspielen, oder das Spiel gezielt verlässt, um einer Szene zu entgehen, muss mit einer Verwarnung oder weiterführenden Sanktionen rechnen – abhängig vom Einzelfall und der Schwere des Regelbruchs."}]}]}'::jsonb, '§10.0 RP Verweigerung Verpflichtung zur aktiven Teilnahme an RP-Situationen §10.1 Jeder Spieler ist dazu verpflichtet, an einer laufenden Roleplay-Situation aktiv teilzunehmen, sobald er direkt oder indirekt in diese eingebunden ist. Dazu gehört unter anderem auch, Detain-Anfragen (Festnahmen oder Festhaltungen) ordnungsgemäß anzunehmen. §10.2 Sollte es notwendig sein, kurzfristig AFK (Away from Keyboard) zu gehen, ist Folgendes zu beachten: – Man muss sich in eine Safezone begeben, – Die Hände nach oben halten (z. B. durch eine entsprechende Animation), – Und zusätzlich im Ingame-Chat die Nachricht "(AFK)" hinterlassen, damit andere Spieler informiert sind. Wichtig: Wer sich verweigert, das RP korrekt auszuspielen, oder das Spiel gezielt verlässt, um einer Szene zu entgehen, muss mit einer Verwarnung oder weiterführenden Sanktionen rechnen – abhängig vom Einzelfall und der Schwere des Regelbruchs.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-11', 'main-11', 'main-11', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§11.0 Trolling', 11, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-11-v1', 'rule-main-11', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§11.1 Das Trollen/Verarschen anderer Personen ist verboten, dies stört nur das Roleplay und kann zu einem Projekt Ausschluss führen."}]},{"type":"paragraph","content":[{"type":"text","text":"§11.2 Zudem darf man bei Ausbildungen seitens der Polizei, Feuerwehr, RD und ADAC diese nicht stören da dies auch unter Trolling gewertet werden kann. Zudem sind Ausbildungen immer OOC dh sie nehmen am RP nicht Aktiv teil."}]},{"type":"paragraph","content":[{"type":"text","text":"§11.3 Soundboard´s über den VC sind verboten und werden dementsprechent bestraft. Das Zählt für jede art (Sirenen, Memes etc)."}]}]}'::jsonb, '§11.0 Trolling §11.1 Das Trollen/Verarschen anderer Personen ist verboten, dies stört nur das Roleplay und kann zu einem Projekt Ausschluss führen. §11.2 Zudem darf man bei Ausbildungen seitens der Polizei, Feuerwehr, RD und ADAC diese nicht stören da dies auch unter Trolling gewertet werden kann. Zudem sind Ausbildungen immer OOC dh sie nehmen am RP nicht Aktiv teil. §11.3 Soundboard´s über den VC sind verboten und werden dementsprechent bestraft. Das Zählt für jede art (Sirenen, Memes etc).', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-12', 'main-12', 'main-12', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§12.0 Clips / Reports', 12, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-12-v1', 'rule-main-12', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§12.1 Alle Beweise, wie z. B. Videoclips oder Screenshots, die zur Meldung eines Regelverstoßes oder für einen Supportfall verwendet werden sollen, müssen innerhalb von 24 Stunden nach dem Vorfall vollständig eingereicht werden."}]},{"type":"paragraph","content":[{"type":"text","text":"§12.2 Nach Ablauf dieser Frist gelten alle Beweise als ungültig und werden im Support nicht mehr berücksichtigt – unabhängig davon, ob sie authentisch oder nachvollziehbar sind."}]},{"type":"paragraph","content":[{"type":"text","text":"§12.3 Stimmen dürfen auch für Beweis Zwecke aufgenommen werden dürfen aber nicht weitergegeben werden oder veröffentlicht werden."}]},{"type":"paragraph","content":[{"type":"text","text":"§12.4 Wird ein Report mithilfe eines Videoclips eingereicht, muss der gesamte relevante Roleplay-Verlauf vollständig und ohne Unterbrechungen ersichtlich sein. Das bedeutet, dass der Clip den Vorfall vom Beginn bis zum Ende zeigen muss, sodass der Kontext der Situation klar nachvollzogen werden kann."}]},{"type":"paragraph","content":[{"type":"text","text":"§12.5 Das absichtliche Verschleiern, Verheimlichen oder Überspringen von Szenen innerhalb des Clips ist nicht gestattet. Geschnittene oder unvollständige Aufnahmen können dazu führen, dass wichtige Informationen fehlen und der Sachverhalt nicht korrekt bewertet werden kann."}]},{"type":"paragraph","content":[{"type":"text","text":"§12.6 Staff-Mitglieder sind jederzeit berechtigt, den vollständigen und ungeschnittenen Clip des Vorfalls anzufordern. Dies dient der fairen und objektiven Prüfung eines Reports."}]},{"type":"paragraph","content":[{"type":"text","text":"§12.7 Sollte der vollständige Clip auf Nachfrage nicht bereitgestellt werden oder sich herausstellen, dass der Clip bearbeitet, gekürzt oder unvollständig ist, wird der eingereichte Beweis als ungültig gewertet und der Report kann entsprechend abgelehnt oder geschlossen werden."}]},{"type":"paragraph","content":[{"type":"text","text":"§12.8 Clips MÜSSEN mind. 24h aufbewahrt werden, ansonsten können Sanktionen Folgen. Zudem wird der Clip dann als \"Ungültig\" erachtet."}]}]}'::jsonb, '§12.0 Clips / Reports §12.1 Alle Beweise, wie z. B. Videoclips oder Screenshots, die zur Meldung eines Regelverstoßes oder für einen Supportfall verwendet werden sollen, müssen innerhalb von 24 Stunden nach dem Vorfall vollständig eingereicht werden. §12.2 Nach Ablauf dieser Frist gelten alle Beweise als ungültig und werden im Support nicht mehr berücksichtigt – unabhängig davon, ob sie authentisch oder nachvollziehbar sind. §12.3 Stimmen dürfen auch für Beweis Zwecke aufgenommen werden dürfen aber nicht weitergegeben werden oder veröffentlicht werden. §12.4 Wird ein Report mithilfe eines Videoclips eingereicht, muss der gesamte relevante Roleplay-Verlauf vollständig und ohne Unterbrechungen ersichtlich sein. Das bedeutet, dass der Clip den Vorfall vom Beginn bis zum Ende zeigen muss, sodass der Kontext der Situation klar nachvollzogen werden kann. §12.5 Das absichtliche Verschleiern, Verheimlichen oder Überspringen von Szenen innerhalb des Clips ist nicht gestattet. Geschnittene oder unvollständige Aufnahmen können dazu führen, dass wichtige Informationen fehlen und der Sachverhalt nicht korrekt bewertet werden kann. §12.6 Staff-Mitglieder sind jederzeit berechtigt, den vollständigen und ungeschnittenen Clip des Vorfalls anzufordern. Dies dient der fairen und objektiven Prüfung eines Reports. §12.7 Sollte der vollständige Clip auf Nachfrage nicht bereitgestellt werden oder sich herausstellen, dass der Clip bearbeitet, gekürzt oder unvollständig ist, wird der eingereichte Beweis als ungültig gewertet und der Report kann entsprechend abgelehnt oder geschlossen werden. §12.8 Clips MÜSSEN mind. 24h aufbewahrt werden, ansonsten können Sanktionen Folgen. Zudem wird der Clip dann als "Ungültig" erachtet.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-13', 'main-13', 'main-13', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§13.0 Blood Out', 13, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-13-v1', 'rule-main-13', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"„Blood Out“ – Finale Charakterlöschung mit RP-Hintergrund"}]},{"type":"paragraph","content":[{"type":"text","text":"Ein sogenannter"},{"type":"text","text":"„Blood Out“"},{"type":"text","text":"stellt den"},{"type":"text","text":"endgültigen Ausstieg"},{"type":"text","text":"eines Charakters aus einer Gang oder Fraktion dar und gilt als"},{"type":"text","text":"dauerhafte Charakterlöschung"},{"type":"text","text":"."}]},{"type":"paragraph","content":[{"type":"text","text":"§13.1 Ein Blood Out darf nicht leichtfertig durchgeführt werden. Es muss ein nachvollziehbarer und tiefgehender RP-Hintergrund vorhanden sein, der diesen Schritt rechtfertigt."}]},{"type":"paragraph","content":[{"type":"text","text":"§13.2 Jeder Spieler, der Mitglied einer offiziellen Gang oder Fraktion ist, darf grundsätzlich einen Blood Out im Rahmen des Roleplays aussprechen – sofern es intern geregelt und gut ausgespielt wird."}]},{"type":"paragraph","content":[{"type":"text","text":"§13.3 Ein Blood Out ist nicht gleichzusetzen mit einem Hinrichtungs-RP. Es geht hierbei nicht um eine bloße Exekution, sondern um einen sinnvoll aufgebauten Ausstieg, der Rollenspiel-basiert umgesetzt werden muss."}]},{"type":"paragraph","content":[{"type":"text","text":"§13.4 Wird ein Spieler gebloodoutet, so gilt folgendes: – Der betreffende Charakter darf nicht mehr gespielt werden. – Alle Informationen, die dieser Charakter im Laufe seines Lebens gesammelt hat (z. B. Gang-Strukturen, interne Pläne, Namen), dürfen nicht mehr verwendet oder weitergegeben werden."}]},{"type":"paragraph","content":[{"type":"text","text":"Ein Missbrauch dieser Regel oder ein Blood Out ohne ausreichendes RP-Fundament kann zur"},{"type":"text","text":"Ungültigkeit"},{"type":"text","text":"des Vorgangs und ggf. zu"},{"type":"text","text":"Strafen"},{"type":"text","text":"führen."}]}]}'::jsonb, '§13.0 Blood Out „Blood Out“ – Finale Charakterlöschung mit RP-Hintergrund Ein sogenannter „Blood Out“ stellt den endgültigen Ausstieg eines Charakters aus einer Gang oder Fraktion dar und gilt als dauerhafte Charakterlöschung . §13.1 Ein Blood Out darf nicht leichtfertig durchgeführt werden. Es muss ein nachvollziehbarer und tiefgehender RP-Hintergrund vorhanden sein, der diesen Schritt rechtfertigt. §13.2 Jeder Spieler, der Mitglied einer offiziellen Gang oder Fraktion ist, darf grundsätzlich einen Blood Out im Rahmen des Roleplays aussprechen – sofern es intern geregelt und gut ausgespielt wird. §13.3 Ein Blood Out ist nicht gleichzusetzen mit einem Hinrichtungs-RP. Es geht hierbei nicht um eine bloße Exekution, sondern um einen sinnvoll aufgebauten Ausstieg, der Rollenspiel-basiert umgesetzt werden muss. §13.4 Wird ein Spieler gebloodoutet, so gilt folgendes: – Der betreffende Charakter darf nicht mehr gespielt werden. – Alle Informationen, die dieser Charakter im Laufe seines Lebens gesammelt hat (z. B. Gang-Strukturen, interne Pläne, Namen), dürfen nicht mehr verwendet oder weitergegeben werden. Ein Missbrauch dieser Regel oder ein Blood Out ohne ausreichendes RP-Fundament kann zur Ungültigkeit des Vorgangs und ggf. zu Strafen führen.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-14', 'main-14', 'main-14', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§14.0 Random DeathMatch', 14, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-14-v1', 'rule-main-14', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§14.1 RP-Hintergrund Jede Situation, in der eine Waffe zum Einsatz kommt, muss auf einem nachvollziehbaren RP-Hintergrund basieren. Es reicht nicht, einfach jemanden zu erschießen, nur weil eine Meinungsverschiedenheit besteht oder eine Provokation stattgefunden hat. Gewalt muss immer im RP-Kontext begründet sein."}]},{"type":"paragraph","content":[{"type":"text","text":"§14.2 Schusscall Pflicht Bevor ein Schuss abgegeben wird, muss eindeutig und sichtbar ein Schusscall gesetzt werden. Dieser kann durch mindestens drei Sekunden aktives Zielen auf die Zielperson oder deren Fahrzeug erfolgen, durch einen Warnschuss in die Luft oder auf den Boden oder durch eine klar erkennbare Textnachricht im Ingame-Chat. Nur so wird der Call gültig und eine RP-Situation mit Waffengebrauch korrekt eingeleitet."}]},{"type":"paragraph","content":[{"type":"text","text":"§14.3 Gültigkeitsdauer des Schusscalls Ein abgegebener Schusscall bleibt für drei Minuten aktiv. Innerhalb dieses Zeitraums darf gehandelt werden, solange sich die Situation nicht verändert oder aufgelöst hat. Danach muss bei weiterer Eskalation ein neuer Call erfolgen."}]},{"type":"paragraph","content":[{"type":"text","text":"§14.4 Unzulässige Call-Arten Ein Schusscall über externe Plattformen wie Discord ist nicht erlaubt. Alle Ankündigungen müssen für alle Beteiligten sichtbar und ingame nachvollziehbar sein."}]},{"type":"paragraph","content":[{"type":"text","text":"§14.5 Besonderheiten bei Ganggebieten Betritt ein Spieler ein aktives Ganggebiet, darf die Gang auch ohne gesonderte Ankündigung handeln – vorausgesetzt, es besteht eine aktive RP-Situation und es wird nicht gegen die Fairness verstoßen. Dennoch ist auch hier das Gambo-RP zu beachten."}]},{"type":"paragraph","content":[{"type":"text","text":"§14.6 Reaktionszeit & Fairness Ein Schusscall muss mindestens fünf Sekunden vor der eigentlichen Handlung erkennbar erfolgen, damit andere Spieler fair reagieren können. Sollte sich eine betroffene Person in einem Menü befinden (z. B. beim Tanken oder Autospawn), muss gewartet werden, bis sie wieder handlungsfähig ist."}]},{"type":"paragraph","content":[{"type":"text","text":"§14.7 Sichtbarkeit & Reichweite Der Schusscall muss sichtbar sein. Eine Gültigkeit besteht nur, wenn sich die betroffenen Personen in einem Radius von maximal 20 Metern befinden. Alles darüber hinaus gilt nicht als klar erkennbare Ankündigung."}]},{"type":"paragraph","content":[{"type":"text","text":"§14.8 Leichen Schändigung & artenLeichenschändigung (Verunglimpfung ausgeschalteter Spieler) ist auf unserem Server strikt untersagt und wird mit einem unmittelbaren Serverausschluss geahndet."}]},{"type":"paragraph","content":[{"type":"text","text":"§14.9 Leichenschändigungs bedingung"}]},{"type":"paragraph","content":[{"type":"text","text":"Damit eine Handlung als Leichenschändung gewertet werden kann, muss gegenüber einer bewusstlosen, verletzten oder bereits verstorben ausgespielten Person eine"},{"type":"text","text":"vorsätzliche und respektlose Handlung"},{"type":"text","text":"erfolgen. Dabei muss erkennbar sein, dass die Handlung bewusst durchgeführt wurde und nicht versehentlich entstanden ist."}]},{"type":"paragraph","content":[{"type":"text","text":"Als Leichenschändung gelten insbesondere:"}]},{"type":"paragraph","content":[{"type":"text","text":"wiederholtes Schießen auf eine bereits handlungsunfähige Person,"}]},{"type":"paragraph","content":[{"type":"text","text":"mehrfaches Überfahren oder absichtliches Anfahren einer am Boden liegenden Person,"}]},{"type":"paragraph","content":[{"type":"text","text":"wiederholtes Überlaufen, Anspringen oder anderweitiges Herabwürdigen einer handlungsunfähigen Person,"}]},{"type":"paragraph","content":[{"type":"text","text":"sonstige vergleichbare Handlungen, die ausschließlich der Verhöhnung, Demütigung oder Missachtung der betroffenen Person dienen."}]},{"type":"paragraph","content":[{"type":"text","text":"Einzelne versehentliche Berührungen, Fahrfehler oder einmalige Missgeschicke gelten in der Regel nicht als Leichenschändung. Für die Bewertung werden stets die Umstände des Einzelfalls, die Absicht des Spielers sowie die Häufigkeit der Handlung berücksichtigt."}]},{"type":"paragraph","content":[{"type":"text","text":"Die endgültige Einstufung, ob eine Handlung als Leichenschändung zu werten ist und welche Sanktion angemessen erscheint, obliegt dem zuständigen Moderator oder Administrator. Dieser entscheidet unter Berücksichtigung der Schwere des Verstoßes, der vorliegenden Beweise sowie der Gesamtsituation."},{"type":"text","text":"§14.10 Verbot von Auftragskiller-RP"}]},{"type":"paragraph","content":[{"type":"text","text":"Das Ausführen, Anbieten oder Vermitteln von sogenannten „Auftragskiller“-Handlungen ist im Roleplay vollständig untersagt. Darunter fällt insbesondere das gezielte Beauftragen, Planen oder Durchführen von Tötungen gegen andere Spieler gegen Bezahlung oder sonstige Gegenleistungen."}]},{"type":"paragraph","content":[{"type":"text","text":"Jegliche Form von Auftragsmorden, unabhängig davon ob diese erfolgreich umgesetzt oder lediglich geplant werden, stellt einen Verstoß gegen das Regelwerk dar. Dies gilt auch für indirekte Absprachen oder das Umgehen dieser Regel durch Dritte."}]}]}'::jsonb, '§14.0 Random DeathMatch §14.1 RP-Hintergrund Jede Situation, in der eine Waffe zum Einsatz kommt, muss auf einem nachvollziehbaren RP-Hintergrund basieren. Es reicht nicht, einfach jemanden zu erschießen, nur weil eine Meinungsverschiedenheit besteht oder eine Provokation stattgefunden hat. Gewalt muss immer im RP-Kontext begründet sein. §14.2 Schusscall Pflicht Bevor ein Schuss abgegeben wird, muss eindeutig und sichtbar ein Schusscall gesetzt werden. Dieser kann durch mindestens drei Sekunden aktives Zielen auf die Zielperson oder deren Fahrzeug erfolgen, durch einen Warnschuss in die Luft oder auf den Boden oder durch eine klar erkennbare Textnachricht im Ingame-Chat. Nur so wird der Call gültig und eine RP-Situation mit Waffengebrauch korrekt eingeleitet. §14.3 Gültigkeitsdauer des Schusscalls Ein abgegebener Schusscall bleibt für drei Minuten aktiv. Innerhalb dieses Zeitraums darf gehandelt werden, solange sich die Situation nicht verändert oder aufgelöst hat. Danach muss bei weiterer Eskalation ein neuer Call erfolgen. §14.4 Unzulässige Call-Arten Ein Schusscall über externe Plattformen wie Discord ist nicht erlaubt. Alle Ankündigungen müssen für alle Beteiligten sichtbar und ingame nachvollziehbar sein. §14.5 Besonderheiten bei Ganggebieten Betritt ein Spieler ein aktives Ganggebiet, darf die Gang auch ohne gesonderte Ankündigung handeln – vorausgesetzt, es besteht eine aktive RP-Situation und es wird nicht gegen die Fairness verstoßen. Dennoch ist auch hier das Gambo-RP zu beachten. §14.6 Reaktionszeit & Fairness Ein Schusscall muss mindestens fünf Sekunden vor der eigentlichen Handlung erkennbar erfolgen, damit andere Spieler fair reagieren können. Sollte sich eine betroffene Person in einem Menü befinden (z. B. beim Tanken oder Autospawn), muss gewartet werden, bis sie wieder handlungsfähig ist. §14.7 Sichtbarkeit & Reichweite Der Schusscall muss sichtbar sein. Eine Gültigkeit besteht nur, wenn sich die betroffenen Personen in einem Radius von maximal 20 Metern befinden. Alles darüber hinaus gilt nicht als klar erkennbare Ankündigung. §14.8 Leichen Schändigung & artenLeichenschändigung (Verunglimpfung ausgeschalteter Spieler) ist auf unserem Server strikt untersagt und wird mit einem unmittelbaren Serverausschluss geahndet. §14.9 Leichenschändigungs bedingung Damit eine Handlung als Leichenschändung gewertet werden kann, muss gegenüber einer bewusstlosen, verletzten oder bereits verstorben ausgespielten Person eine vorsätzliche und respektlose Handlung erfolgen. Dabei muss erkennbar sein, dass die Handlung bewusst durchgeführt wurde und nicht versehentlich entstanden ist. Als Leichenschändung gelten insbesondere: wiederholtes Schießen auf eine bereits handlungsunfähige Person, mehrfaches Überfahren oder absichtliches Anfahren einer am Boden liegenden Person, wiederholtes Überlaufen, Anspringen oder anderweitiges Herabwürdigen einer handlungsunfähigen Person, sonstige vergleichbare Handlungen, die ausschließlich der Verhöhnung, Demütigung oder Missachtung der betroffenen Person dienen. Einzelne versehentliche Berührungen, Fahrfehler oder einmalige Missgeschicke gelten in der Regel nicht als Leichenschändung. Für die Bewertung werden stets die Umstände des Einzelfalls, die Absicht des Spielers sowie die Häufigkeit der Handlung berücksichtigt. Die endgültige Einstufung, ob eine Handlung als Leichenschändung zu werten ist und welche Sanktion angemessen erscheint, obliegt dem zuständigen Moderator oder Administrator. Dieser entscheidet unter Berücksichtigung der Schwere des Verstoßes, der vorliegenden Beweise sowie der Gesamtsituation. §14.10 Verbot von Auftragskiller-RP Das Ausführen, Anbieten oder Vermitteln von sogenannten „Auftragskiller“-Handlungen ist im Roleplay vollständig untersagt. Darunter fällt insbesondere das gezielte Beauftragen, Planen oder Durchführen von Tötungen gegen andere Spieler gegen Bezahlung oder sonstige Gegenleistungen. Jegliche Form von Auftragsmorden, unabhängig davon ob diese erfolgreich umgesetzt oder lediglich geplant werden, stellt einen Verstoß gegen das Regelwerk dar. Dies gilt auch für indirekte Absprachen oder das Umgehen dieser Regel durch Dritte.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-15', 'main-15', 'main-15', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§15.0 Vehicle Death Match', 15, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-15-v1', 'rule-main-15', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§15.1 Das gezielte Anfahren von Personen mit einem Fahrzeug, mit der Absicht diese zu verletzen oder zu töten, ist untersagt. Insbesondere gilt dies, wenn eine Person mehrfach hintereinander oder mehrere Personen innerhalb kurzer Zeit angefahren werden. Als Richtwert gilt: Wer innerhalb von drei Minuten dieselbe Person mindestens drei Mal oder mehrere Personen in kurzer Abfolge anfährt, handelt regelwidrig und riskiert Konsequenzen."}]}]}'::jsonb, '§15.0 Vehicle Death Match §15.1 Das gezielte Anfahren von Personen mit einem Fahrzeug, mit der Absicht diese zu verletzen oder zu töten, ist untersagt. Insbesondere gilt dies, wenn eine Person mehrfach hintereinander oder mehrere Personen innerhalb kurzer Zeit angefahren werden. Als Richtwert gilt: Wer innerhalb von drei Minuten dieselbe Person mindestens drei Mal oder mehrere Personen in kurzer Abfolge anfährt, handelt regelwidrig und riskiert Konsequenzen.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-16', 'main-16', 'main-16', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§16.0 Random Car Damage', 16, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-16-v1', 'rule-main-16', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§16.1 Das mutwillige Beschädigen oder Zerstören von Fahrzeugen (PKW, LKW) ohne einen nachvollziehbaren Roleplay-Hintergrund ist strengstens untersagt. Dies umfasst insbesondere das grundlose Rammen, Zerkratzen oder Beschießen von Fahrzeugen. Wer auf ein Fahrzeug schießt, benötigt einen gültigen Schusscall – ohne diesen gilt die Handlung als Regelverstoß.§17.0 Safe Zones"}]},{"type":"paragraph","content":[{"type":"text","text":"Safe-Zone Regelung"}]}]}'::jsonb, '§16.0 Random Car Damage §16.1 Das mutwillige Beschädigen oder Zerstören von Fahrzeugen (PKW, LKW) ohne einen nachvollziehbaren Roleplay-Hintergrund ist strengstens untersagt. Dies umfasst insbesondere das grundlose Rammen, Zerkratzen oder Beschießen von Fahrzeugen. Wer auf ein Fahrzeug schießt, benötigt einen gültigen Schusscall – ohne diesen gilt die Handlung als Regelverstoß.§17.0 Safe Zones Safe-Zone Regelung', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-17', 'main-17', 'main-17', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§17.1 Das Entführen, Bedrohen , Grundlose umfahren oder Erschießen von Personen innerhalb einer Safe-Zone ist ausdrücklich verboten. Safe-Zones dienen dem Schutz und der Neutralität und sind frei von jeglichen gewaltsamen Handlungen. Sollte sich eine Person jedoch aktiv aus einer laufenden RP-Situation in eine Safe-Zone retten, verliert diese in diesem speziellen Fall ihren Schutzstatus gegenüber der verfolgenden Partei. Dennoch ist auch hier stets auf ein faires und realistisches Ausspielen der Situation zu achten. Zudem dürfen auch Waffen aler art nicht in der Safezone gezogen werden.', 17, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-17-v1', 'rule-main-17', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Folgende Orte gelten als Safe-Zones:"}]},{"type":"paragraph","content":[{"type":"text","text":"– Spawnpunkt in River City (Das Parken auf den Staff Parkplätzen ist ebenfalls verboten)"},{"type":"text","text":"– Krankenhaus (Parkplatz Vorne + Hinten)"},{"type":"text","text":"– Feuerwehrwache 1 & 2"},{"type":"text","text":"–Polizei Wache im gebäude als auch"},{"type":"text","text":"beide Parkplätze des Polizeipräsidiumes."},{"type":"text","text":"– Department of Transportation"}]},{"type":"paragraph","content":[{"type":"text","text":"§17.2 Das Abschleppen von Fahrzeugen innerhalb dieser Safe-Zones ist ebenfalls untersagt, unabhängig davon, ob ein Spieler anwesend ist oder nicht."}]},{"type":"paragraph","content":[{"type":"text","text":"§17.3 Wenn man während einer Aktiven Verfolgung in eine Safezone \"Flüchtet\" Verliert man den Safezone-\"Status\"."}]}]}'::jsonb, '§17.1 Das Entführen, Bedrohen , Grundlose umfahren oder Erschießen von Personen innerhalb einer Safe-Zone ist ausdrücklich verboten. Safe-Zones dienen dem Schutz und der Neutralität und sind frei von jeglichen gewaltsamen Handlungen. Sollte sich eine Person jedoch aktiv aus einer laufenden RP-Situation in eine Safe-Zone retten, verliert diese in diesem speziellen Fall ihren Schutzstatus gegenüber der verfolgenden Partei. Dennoch ist auch hier stets auf ein faires und realistisches Ausspielen der Situation zu achten. Zudem dürfen auch Waffen aler art nicht in der Safezone gezogen werden. Folgende Orte gelten als Safe-Zones: – Spawnpunkt in River City (Das Parken auf den Staff Parkplätzen ist ebenfalls verboten) – Krankenhaus (Parkplatz Vorne + Hinten) – Feuerwehrwache 1 & 2 –Polizei Wache im gebäude als auch beide Parkplätze des Polizeipräsidiumes. – Department of Transportation §17.2 Das Abschleppen von Fahrzeugen innerhalb dieser Safe-Zones ist ebenfalls untersagt, unabhängig davon, ob ein Spieler anwesend ist oder nicht. §17.3 Wenn man während einer Aktiven Verfolgung in eine Safezone "Flüchtet" Verliert man den Safezone-"Status".', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-18', 'main-18', 'main-18', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§18.0 Gambo Roleplay', 18, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-18-v1', 'rule-main-18', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Unverhältnismäßiger Waffengebrauch"}]},{"type":"paragraph","content":[{"type":"text","text":"§18.1 Ein übermäßiger und grundlos häufiger Einsatz von Waffen ist untersagt. Waffen sollten im RP nur dann verwendet werden, wenn die Situation es realistisch und nachvollziehbar erfordert. Jeder Spieler trägt die volle Verantwortung für den eigenen Waffengebrauch und muss diesen stets angemessen im RP begründen können."}]},{"type":"paragraph","content":[{"type":"text","text":"§18.2 Sollte der Umgang mit Waffen als unangemessen, störend oder regelwidrig eingestuft werden, kann dies zu Einschränkungen bis hin zur Sperrung der Waffe oder sogar zu weiteren Sanktionen führen."}]}]}'::jsonb, '§18.0 Gambo Roleplay Unverhältnismäßiger Waffengebrauch §18.1 Ein übermäßiger und grundlos häufiger Einsatz von Waffen ist untersagt. Waffen sollten im RP nur dann verwendet werden, wenn die Situation es realistisch und nachvollziehbar erfordert. Jeder Spieler trägt die volle Verantwortung für den eigenen Waffengebrauch und muss diesen stets angemessen im RP begründen können. §18.2 Sollte der Umgang mit Waffen als unangemessen, störend oder regelwidrig eingestuft werden, kann dies zu Einschränkungen bis hin zur Sperrung der Waffe oder sogar zu weiteren Sanktionen führen.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-19', 'main-19', 'main-19', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§19.0 Value your Life', 19, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-19-v1', 'rule-main-19', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Schutz des eigenen Lebens (Höchstgut-Regel)"}]},{"type":"paragraph","content":[{"type":"text","text":"§19.1 Das eigene Leben stellt im Roleplay das höchste Gut dar und muss unter allen Umständen geschützt werden. Entsprechend ist es nicht erlaubt, bei einer akuten Bedrohung durch eine Waffe zu flüchten – sei es durch Weglaufen, Wegfahren oder das Ziehen einer eigenen Waffe."}]},{"type":"paragraph","content":[{"type":"text","text":"§19.2 Ebenso ist es untersagt, in einem brennenden Fahrzeug sitzen zu bleiben, da dies nicht der realistischen Selbsterhaltungspflicht entspricht."}]}]}'::jsonb, '§19.0 Value your Life Schutz des eigenen Lebens (Höchstgut-Regel) §19.1 Das eigene Leben stellt im Roleplay das höchste Gut dar und muss unter allen Umständen geschützt werden. Entsprechend ist es nicht erlaubt, bei einer akuten Bedrohung durch eine Waffe zu flüchten – sei es durch Weglaufen, Wegfahren oder das Ziehen einer eigenen Waffe. §19.2 Ebenso ist es untersagt, in einem brennenden Fahrzeug sitzen zu bleiben, da dies nicht der realistischen Selbsterhaltungspflicht entspricht.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-20', 'main-20', 'main-20', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§20.0 Geiselnahmen', 20, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-20-v1', 'rule-main-20', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Geiselnahmen im Roleplay – Regeln & Vorgaben"}]},{"type":"paragraph","content":[{"type":"text","text":"§20.1– Safe-Zones sind tabu: Geiselnahmen dürfen nicht innerhalb einer Safe-Zone stattfinden. §20.2– Geeignetes Fahrzeug: Die Geiselnahme muss in einem Fahrzeug mit mindestens vier Sitzplätzen erfolgen. §20.3– Verhandlungsbereitschaft: Sowohl Polizei als auch Geiselnehmer müssen jederzeit zur Verhandlung bereit sein. §20.4– Forderungsgrenze: Pro Geisel ist nur eine konkrete Forderung erlaubt – diese muss zudem realistisch und umsetzbar sein. §20.5– Einhaltung der Forderungen: Vereinbarte Forderungen müssen von beiden Seiten eingehalten werden. §20.6– Freie Flucht: Eine „Freie Flucht“-Forderung darf maximal 15 Sekunden lang sein – bei E-Fahrzeugen nur 10 Sekunden. Bei einer Freien-flucht, ist es Verboten während der ausgehandelten Zeit Stopsticks / Spikes etc zu \"Werfen\", zudem ist es auch Verboten währendessen auf das Auto zu Schießen.§20.7 – Die Freie Flucht zu Blockieren wird zudem auch als Bruch der Verhandlungen angesehen. §20.8– Geiseln pro Geiselnehmer: Jeder Geiselnehmer darf maximal eine Geisel nehmen. §20.9– Zeitlimit: Eine Geisel darf nicht länger als 20 Minuten festgehalten werden. Danach muss die Geisel freigelassen werden. §20.10– Sicherstellung der Unversehrtheit: Alle Beteiligten, Polizei wie Geiselnehmer müssen sich bemühen, die Geisel während der gesamten Situation zu schützen. §20.11– Stürmungsrecht der Polizei: Die Polizei darf die Situation stürmen, wenn keine akute Gefahr mehr für die Geisel besteht – zum Beispiel, wenn niemand mehr aktiv auf sie zielt. §20.12– Sonderregelung für Dienst-Fraktionen: Rettungsdienst, Feuerwehr und ADAC dürfen nur dann als Geiseln genommen werden, wenn eine akute Ausnahmesituation vorliegt – etwa wenn Geiselnehmer von der Polizei verfolgt werden und keine andere Fluchtmöglichkeit mehr haben. §20.13– Kinderschutz: Kinder dürfen niemals als Geiseln genommen werden."}]},{"type":"paragraph","content":[{"type":"text","text":"§20.14 Schein-Geiseln sind ausnahmslos unzulässig, da sie den Grundsatz fairen Rollenspiels verletzen."}]},{"type":"paragraph","content":[{"type":"text","text":"§20.15 Die Geiselnahme eines Polizeibeamten ist erst ab einer Mindestpräsenz von 3 aktiven Polizeikräften im Rollenspiel zulässig. Die Unterschreitung dieser Mindestanzahl ist strikt untersagt."}]},{"type":"paragraph","content":[{"type":"text","text":"§20.16 Zwischen zwei Geiselnahmen muss ein Mindestabstand von 30 Minuten liegen. Geiselnahmen, die innerhalb dieses Zeitraums erneut begonnen werden, sind unzulässig."}]}]}'::jsonb, '§20.0 Geiselnahmen Geiselnahmen im Roleplay – Regeln & Vorgaben §20.1– Safe-Zones sind tabu: Geiselnahmen dürfen nicht innerhalb einer Safe-Zone stattfinden. §20.2– Geeignetes Fahrzeug: Die Geiselnahme muss in einem Fahrzeug mit mindestens vier Sitzplätzen erfolgen. §20.3– Verhandlungsbereitschaft: Sowohl Polizei als auch Geiselnehmer müssen jederzeit zur Verhandlung bereit sein. §20.4– Forderungsgrenze: Pro Geisel ist nur eine konkrete Forderung erlaubt – diese muss zudem realistisch und umsetzbar sein. §20.5– Einhaltung der Forderungen: Vereinbarte Forderungen müssen von beiden Seiten eingehalten werden. §20.6– Freie Flucht: Eine „Freie Flucht“-Forderung darf maximal 15 Sekunden lang sein – bei E-Fahrzeugen nur 10 Sekunden. Bei einer Freien-flucht, ist es Verboten während der ausgehandelten Zeit Stopsticks / Spikes etc zu "Werfen", zudem ist es auch Verboten währendessen auf das Auto zu Schießen.§20.7 – Die Freie Flucht zu Blockieren wird zudem auch als Bruch der Verhandlungen angesehen. §20.8– Geiseln pro Geiselnehmer: Jeder Geiselnehmer darf maximal eine Geisel nehmen. §20.9– Zeitlimit: Eine Geisel darf nicht länger als 20 Minuten festgehalten werden. Danach muss die Geisel freigelassen werden. §20.10– Sicherstellung der Unversehrtheit: Alle Beteiligten, Polizei wie Geiselnehmer müssen sich bemühen, die Geisel während der gesamten Situation zu schützen. §20.11– Stürmungsrecht der Polizei: Die Polizei darf die Situation stürmen, wenn keine akute Gefahr mehr für die Geisel besteht – zum Beispiel, wenn niemand mehr aktiv auf sie zielt. §20.12– Sonderregelung für Dienst-Fraktionen: Rettungsdienst, Feuerwehr und ADAC dürfen nur dann als Geiseln genommen werden, wenn eine akute Ausnahmesituation vorliegt – etwa wenn Geiselnehmer von der Polizei verfolgt werden und keine andere Fluchtmöglichkeit mehr haben. §20.13– Kinderschutz: Kinder dürfen niemals als Geiseln genommen werden. §20.14 Schein-Geiseln sind ausnahmslos unzulässig, da sie den Grundsatz fairen Rollenspiels verletzen. §20.15 Die Geiselnahme eines Polizeibeamten ist erst ab einer Mindestpräsenz von 3 aktiven Polizeikräften im Rollenspiel zulässig. Die Unterschreitung dieser Mindestanzahl ist strikt untersagt. §20.16 Zwischen zwei Geiselnahmen muss ein Mindestabstand von 30 Minuten liegen. Geiselnahmen, die innerhalb dieses Zeitraums erneut begonnen werden, sind unzulässig.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-21', 'main-21', 'main-21', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§21.0 Tier RP', 21, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-21-v1', 'rule-main-21', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Tier-RP & unzulässige Charakterdarstellungen"}]},{"type":"paragraph","content":[{"type":"text","text":"§21.1 Das Ausspielen von Tier-RP ist auf unserem Server strengstens untersagt und kann entsprechende Konsequenzen nach sich ziehen. Es gibt keinerlei Ausnahmen von dieser Regel – das gilt auch für andere tierähnliche Charaktere."}]},{"type":"paragraph","content":[{"type":"text","text":"§21.2 Sollte die Identität des Charakters nicht eindeutig menschlich erkennbar sein, ist der Skin nicht erlaubt und der Charakter darf im RP nicht genutzt werden."}]},{"type":"paragraph","content":[{"type":"text","text":"§21.3 Furry-Skins sind am Spawn erlaubt jedoch nicht im RP."}]}]}'::jsonb, '§21.0 Tier RP Tier-RP & unzulässige Charakterdarstellungen §21.1 Das Ausspielen von Tier-RP ist auf unserem Server strengstens untersagt und kann entsprechende Konsequenzen nach sich ziehen. Es gibt keinerlei Ausnahmen von dieser Regel – das gilt auch für andere tierähnliche Charaktere. §21.2 Sollte die Identität des Charakters nicht eindeutig menschlich erkennbar sein, ist der Skin nicht erlaubt und der Charakter darf im RP nicht genutzt werden. §21.3 Furry-Skins sind am Spawn erlaubt jedoch nicht im RP.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-22', 'main-22', 'main-22', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§22.0 Medic Roleplay', 22, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-22-v1', 'rule-main-22', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Medic Roleplay (Rettungsdienst-RP)"}]},{"type":"paragraph","content":[{"type":"text","text":"§22.1 Das Medic Roleplay ist verpflichtend und muss jederzeit ernsthaft ausgespielt werden."}]},{"type":"paragraph","content":[{"type":"text","text":"§22.2 Während eine medizinische Behandlung stattfindet, gilt im Umkreis von 5 Metern eine Safe-Zone – Einsätze des Rettungsdienstes dürfen nicht gestört oder angegriffen werden."}]},{"type":"paragraph","content":[{"type":"text","text":"§22.3 Verletzte Personen müssen mit einem RTW, KTW oder ITW transportiert werden. Eine Ausnahme besteht nur, wenn aktuell keines dieser Fahrzeuge verfügbar ist."}]},{"type":"paragraph","content":[{"type":"text","text":"§22.4 Eigenschutz geht vor: Einsatzkräfte dürfen sich nicht unnötig in Gefahr bringen. Bei aktiver Bedrohung ist der Rückzug erlaubt."}]},{"type":"paragraph","content":[{"type":"text","text":"§22.5 Nach dem eigenen Tod muss verpflichtend der \"EMS Call\" Button gedrückt werden."}]},{"type":"paragraph","content":[{"type":"text","text":"§22.6 Befindet sich kein Mitglied des Rettungsdienstes im Dienst, muss man mindestens 5 Minuten warten, bevor man respawnen darf. Sind aktive Medics im Dienst, beträgt die Wartezeit mindestens 7 Minuten."}]},{"type":"paragraph","content":[{"type":"text","text":"§22.7 Befindet sich Rettungspersonal in der Nähe, ist das Respawnen nicht erlaubt – man muss die Versorgung durch das Rettungsteam abwarten."}]},{"type":"paragraph","content":[{"type":"text","text":"§22.8 Ausschließlich der offizielle Rettungsdienst ist befugt, Medic RP zu betreiben. Jegliches eigenmächtige Medic RP durch Nicht-Mitglieder wird als Regelverstoß gewertet."}]},{"type":"paragraph","content":[{"type":"text","text":"§22.8 Medic RP Dürfen auch Zivilisten / Polizisten etc auch ausspielen wenn KEIN einziger Medic Online ist."}]},{"type":"paragraph","content":[{"type":"text","text":"§22.9 Sich bewusst „tot zu stellen“ oder den eigenen Charakter ohne nachvollziehbaren RP-Grund als tot darzustellen, ist untersagt. Dieses Verhalten gilt als RP-Verweigerung, da dadurch laufende RP-Situationen – insbesondere Maßnahmen des Rettungsdienstes, der Polizei oder anderer Spieler – absichtlich blockiert oder umgangen werden."}]}]}'::jsonb, '§22.0 Medic Roleplay Medic Roleplay (Rettungsdienst-RP) §22.1 Das Medic Roleplay ist verpflichtend und muss jederzeit ernsthaft ausgespielt werden. §22.2 Während eine medizinische Behandlung stattfindet, gilt im Umkreis von 5 Metern eine Safe-Zone – Einsätze des Rettungsdienstes dürfen nicht gestört oder angegriffen werden. §22.3 Verletzte Personen müssen mit einem RTW, KTW oder ITW transportiert werden. Eine Ausnahme besteht nur, wenn aktuell keines dieser Fahrzeuge verfügbar ist. §22.4 Eigenschutz geht vor: Einsatzkräfte dürfen sich nicht unnötig in Gefahr bringen. Bei aktiver Bedrohung ist der Rückzug erlaubt. §22.5 Nach dem eigenen Tod muss verpflichtend der "EMS Call" Button gedrückt werden. §22.6 Befindet sich kein Mitglied des Rettungsdienstes im Dienst, muss man mindestens 5 Minuten warten, bevor man respawnen darf. Sind aktive Medics im Dienst, beträgt die Wartezeit mindestens 7 Minuten. §22.7 Befindet sich Rettungspersonal in der Nähe, ist das Respawnen nicht erlaubt – man muss die Versorgung durch das Rettungsteam abwarten. §22.8 Ausschließlich der offizielle Rettungsdienst ist befugt, Medic RP zu betreiben. Jegliches eigenmächtige Medic RP durch Nicht-Mitglieder wird als Regelverstoß gewertet. §22.8 Medic RP Dürfen auch Zivilisten / Polizisten etc auch ausspielen wenn KEIN einziger Medic Online ist. §22.9 Sich bewusst „tot zu stellen“ oder den eigenen Charakter ohne nachvollziehbaren RP-Grund als tot darzustellen, ist untersagt. Dieses Verhalten gilt als RP-Verweigerung, da dadurch laufende RP-Situationen – insbesondere Maßnahmen des Rettungsdienstes, der Polizei oder anderer Spieler – absichtlich blockiert oder umgangen werden.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-23', 'main-23', 'main-23', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§23.0 Waffen', 23, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-23-v1', 'rule-main-23', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§23.1 Das Mitführen oder Benutzen von Waffen ist in allen Safe-Zonen strengstens untersagt. Dazu zählen unter anderem: Messer, Pistolen, Gewehre und andere Waffen."}]},{"type":"paragraph","content":[{"type":"text","text":"§23.2 Das Schießen mit Waffen unter Wasser ist nicht erlaubt – ebenso ist das Tasern unter Wasser verboten, da dies in keiner Weise realistisch wäre."}]},{"type":"paragraph","content":[{"type":"text","text":"§23.3 Der Befehl „Zieht Waffe“ (ZW) ist auf unserem Server keine Pflicht. Es liegt im Ermessen des Spielers, ob er diesen zur Verdeutlichung verwendet, doch er ersetzt keine RP-Handlung."}]},{"type":"paragraph","content":[{"type":"text","text":"§23.4 Es gibt auf unserem Server keine sogenannten „Fake-Waffen“. Jede gezogene Waffe ist als echt zu betrachten – auch Spielzeuge, Airsoft-Waffen o. ä. gelten als vollwertige Bedrohung innerhalb des Roleplays."}]}]}'::jsonb, '§23.0 Waffen §23.1 Das Mitführen oder Benutzen von Waffen ist in allen Safe-Zonen strengstens untersagt. Dazu zählen unter anderem: Messer, Pistolen, Gewehre und andere Waffen. §23.2 Das Schießen mit Waffen unter Wasser ist nicht erlaubt – ebenso ist das Tasern unter Wasser verboten, da dies in keiner Weise realistisch wäre. §23.3 Der Befehl „Zieht Waffe“ (ZW) ist auf unserem Server keine Pflicht. Es liegt im Ermessen des Spielers, ob er diesen zur Verdeutlichung verwendet, doch er ersetzt keine RP-Handlung. §23.4 Es gibt auf unserem Server keine sogenannten „Fake-Waffen“. Jede gezogene Waffe ist als echt zu betrachten – auch Spielzeuge, Airsoft-Waffen o. ä. gelten als vollwertige Bedrohung innerhalb des Roleplays.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-24', 'main-24', 'main-24', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§24.0 Drohnen Regel', 24, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-24-v1', 'rule-main-24', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Drohnenverwendung"}]},{"type":"paragraph","content":[{"type":"text","text":"§24.1 Das Verwenden von Drohnen ist in allen Safe-Zonen sowie in der unmittelbaren Nähe eines aktiven Modcalls untersagt. Dies dient dem Schutz der Privatsphäre und der ungestörten Bearbeitung von Supportfällen."}]},{"type":"paragraph","content":[{"type":"text","text":"§24.2 Auch in Gang-Gebieten ist der Einsatz von Drohnen strengstens verboten, um unfaire Informationsvorteile oder Metagaming zu verhindern."}]},{"type":"paragraph","content":[{"type":"text","text":"§24.3 Drohnen dürfen nur in öffentlichen Bereichen außerhalb dieser Zonen genutzt werden – stets unter Beachtung der allgemeinen RP-Regeln."}]}]}'::jsonb, '§24.0 Drohnen Regel Drohnenverwendung §24.1 Das Verwenden von Drohnen ist in allen Safe-Zonen sowie in der unmittelbaren Nähe eines aktiven Modcalls untersagt. Dies dient dem Schutz der Privatsphäre und der ungestörten Bearbeitung von Supportfällen. §24.2 Auch in Gang-Gebieten ist der Einsatz von Drohnen strengstens verboten, um unfaire Informationsvorteile oder Metagaming zu verhindern. §24.3 Drohnen dürfen nur in öffentlichen Bereichen außerhalb dieser Zonen genutzt werden – stets unter Beachtung der allgemeinen RP-Regeln.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-25', 'main-25', 'main-25', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§25.0 RP Flucht', 25, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-25-v1', 'rule-main-25', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Unzulässige RP-Flucht"}]},{"type":"paragraph","content":[{"type":"text","text":"§25.1 Das unerlaubte Verlassen einer aktiven RP-Situation – auch bekannt als RP-Flucht – ist auf unserem Server nicht gestattet, da es den Spielfluss und die Immersion erheblich stört."}]},{"type":"paragraph","content":[{"type":"text","text":"Als RP-Flucht gelten unter anderem folgende Handlungen: – Das Entfernen von der RP-Situation um mehr als 50 Meter ohne ersichtlichen RP-Grund. – Das Verlassen des Ingame-Servers während einer laufenden Szene. – Das Wechseln des Teams oder Jobs, um sich einer Situation zu entziehen."}]},{"type":"paragraph","content":[{"type":"text","text":"§25.2 Jeder Spieler ist verpflichtet, eine begonnene RP-Situation vollständig und realistisch zu Ende zu spielen. Zuwiderhandlungen können zu Verwarnungen oder weiteren Konsequenzen führen."}]}]}'::jsonb, '§25.0 RP Flucht Unzulässige RP-Flucht §25.1 Das unerlaubte Verlassen einer aktiven RP-Situation – auch bekannt als RP-Flucht – ist auf unserem Server nicht gestattet, da es den Spielfluss und die Immersion erheblich stört. Als RP-Flucht gelten unter anderem folgende Handlungen: – Das Entfernen von der RP-Situation um mehr als 50 Meter ohne ersichtlichen RP-Grund. – Das Verlassen des Ingame-Servers während einer laufenden Szene. – Das Wechseln des Teams oder Jobs, um sich einer Situation zu entziehen. §25.2 Jeder Spieler ist verpflichtet, eine begonnene RP-Situation vollständig und realistisch zu Ende zu spielen. Zuwiderhandlungen können zu Verwarnungen oder weiteren Konsequenzen führen.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-26', 'main-26', 'main-26', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§26.0 Support Flucht', 26, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-26-v1', 'rule-main-26', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Support-Flucht"}]},{"type":"paragraph","content":[{"type":"text","text":"§26.1 Das absichtliche Flüchten vor einem Supporter ist strengstens untersagt und wird als Support-Flucht gewertet. Jeder Spieler ist dazu verpflichtet, bei einem eingeleiteten Supportfall mitzuwirken und erreichbar zu bleiben."}]},{"type":"paragraph","content":[{"type":"text","text":"Folgende Handlungen gelten als Support-Flucht: – Das Entfernen um mehr als 50 Meter vom Supporter ohne Zustimmung. – Das Verlassen des Ingame-Servers während eines laufenden Supports. – Das Wechseln des Jobs oder Teams, um sich dem Support zu entziehen."}]},{"type":"paragraph","content":[{"type":"text","text":"§26.2 Support-Situationen sind genauso verbindlich wie RP-Situationen. Ein Verstoß gegen diese Regel kann direkte Sanktionen nach sich ziehen."}]}]}'::jsonb, '§26.0 Support Flucht Support-Flucht §26.1 Das absichtliche Flüchten vor einem Supporter ist strengstens untersagt und wird als Support-Flucht gewertet. Jeder Spieler ist dazu verpflichtet, bei einem eingeleiteten Supportfall mitzuwirken und erreichbar zu bleiben. Folgende Handlungen gelten als Support-Flucht: – Das Entfernen um mehr als 50 Meter vom Supporter ohne Zustimmung. – Das Verlassen des Ingame-Servers während eines laufenden Supports. – Das Wechseln des Jobs oder Teams, um sich dem Support zu entziehen. §26.2 Support-Situationen sind genauso verbindlich wie RP-Situationen. Ein Verstoß gegen diese Regel kann direkte Sanktionen nach sich ziehen.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-27', 'main-27', 'main-27', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§27.1 Skins/Fail Skins', 27, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-27-v1', 'rule-main-27', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Realistische Darstellung von Skins"}]},{"type":"paragraph","content":[{"type":"text","text":"§27.1 Alle Skins auf unserem Server müssen realistisch und glaubwürdig gestaltet sein. Es ist nicht erlaubt, Skins zu verwenden, die unrealistische Eigenschaften oder Darstellungen aufweisen. Im Einzelnen bedeutet das:"}]},{"type":"paragraph","content":[{"type":"text","text":"§27.2– Schwebende oder fliegende Objekte sind nicht gestattet. Jeder Skin muss physikalisch korrekt dargestellt werden. §27.3– Die Hautfarbe eines Skins darf nicht unrealistisch sein, wie beispielsweise Weiß, Grau oder andere nicht natürliche Farben. §27.4– Der Skin darf keinen spielerischen Vorteil verschaffen, wie etwa eine kleinere Hitbox oder andere Vorteile, die den Charakter im Spiel benachteiligen würden. §27.5– Das Tragen von SWAT-Westen oder SWAT-Helmen ist auf diesem Server ausdrücklich verboten, da dies in den meisten Fällen keine realistische Darstellung ist. §27.6– Alle Skins müssen den Roblox Terms of Service (ToS) entsprechen und dürfen keine Verstöße gegen diese beinhalten. §27.7– Uniformen, die vom Server gestellt werden, sind Pflicht und müssen getragen werden, um eine konsistente und faire Spielerfahrung zu gewährleisten."}]},{"type":"paragraph","content":[{"type":"text","text":"§27.8 Das Ziel ist, ein realistisches und immersives Roleplay zu fördern, das allen Spielern ein faires und glaubwürdiges Erlebnis bietet."}]}]}'::jsonb, '§27.1 Skins/Fail Skins Realistische Darstellung von Skins §27.1 Alle Skins auf unserem Server müssen realistisch und glaubwürdig gestaltet sein. Es ist nicht erlaubt, Skins zu verwenden, die unrealistische Eigenschaften oder Darstellungen aufweisen. Im Einzelnen bedeutet das: §27.2– Schwebende oder fliegende Objekte sind nicht gestattet. Jeder Skin muss physikalisch korrekt dargestellt werden. §27.3– Die Hautfarbe eines Skins darf nicht unrealistisch sein, wie beispielsweise Weiß, Grau oder andere nicht natürliche Farben. §27.4– Der Skin darf keinen spielerischen Vorteil verschaffen, wie etwa eine kleinere Hitbox oder andere Vorteile, die den Charakter im Spiel benachteiligen würden. §27.5– Das Tragen von SWAT-Westen oder SWAT-Helmen ist auf diesem Server ausdrücklich verboten, da dies in den meisten Fällen keine realistische Darstellung ist. §27.6– Alle Skins müssen den Roblox Terms of Service (ToS) entsprechen und dürfen keine Verstöße gegen diese beinhalten. §27.7– Uniformen, die vom Server gestellt werden, sind Pflicht und müssen getragen werden, um eine konsistente und faire Spielerfahrung zu gewährleisten. §27.8 Das Ziel ist, ein realistisches und immersives Roleplay zu fördern, das allen Spielern ein faires und glaubwürdiges Erlebnis bietet.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-28', 'main-28', 'main-28', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§28.0 Überfälle', 28, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-28-v1', 'rule-main-28', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Überfälle auf Banken und Juweliere"}]},{"type":"paragraph","content":[{"type":"text","text":"§28.1 Überfälle auf die Bank müssen immer zwei Personen involvieren. Ein Überfall kann nur dann durchgeführt werden, wenn mindestens zwei Spieler aktiv an der Tat beteiligt sind."}]},{"type":"paragraph","content":[{"type":"text","text":"§28.2 Für alle anderen ausraubbaren Gegenstände, wie zum Beispiel Kassen, Geldautomaten oder ähnliche Ziele, ist es auch einzelnen Spielern gestattet, diese zu überfallen."}]},{"type":"paragraph","content":[{"type":"text","text":"§28.3 Das Ziel dieser Regel ist es, bestimmte Überfälle, auf die Banken, als größere, komplexere Aktionen darzustellen, bei denen Teamarbeit erforderlich ist, während kleinere Raubüberfälle durch Einzelpersonen durchgeführt werden können."}]}]}'::jsonb, '§28.0 Überfälle Überfälle auf Banken und Juweliere §28.1 Überfälle auf die Bank müssen immer zwei Personen involvieren. Ein Überfall kann nur dann durchgeführt werden, wenn mindestens zwei Spieler aktiv an der Tat beteiligt sind. §28.2 Für alle anderen ausraubbaren Gegenstände, wie zum Beispiel Kassen, Geldautomaten oder ähnliche Ziele, ist es auch einzelnen Spielern gestattet, diese zu überfallen. §28.3 Das Ziel dieser Regel ist es, bestimmte Überfälle, auf die Banken, als größere, komplexere Aktionen darzustellen, bei denen Teamarbeit erforderlich ist, während kleinere Raubüberfälle durch Einzelpersonen durchgeführt werden können.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-29', 'main-29', 'main-29', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§29.0 Falschgeld', 29, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-29-v1', 'rule-main-29', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§29.1 Der Einsatz von Falschgeld ist im RP grundsätzlich erlaubt, solange er realistisch ausgespielt wird und nicht zum massiven Wirtschaftsmissbrauch führt. Es darf nicht dauerhaft als primäre Einnahmequelle genutzt werden. Ein Missbrauch kann durch das Team jederzeit geahndet werden."}]}]}'::jsonb, '§29.0 Falschgeld §29.1 Der Einsatz von Falschgeld ist im RP grundsätzlich erlaubt, solange er realistisch ausgespielt wird und nicht zum massiven Wirtschaftsmissbrauch führt. Es darf nicht dauerhaft als primäre Einnahmequelle genutzt werden. Ein Missbrauch kann durch das Team jederzeit geahndet werden.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-30', 'main-30', 'main-30', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§30.0 Korruption', 30, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-30-v1', 'rule-main-30', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§30.1 Korruption ist in gewissem Rahmen erlaubt, muss jedoch realistisch, logisch und nachvollziehbar ausgespielt werden. Sie darf nicht übertrieben oder spielzerstörend sein und sollte dem RP dienen – nicht zur persönlichen Bereicherung außerhalb des Rollenspiels. Bei unangemessener Ausnutzung kann das Team eingreifen."}]}]}'::jsonb, '§30.0 Korruption §30.1 Korruption ist in gewissem Rahmen erlaubt, muss jedoch realistisch, logisch und nachvollziehbar ausgespielt werden. Sie darf nicht übertrieben oder spielzerstörend sein und sollte dem RP dienen – nicht zur persönlichen Bereicherung außerhalb des Rollenspiels. Bei unangemessener Ausnutzung kann das Team eingreifen.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-31', 'main-31', 'main-31', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§31.0 Gamepässe und Werkzeuge', 31, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-31-v1', 'rule-main-31', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Verbotene und erlaubte Gamepass-Nutzung und Tools"}]},{"type":"paragraph","content":[{"type":"text","text":"§31.1 Das Nutzen des Gamepasses \"Instant Refuel\" ist auf unserem Server verboten. Dies verstößt gegen die Prinzipien des fairen Gameplays und verzerrt das Spielerlebnis."}]},{"type":"paragraph","content":[{"type":"text","text":"§31.2 Das Verwenden des Scanners ist ebenfalls verboten und wird als Meta Gaming angesehen. Informationen, die auf diesem Weg erhalten werden, dürfen nicht in das Ingame-RP eingebracht werden, da dies das Spiel unfair macht."}]},{"type":"paragraph","content":[{"type":"text","text":"§31.3 Das Nutzen des Polizeihelikopters ist verboten und fällt unter Meta Gaming. Das Fliegen und die Nutzung des Helikopters für die Erfassung von Informationen oder Überwachung von Spielern sind nicht gestattet, da sie ebenfalls den Verlauf des Spiels manipulieren können."}]},{"type":"paragraph","content":[{"type":"text","text":"§31.4 Das Nutzen der \"Spray Can\" (Sprühdose) ist erlaubt, jedoch sollte man dabei stets das Ausmaß im Blick behalten. Übermäßiger oder unnötiger Einsatz dieser Dosen, der das RP stört oder unrealistisch wirkt, sollte vermieden werden."}]}]}'::jsonb, '§31.0 Gamepässe und Werkzeuge Verbotene und erlaubte Gamepass-Nutzung und Tools §31.1 Das Nutzen des Gamepasses "Instant Refuel" ist auf unserem Server verboten. Dies verstößt gegen die Prinzipien des fairen Gameplays und verzerrt das Spielerlebnis. §31.2 Das Verwenden des Scanners ist ebenfalls verboten und wird als Meta Gaming angesehen. Informationen, die auf diesem Weg erhalten werden, dürfen nicht in das Ingame-RP eingebracht werden, da dies das Spiel unfair macht. §31.3 Das Nutzen des Polizeihelikopters ist verboten und fällt unter Meta Gaming. Das Fliegen und die Nutzung des Helikopters für die Erfassung von Informationen oder Überwachung von Spielern sind nicht gestattet, da sie ebenfalls den Verlauf des Spiels manipulieren können. §31.4 Das Nutzen der "Spray Can" (Sprühdose) ist erlaubt, jedoch sollte man dabei stets das Ausmaß im Blick behalten. Übermäßiger oder unnötiger Einsatz dieser Dosen, der das RP stört oder unrealistisch wirkt, sollte vermieden werden.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-32', 'main-32', 'main-32', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§32.0 Crash Roleplay', 32, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-32-v1', 'rule-main-32', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Crash Roleplay (CRP) – Unfall und Folgen"}]},{"type":"paragraph","content":[{"type":"text","text":"§32.1 Das Crash Roleplay muss immer nach einem Unfall ausgespielt werden, der eine Geschwindigkeit von mindestens 40 km/h überschreitet. Dies stellt sicher, dass jeder Unfall realistisch und im Einklang mit den RP-Regeln behandelt wird."}]},{"type":"paragraph","content":[{"type":"text","text":"§32.2 Bei sehr hohen Geschwindigkeiten von 100 km/h oder mehr muss zwingend ein Notruf getätigt werden, um den Vorfall korrekt zu melden und die nötigen Rettungsmaßnahmen einzuleiten."}]},{"type":"paragraph","content":[{"type":"text","text":"§32.3 Nach einem Unfall ist es erforderlich, dass der Spieler zuerst auf sich selbst sowie auf das beschädigte Fahrzeug achtet. Das sofortige Weiterfahren nach einem Unfall ohne eine realistische Reaktion auf den Schaden ist nicht gestattet und verstößt gegen das Prinzip des realistischen Rollenspiels."}]},{"type":"paragraph","content":[{"type":"text","text":"§32.4 Sollte das Fahrzeug schwer beschädigt sein, so muss ebenfalls umgehend ein Notruf getätigt werden. Bei größeren Schäden ist es entscheidend, die nötigen Rettungsdienste zu alarmieren, um das Spielgeschehen aufrechtzuerhalten und die Sicherheit aller Beteiligten zu gewährleisten."}]},{"type":"paragraph","content":[{"type":"text","text":"§32.5 Der Swat Truck von der POL muss das Crash-RP erst ab einer Geschwindigkeit von ca 80 km/h ausspielen."}]},{"type":"paragraph","content":[{"type":"text","text":"§32.6 Das Crash RP entfällt bei Objekten die umgefahren werden können (Zaun, Laternen, Schilder etc.)"}]}]}'::jsonb, '§32.0 Crash Roleplay Crash Roleplay (CRP) – Unfall und Folgen §32.1 Das Crash Roleplay muss immer nach einem Unfall ausgespielt werden, der eine Geschwindigkeit von mindestens 40 km/h überschreitet. Dies stellt sicher, dass jeder Unfall realistisch und im Einklang mit den RP-Regeln behandelt wird. §32.2 Bei sehr hohen Geschwindigkeiten von 100 km/h oder mehr muss zwingend ein Notruf getätigt werden, um den Vorfall korrekt zu melden und die nötigen Rettungsmaßnahmen einzuleiten. §32.3 Nach einem Unfall ist es erforderlich, dass der Spieler zuerst auf sich selbst sowie auf das beschädigte Fahrzeug achtet. Das sofortige Weiterfahren nach einem Unfall ohne eine realistische Reaktion auf den Schaden ist nicht gestattet und verstößt gegen das Prinzip des realistischen Rollenspiels. §32.4 Sollte das Fahrzeug schwer beschädigt sein, so muss ebenfalls umgehend ein Notruf getätigt werden. Bei größeren Schäden ist es entscheidend, die nötigen Rettungsdienste zu alarmieren, um das Spielgeschehen aufrechtzuerhalten und die Sicherheit aller Beteiligten zu gewährleisten. §32.5 Der Swat Truck von der POL muss das Crash-RP erst ab einer Geschwindigkeit von ca 80 km/h ausspielen. §32.6 Das Crash RP entfällt bei Objekten die umgefahren werden können (Zaun, Laternen, Schilder etc.)', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-33', 'main-33', 'main-33', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§33.0 Livery´s / Uniformen', 33, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-33-v1', 'rule-main-33', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Verwendung von Liverys und Uniformen"}]},{"type":"paragraph","content":[{"type":"text","text":"§33.1 Es ist ausschließlich erlaubt, die Liverys und Uniformen zu verwenden, die vom Server bereitgestellt werden. Diese wurden speziell für den Server erstellt und müssen zu allen Zeiten genutzt werden, um Konsistenz und ein authentisches Spielerlebnis zu gewährleisten."}]},{"type":"paragraph","content":[{"type":"text","text":"§33.2 Liverys und Uniformen mit dem Zusatz „DC Only“ im Namen dürfen nur von Spielern genutzt werden, die im entsprechenden Discord-Server (DC) Mitglied sind. Diese speziellen Designs sind für bestimmte Gruppen und müssen daher nur von den berechtigten Nutzern verwendet werden."}]},{"type":"paragraph","content":[{"type":"text","text":"§33.3 Uniformen müssen stets klar erkennbar und sichtbar sein. Es darf nichts die Uniform verdecken, um Missverständnissen vorzubeugen. Dies gewährleistet, dass jeder Spieler im RP die Rolle und Funktion des jeweiligen Charakters eindeutig erkennt."}]},{"type":"paragraph","content":[{"type":"text","text":"§33.4 Liverys und Uniformen, die „gesperrt“ sind, dürfen nicht verwendet werden. Die Verwendung solcher Designs kann schwere Konsequenzen nach sich ziehen, da sie gegen die Server-Regeln verstoßen. Spieler, die gesperrte Liverys oder Uniformen verwenden, müssen mit sofortigen Maßnahmen rechnen."}]}]}'::jsonb, '§33.0 Livery´s / Uniformen Verwendung von Liverys und Uniformen §33.1 Es ist ausschließlich erlaubt, die Liverys und Uniformen zu verwenden, die vom Server bereitgestellt werden. Diese wurden speziell für den Server erstellt und müssen zu allen Zeiten genutzt werden, um Konsistenz und ein authentisches Spielerlebnis zu gewährleisten. §33.2 Liverys und Uniformen mit dem Zusatz „DC Only“ im Namen dürfen nur von Spielern genutzt werden, die im entsprechenden Discord-Server (DC) Mitglied sind. Diese speziellen Designs sind für bestimmte Gruppen und müssen daher nur von den berechtigten Nutzern verwendet werden. §33.3 Uniformen müssen stets klar erkennbar und sichtbar sein. Es darf nichts die Uniform verdecken, um Missverständnissen vorzubeugen. Dies gewährleistet, dass jeder Spieler im RP die Rolle und Funktion des jeweiligen Charakters eindeutig erkennt. §33.4 Liverys und Uniformen, die „gesperrt“ sind, dürfen nicht verwendet werden. Die Verwendung solcher Designs kann schwere Konsequenzen nach sich ziehen, da sie gegen die Server-Regeln verstoßen. Spieler, die gesperrte Liverys oder Uniformen verwenden, müssen mit sofortigen Maßnahmen rechnen.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-34', 'main-34', 'main-34', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§34.0 Polizei', 34, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-34-v1', 'rule-main-34', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§34.1 Festnahmen und Uniformen Als Polizist muss immer ein Grund für eine Festnahme vorhanden sein. Man darf nur die Uniformen tragen, die für den eigenen Rang zugelassen sind. Das Nutzen von Langwaffen im Inventar ist ausschließlich für Spezialeinheiten erlaubt. Streifenpolizisten dürfen Langwaffen nur im Kofferraum führen."}]},{"type":"paragraph","content":[{"type":"text","text":"§34.2 Verhalten und Missbrauch Das Missbrauchen der Handschellen ist verboten, ebenso wie das sogenannte „Cuff Rush“. Bei einer Geiselnahme hat immer der höhergestellte Polizist das Sagen."}]},{"type":"paragraph","content":[{"type":"text","text":"§34.3 Disziplin und Verantwortung Der Höherdienst ist berechtigt, Suspendierungen von bis zu einem Monat auszusprechen. Das Ausgeben als eine höhergestellte Person ist untersagt. Als Polizist muss das eigene Leben immer an erster Stelle stehen."}]},{"type":"paragraph","content":[{"type":"text","text":"§34.4 Zusammenarbeit und Absperrung Polizisten dürfen keine Unterstützung für Gang- oder Mafia-Mitglieder leisten. Bei Absperrungen muss darauf geachtet werden, dass immer noch Autos vorbeifahren können. Ein vollständiges Sperren von Straßen ist verboten. Spezialeinheiten sind nicht berechtigt, Verkehrskontrollen durchzuführen."}]},{"type":"paragraph","content":[{"type":"text","text":"§34.5 Festnahmeprozedere Nach der Festnahme einer Person hat der Polizist fünf Sekunden Zeit, „cuff“ zu schreiben."}]}]}'::jsonb, '§34.0 Polizei §34.1 Festnahmen und Uniformen Als Polizist muss immer ein Grund für eine Festnahme vorhanden sein. Man darf nur die Uniformen tragen, die für den eigenen Rang zugelassen sind. Das Nutzen von Langwaffen im Inventar ist ausschließlich für Spezialeinheiten erlaubt. Streifenpolizisten dürfen Langwaffen nur im Kofferraum führen. §34.2 Verhalten und Missbrauch Das Missbrauchen der Handschellen ist verboten, ebenso wie das sogenannte „Cuff Rush“. Bei einer Geiselnahme hat immer der höhergestellte Polizist das Sagen. §34.3 Disziplin und Verantwortung Der Höherdienst ist berechtigt, Suspendierungen von bis zu einem Monat auszusprechen. Das Ausgeben als eine höhergestellte Person ist untersagt. Als Polizist muss das eigene Leben immer an erster Stelle stehen. §34.4 Zusammenarbeit und Absperrung Polizisten dürfen keine Unterstützung für Gang- oder Mafia-Mitglieder leisten. Bei Absperrungen muss darauf geachtet werden, dass immer noch Autos vorbeifahren können. Ein vollständiges Sperren von Straßen ist verboten. Spezialeinheiten sind nicht berechtigt, Verkehrskontrollen durchzuführen. §34.5 Festnahmeprozedere Nach der Festnahme einer Person hat der Polizist fünf Sekunden Zeit, „cuff“ zu schreiben.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-35', 'main-35', 'main-35', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§35.0 Rettungsdienst', 35, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-35-v1', 'rule-main-35', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§35.1 Medic RP und Verantwortung Der Rettungsdienst muss immer das Medic RP ausspielen und sich an die Regeln des Roleplays halten. Der Rettungsdienst ist nicht berechtigt, andere Dinge zu löschen oder zu verändern, außer bei Fahrzeugbränden, bei denen ein Feuerlöscher (CO2) eingesetzt werden darf."}]},{"type":"paragraph","content":[{"type":"text","text":"§35.2 Rollenanforderungen Das Spielen als Notarzt, Leitender Notarzt (LNA), Desinfektor oder Organisatorische Leitung (OrgL) ist nur erlaubt, wenn der Spieler die entsprechende Rolle im Discord besitzt."}]},{"type":"paragraph","content":[{"type":"text","text":"§35.3 Verbotene Aktivitäten Das Aufbauen von Impfstationen ist verboten. Der Rettungsdienst ist nicht befugt, große Brände zu löschen. Eine Ausnahme besteht nur bei Fahrzeugbränden, bei denen der CO2-Feuerlöscher verwendet werden darf."}]},{"type":"paragraph","content":[{"type":"text","text":"§35.4 Neutralität und Schweigepflicht Der Rettungsdienst ist verpflichtet, stets neutral zu bleiben und die ärztliche Schweigepflicht zu wahren."}]},{"type":"paragraph","content":[{"type":"text","text":"§35.5 Beinflussung des Rettungsdienstes"}]},{"type":"paragraph","content":[{"type":"text","text":"Jegliche Einflussnahme auf den Rettungsdienst ist untersagt. Anweisungen oder Forderungen wie „Versorge nur meine Leute“ oder das bewusste Zurücklassen anderer verletzter Personen sind im Roleplay nicht gestattet. Der Rettungsdienst ist verpflichtet, alle Personen unabhängig von Fraktion, Zugehörigkeit oder Rolle gleich zu behandeln."}]}]}'::jsonb, '§35.0 Rettungsdienst §35.1 Medic RP und Verantwortung Der Rettungsdienst muss immer das Medic RP ausspielen und sich an die Regeln des Roleplays halten. Der Rettungsdienst ist nicht berechtigt, andere Dinge zu löschen oder zu verändern, außer bei Fahrzeugbränden, bei denen ein Feuerlöscher (CO2) eingesetzt werden darf. §35.2 Rollenanforderungen Das Spielen als Notarzt, Leitender Notarzt (LNA), Desinfektor oder Organisatorische Leitung (OrgL) ist nur erlaubt, wenn der Spieler die entsprechende Rolle im Discord besitzt. §35.3 Verbotene Aktivitäten Das Aufbauen von Impfstationen ist verboten. Der Rettungsdienst ist nicht befugt, große Brände zu löschen. Eine Ausnahme besteht nur bei Fahrzeugbränden, bei denen der CO2-Feuerlöscher verwendet werden darf. §35.4 Neutralität und Schweigepflicht Der Rettungsdienst ist verpflichtet, stets neutral zu bleiben und die ärztliche Schweigepflicht zu wahren. §35.5 Beinflussung des Rettungsdienstes Jegliche Einflussnahme auf den Rettungsdienst ist untersagt. Anweisungen oder Forderungen wie „Versorge nur meine Leute“ oder das bewusste Zurücklassen anderer verletzter Personen sind im Roleplay nicht gestattet. Der Rettungsdienst ist verpflichtet, alle Personen unabhängig von Fraktion, Zugehörigkeit oder Rolle gleich zu behandeln.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-36', 'main-36', 'main-36', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§36.0 Feuerwehr', 36, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-36-v1', 'rule-main-36', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Feuerwehr-Richtlinien"}]},{"type":"paragraph","content":[{"type":"text","text":"§36.1 Die Feuerwehr ist nicht befugt, Personen ins Krankenhaus zu fahren. Dies liegt in der Verantwortung des Rettungsdienstes, der die notwendige medizinische Versorgung leisten muss. Ebenso ist es der Feuerwehr untersagt, das Gerät „Monitor/EKG“ zu verwenden, da dieses ausschließlich dem Rettungsdienst vorbehalten ist."}]},{"type":"paragraph","content":[{"type":"text","text":"§36.2 Das Missbrauchen der Drehleiter (DLK) ist ebenfalls verboten. Die DLK darf nur für feuerwehrtechnische Einsätze genutzt werden, bei denen sie tatsächlich erforderlich ist. Zudem ist die Nutzung der „Simpel Fire Hose“ untersagt. Diese darf garnicht verwendet werden, um das Gameplay fair zu halten."}]}]}'::jsonb, '§36.0 Feuerwehr Feuerwehr-Richtlinien §36.1 Die Feuerwehr ist nicht befugt, Personen ins Krankenhaus zu fahren. Dies liegt in der Verantwortung des Rettungsdienstes, der die notwendige medizinische Versorgung leisten muss. Ebenso ist es der Feuerwehr untersagt, das Gerät „Monitor/EKG“ zu verwenden, da dieses ausschließlich dem Rettungsdienst vorbehalten ist. §36.2 Das Missbrauchen der Drehleiter (DLK) ist ebenfalls verboten. Die DLK darf nur für feuerwehrtechnische Einsätze genutzt werden, bei denen sie tatsächlich erforderlich ist. Zudem ist die Nutzung der „Simpel Fire Hose“ untersagt. Diese darf garnicht verwendet werden, um das Gameplay fair zu halten.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-37', 'main-37', 'main-37', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§37.0 ADAC', 37, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-37-v1', 'rule-main-37', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"ADAC-Richtlinien"}]},{"type":"paragraph","content":[{"type":"text","text":"§37.1 Der ADAC ist berechtigt, Fahrzeuge abzuschleppen, jedoch nur mit einem entsprechenden RP-Hintergrund. Das Abschleppen darf nur in Situationen erfolgen, in denen Fahrzeuge die Straße blockieren, falsch parken oder ähnliche Probleme verursachen."}]},{"type":"paragraph","content":[{"type":"text","text":"§37.2 Wichtig ist, dass der ADAC kein Einsatzfahrzeug ist. Das bedeutet, dass die ADAC-Fahrzeuge nicht über rote Ampeln fahren oder sich mit überhöhter Geschwindigkeit fortbewegen dürfen."}]},{"type":"paragraph","content":[{"type":"text","text":"§37.3 Mehrfaches, grundloses Abschleppen von Fahrzeugen kann als Trolling betrachtet werden und zu entsprechenden Konsequenzen führen. Jeder Abschleppvorgang muss einen klaren RP-Hintergrund und einen realistischen Grund haben."}]}]}'::jsonb, '§37.0 ADAC ADAC-Richtlinien §37.1 Der ADAC ist berechtigt, Fahrzeuge abzuschleppen, jedoch nur mit einem entsprechenden RP-Hintergrund. Das Abschleppen darf nur in Situationen erfolgen, in denen Fahrzeuge die Straße blockieren, falsch parken oder ähnliche Probleme verursachen. §37.2 Wichtig ist, dass der ADAC kein Einsatzfahrzeug ist. Das bedeutet, dass die ADAC-Fahrzeuge nicht über rote Ampeln fahren oder sich mit überhöhter Geschwindigkeit fortbewegen dürfen. §37.3 Mehrfaches, grundloses Abschleppen von Fahrzeugen kann als Trolling betrachtet werden und zu entsprechenden Konsequenzen führen. Jeder Abschleppvorgang muss einen klaren RP-Hintergrund und einen realistischen Grund haben.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-38', 'main-38', 'main-38', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§38.0 Gang´s', 38, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-38-v1', 'rule-main-38', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Gang-Richtlinien"}]},{"type":"paragraph","content":[{"type":"text","text":"§38.1 Eine inoffizielle Gang darf nur aus maximal 3 Mitgliedern bestehen. Möchte man mit mehr Mitgliedern in einer Gang RP betreiben, muss eine offizielle Gang gegründet werden. Offizielle Gangs haben bestimmte Rechte und Pflichten innerhalb des Servers."}]},{"type":"paragraph","content":[{"type":"text","text":"§38.2 Innerhalb des Ganggebiets gilt immer ein Schusscall, der den Gangmitgliedern erlaubt, in ihrem Gebiet zu agieren. Dabei müssen sie jedoch das \"Gambo RP\" beachten, um unrealistische oder unangemessene Situationen zu vermeiden."}]},{"type":"paragraph","content":[{"type":"text","text":"§38.3 Die New Life Rule (NLR) entfällt für Gangmitglieder in ihrem eigenen Ganggebiet. Das bedeutet, wenn ein Gangmitglied in seinem Ganggebiet stirbt, darf es dorthin zurückkehren, da es als „Zuhause“ der Gang betrachtet wird. Jedoch ist es weiterhin wichtig, das RP realistisch zu gestalten und die anderen Regeln zu respektieren."}]},{"type":"paragraph","content":[{"type":"text","text":"§38.4 Weiteres und genaueres kann man unter \"Fraktions Regelwerk\" Nachlesen"}]},{"type":"paragraph","content":[{"type":"text","text":"§38.5 Gangs sind verpflichtet, sich im Roleplay eindeutig kenntlich zu machen. Dies erfolgt durch die Verwendung ihrer zugewiesenen Farben, Erkennungsmerkmale sowie ggf. weiterer charakteristischer Kennzeichen.Die Zugehörigkeit zu einer Gang muss für andere Spieler im RP nachvollziehbar und erkennbar sein, um ein realistisches und strukturiertes Spielgeschehen zu gewährleisten."}]},{"type":"paragraph","content":[{"type":"text","text":"§38.6 Es ist strengstens verboten, Polizeibeamte mutwillig oder durch Vortäuschung falscher Tatsachen in ein Gang-Gebiet zu locken (sog. Cop-Baiting). Zuwiderhandlungen werden als Regelverstoß gewertet."}]}]}'::jsonb, '§38.0 Gang´s Gang-Richtlinien §38.1 Eine inoffizielle Gang darf nur aus maximal 3 Mitgliedern bestehen. Möchte man mit mehr Mitgliedern in einer Gang RP betreiben, muss eine offizielle Gang gegründet werden. Offizielle Gangs haben bestimmte Rechte und Pflichten innerhalb des Servers. §38.2 Innerhalb des Ganggebiets gilt immer ein Schusscall, der den Gangmitgliedern erlaubt, in ihrem Gebiet zu agieren. Dabei müssen sie jedoch das "Gambo RP" beachten, um unrealistische oder unangemessene Situationen zu vermeiden. §38.3 Die New Life Rule (NLR) entfällt für Gangmitglieder in ihrem eigenen Ganggebiet. Das bedeutet, wenn ein Gangmitglied in seinem Ganggebiet stirbt, darf es dorthin zurückkehren, da es als „Zuhause“ der Gang betrachtet wird. Jedoch ist es weiterhin wichtig, das RP realistisch zu gestalten und die anderen Regeln zu respektieren. §38.4 Weiteres und genaueres kann man unter "Fraktions Regelwerk" Nachlesen §38.5 Gangs sind verpflichtet, sich im Roleplay eindeutig kenntlich zu machen. Dies erfolgt durch die Verwendung ihrer zugewiesenen Farben, Erkennungsmerkmale sowie ggf. weiterer charakteristischer Kennzeichen.Die Zugehörigkeit zu einer Gang muss für andere Spieler im RP nachvollziehbar und erkennbar sein, um ein realistisches und strukturiertes Spielgeschehen zu gewährleisten. §38.6 Es ist strengstens verboten, Polizeibeamte mutwillig oder durch Vortäuschung falscher Tatsachen in ein Gang-Gebiet zu locken (sog. Cop-Baiting). Zuwiderhandlungen werden als Regelverstoß gewertet.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-39', 'main-39', 'main-39', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§39.0 Imunitäten', 39, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-39-v1', 'rule-main-39', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Grundsatz"}]},{"type":"paragraph","content":[{"type":"text","text":"Im Deutschland Roleplay gilt uneingeschränkt:"},{"type":"text","text":"Alle Spieler:innen unterliegen gleichermaßen den RP-Regeln und den geltenden Gesetzen."},{"type":"text","text":"Es existieren"},{"type":"text","text":"keine Immunitäten"},{"type":"text","text":"– unabhängig von Rang, Fraktion, Rolle oder Funktion."}]},{"type":"paragraph","content":[{"type":"text","text":"Geltungsbereich"}]},{"type":"paragraph","content":[{"type":"text","text":"Dieses Verbot umfasst unter anderem:"}]},{"type":"paragraph","content":[{"type":"text","text":"Schutz vor Kontrollen, Festnahmen oder Durchsuchungen"}]},{"type":"paragraph","content":[{"type":"text","text":"Unantastbarkeit im Straf- oder Ermittlungsverfahren"}]},{"type":"paragraph","content":[{"type":"text","text":"Umgehung von Strafen oder RP-Folgen durch Dienstgrad oder Rang"}]},{"type":"paragraph","content":[{"type":"text","text":"\"God-Roleplay\" (Unverletzlichkeit, Übermenschlichkeit etc.)"}]},{"type":"paragraph","content":[{"type":"text","text":"Ausnahmen"}]},{"type":"paragraph","content":[{"type":"text","text":"Ausnahmen sind"},{"type":"text","text":"nur im Vorfeld genehmigte RP-Events"},{"type":"text","text":", die vom"},{"type":"text","text":"Serverteam explizit angekündigt und freigegeben"},{"type":"text","text":"wurden. Eine selbstbestimmte Immunität ohne klare Genehmigung ist"},{"type":"text","text":"nicht erlaubt"},{"type":"text","text":"."}]}]}'::jsonb, '§39.0 Imunitäten Grundsatz Im Deutschland Roleplay gilt uneingeschränkt: Alle Spieler:innen unterliegen gleichermaßen den RP-Regeln und den geltenden Gesetzen. Es existieren keine Immunitäten – unabhängig von Rang, Fraktion, Rolle oder Funktion. Geltungsbereich Dieses Verbot umfasst unter anderem: Schutz vor Kontrollen, Festnahmen oder Durchsuchungen Unantastbarkeit im Straf- oder Ermittlungsverfahren Umgehung von Strafen oder RP-Folgen durch Dienstgrad oder Rang "God-Roleplay" (Unverletzlichkeit, Übermenschlichkeit etc.) Ausnahmen Ausnahmen sind nur im Vorfeld genehmigte RP-Events , die vom Serverteam explizit angekündigt und freigegeben wurden. Eine selbstbestimmte Immunität ohne klare Genehmigung ist nicht erlaubt .', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-40', 'main-40', 'main-40', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§40.0 Staff Team', 40, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-40-v1', 'rule-main-40', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Staff Team Richtlinien"}]},{"type":"paragraph","content":[{"type":"text","text":"§40.1 Staff Team Mitglieder sind im Roleplay (RP) unsichtbar, was bedeutet, dass sie nicht aktiv in RP-Situationen eingebunden werden, es sei denn, sie handeln in ihrer offiziellen Funktion als Moderatoren."}]},{"type":"paragraph","content":[{"type":"text","text":"§40.2 Das grundlose Rufen eines Staff Team Mitglieds wird bestraft, da es den normalen RP-Fluss stört und das Team nicht unnötig involviert werden soll. Sollte man ein Staff Team Auto rammen, muss kein Crash RP ausgespielt werden. Jedoch wird das absichtliche Rammen eines Staff Team Autos bestraft, da es als respektlos gegenüber den Regeln und den Teammitgliedern angesehen wird."}]},{"type":"paragraph","content":[{"type":"text","text":"§40.3 Als Beweis für Regelverstöße reicht auch eine Aussage eines Moderators aus, solange das Teammitglied On Duty ist. Sollte zu dem Zeitpunkt kein Staff Mitglied ingame sein, kann der Spieler ein Ticket auf dem Discord-Server eröffnen, um das Problem zu schildern und eine Lösung zu finden."}]},{"type":"paragraph","content":[{"type":"text","text":"§40.4 Der Support-fall und der damit beinhaltetnde RP Stopp begint erst wenn das Staffmitglied vorort ist."}]},{"type":"paragraph","content":[{"type":"text","text":"§40.5 Nach einer RP auflösung durch ein Staff-Mitglied dürfen die \"Selben\" Parteien für 5 minuten dort keine neue RP Szene beginnen."}]},{"type":"paragraph","content":[{"type":"text","text":"§40.6 Wenn ein Staffmitglied einen Kick vergibt so muss man 20 Minuten warten bis man erneut dem Server beitreten kann, sollte man vorher beitreten folgen weiter Sanktionen."}]},{"type":"paragraph","content":[{"type":"text","text":"§40.7 Disskussionen aller art sind unerwünscht das Staff Team hat immer das letzte Wort."}]}]}'::jsonb, '§40.0 Staff Team Staff Team Richtlinien §40.1 Staff Team Mitglieder sind im Roleplay (RP) unsichtbar, was bedeutet, dass sie nicht aktiv in RP-Situationen eingebunden werden, es sei denn, sie handeln in ihrer offiziellen Funktion als Moderatoren. §40.2 Das grundlose Rufen eines Staff Team Mitglieds wird bestraft, da es den normalen RP-Fluss stört und das Team nicht unnötig involviert werden soll. Sollte man ein Staff Team Auto rammen, muss kein Crash RP ausgespielt werden. Jedoch wird das absichtliche Rammen eines Staff Team Autos bestraft, da es als respektlos gegenüber den Regeln und den Teammitgliedern angesehen wird. §40.3 Als Beweis für Regelverstöße reicht auch eine Aussage eines Moderators aus, solange das Teammitglied On Duty ist. Sollte zu dem Zeitpunkt kein Staff Mitglied ingame sein, kann der Spieler ein Ticket auf dem Discord-Server eröffnen, um das Problem zu schildern und eine Lösung zu finden. §40.4 Der Support-fall und der damit beinhaltetnde RP Stopp begint erst wenn das Staffmitglied vorort ist. §40.5 Nach einer RP auflösung durch ein Staff-Mitglied dürfen die "Selben" Parteien für 5 minuten dort keine neue RP Szene beginnen. §40.6 Wenn ein Staffmitglied einen Kick vergibt so muss man 20 Minuten warten bis man erneut dem Server beitreten kann, sollte man vorher beitreten folgen weiter Sanktionen. §40.7 Disskussionen aller art sind unerwünscht das Staff Team hat immer das letzte Wort.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-41', 'main-41', 'main-41', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§41.0 Spezial Events', 41, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-41-v1', 'rule-main-41', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§41.1 Winter Event"}]},{"type":"paragraph","content":[{"type":"text","text":"Das Befahren von Eisflächen mit Fahrzeugen ist untersagt, da es dem realistischen Rollenspiel (RP) widerspricht und als unzulässiges FRP bestraft wird."}]},{"type":"paragraph","content":[{"type":"text","text":"§41.2 Halloween / Murder Mysterie"}]},{"type":"paragraph","content":[{"type":"text","text":"Die Einnahme von Tränken (Potions) oder ähnlichen magischen/fantastischen Konsumgütern ist untersagt. Solche Gegenstände verstoßen gegen die Realismus-Anforderung des Rollenspiels (FRP)."}]},{"type":"paragraph","content":[{"type":"text","text":"§41.3 Razzia"}]},{"type":"paragraph","content":[{"type":"text","text":"Im Falle einer Razzia innerhalb des Gang-Gebiets wird die New Life Rule (NLR) für die beteiligten Gang-Mitglieder nicht angewandt. Stirbt ein Gang-Mitglied während der Razzia, ist ihm die Rückkehr in das umkämpfte Gebiet für die Dauer des Events strikt untersagt."}]}]}'::jsonb, '§41.0 Spezial Events §41.1 Winter Event Das Befahren von Eisflächen mit Fahrzeugen ist untersagt, da es dem realistischen Rollenspiel (RP) widerspricht und als unzulässiges FRP bestraft wird. §41.2 Halloween / Murder Mysterie Die Einnahme von Tränken (Potions) oder ähnlichen magischen/fantastischen Konsumgütern ist untersagt. Solche Gegenstände verstoßen gegen die Realismus-Anforderung des Rollenspiels (FRP). §41.3 Razzia Im Falle einer Razzia innerhalb des Gang-Gebiets wird die New Life Rule (NLR) für die beteiligten Gang-Mitglieder nicht angewandt. Stirbt ein Gang-Mitglied während der Razzia, ist ihm die Rückkehr in das umkämpfte Gebiet für die Dauer des Events strikt untersagt.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-42', 'main-42', 'main-42', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§42.0 Neutralität', 42, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-42-v1', 'rule-main-42', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§42.1 Neutralität im Roleplay"}]},{"type":"paragraph","content":[{"type":"text","text":"Innerhalb des gesamten Roleplays auf dem Server ist ein neutraler Umgang mit religiösen Themen verpflichtend. Religion darf weder aktiv dargestellt, noch als Teil einer Rolle, Organisation oder Handlung im Spiel eingebunden werden."}]},{"type":"paragraph","content":[{"type":"text","text":"§42.2 Verbot religiöser Darstellungen"}]},{"type":"paragraph","content":[{"type":"text","text":"Das Ausspielen von Religionen oder religiösen Gruppierungen im Roleplay ist nicht gestattet. Hierzu zählen unter anderem religiöse Organisationen, Geistliche Rollen, religiöse Versammlungen oder vergleichbare Darstellungen."}]},{"type":"paragraph","content":[{"type":"text","text":"§42.3 Verbot religiöser Aussagen"}]},{"type":"paragraph","content":[{"type":"text","text":"Religiöse Aussagen, Gebete oder Ausrufe sind im Roleplay nicht erwünscht und daher zu unterlassen. Dazu zählen beispielsweise Formulierungen wie „Allahu Akbar“ oder vergleichbare religiöse Ausdrücke aus anderen Glaubensrichtungen."}]},{"type":"paragraph","content":[{"type":"text","text":"§42.4 Schutz religiöser Neutralität"}]},{"type":"paragraph","content":[{"type":"text","text":"Jegliche Form von religiöser Einflussnahme auf andere Spieler, Gruppen oder Fraktionen ist untersagt. Das Roleplay soll frei von religiösen Inhalten bleiben, um Konflikte, Provokationen oder Missverständnisse innerhalb der Community zu vermeiden."}]},{"type":"paragraph","content":[{"type":"text","text":"§42.5 Gleichbehandlung aller Glaubensrichtungen"}]},{"type":"paragraph","content":[{"type":"text","text":"Diese Regelung gilt unabhängig von der jeweiligen Religion oder Weltanschauung. Es werden keine einzelnen Religionen gesondert behandelt; sämtliche religiösen Inhalte sind im Roleplay gleichermaßen untersagt."}]},{"type":"paragraph","content":[{"type":"text","text":"§42.6 Konsequenzen bei Verstößen"}]},{"type":"paragraph","content":[{"type":"text","text":"Verstöße gegen diese Regelung können je nach Schwere des Vorfalls durch das Serverteam sanktioniert werden. Mögliche Maßnahmen reichen von Verwarnungen bis hin zu temporären oder permanenten Ausschlüssen vom Server."}]},{"type":"paragraph","content":[{"type":"text","text":"§42.7 Verbot realer Kriege und Konflikte"}]},{"type":"paragraph","content":[{"type":"text","text":"Das Darstellen, Ausspielen oder Thematisieren realer militärischer Konflikte und Kriege im Roleplay ist untersagt. Hierzu zählen unter anderem aktuelle oder vergangene Konflikte zwischen realen Staaten oder Regionen."}]},{"type":"paragraph","content":[{"type":"text","text":"§42.8 Bezug auf aktuelle geopolitische Ereignisse"}]},{"type":"paragraph","content":[{"type":"text","text":"Die Erwähnung, Darstellung oder Nachstellung aktueller geopolitischer Ereignisse innerhalb des Roleplays ist nicht gestattet. Der Server soll frei von realpolitischen Spannungen und Konflikten bleiben."}]},{"type":"paragraph","content":[{"type":"text","text":"§42.9 Politische Neutralität"}]},{"type":"paragraph","content":[{"type":"text","text":"Innerhalb des Roleplays ist eine strikt neutrale Haltung gegenüber politischen Themen verpflichtend. Politische Diskussionen, Aussagen oder Darstellungen sind im Roleplay nicht erwünscht."}]},{"type":"paragraph","content":[{"type":"text","text":"§42.10 Verbot politischer Parteien und Ideologien"}]},{"type":"paragraph","content":[{"type":"text","text":"Das Darstellen, Unterstützen oder Erwähnen realer politischer Parteien, Bewegungen oder Ideologien ist im Roleplay untersagt. Hierzu zählen beispielsweise Parteien, politische Gruppierungen oder vergleichbare Organisationen."}]},{"type":"paragraph","content":[{"type":"text","text":"§42.11 Politische Parolen und Symbole"}]},{"type":"paragraph","content":[{"type":"text","text":"Politische Parolen, Symbole, Flaggen oder vergleichbare Darstellungen, welche eine politische Position oder Ideologie ausdrücken, dürfen im Roleplay weder verwendet noch gezeigt werden."}]},{"type":"paragraph","content":[{"type":"text","text":"§42.12 Einflussnahme durch politische Inhalte"}]},{"type":"paragraph","content":[{"type":"text","text":"Jegliche Form von politischer Einflussnahme, Propaganda oder politischer Überzeugungsarbeit gegenüber anderen Spielern ist im Roleplay untersagt, um eine neutrale und konfliktfreie Spielumgebung zu gewährleisten."}]}]}'::jsonb, '§42.0 Neutralität §42.1 Neutralität im Roleplay Innerhalb des gesamten Roleplays auf dem Server ist ein neutraler Umgang mit religiösen Themen verpflichtend. Religion darf weder aktiv dargestellt, noch als Teil einer Rolle, Organisation oder Handlung im Spiel eingebunden werden. §42.2 Verbot religiöser Darstellungen Das Ausspielen von Religionen oder religiösen Gruppierungen im Roleplay ist nicht gestattet. Hierzu zählen unter anderem religiöse Organisationen, Geistliche Rollen, religiöse Versammlungen oder vergleichbare Darstellungen. §42.3 Verbot religiöser Aussagen Religiöse Aussagen, Gebete oder Ausrufe sind im Roleplay nicht erwünscht und daher zu unterlassen. Dazu zählen beispielsweise Formulierungen wie „Allahu Akbar“ oder vergleichbare religiöse Ausdrücke aus anderen Glaubensrichtungen. §42.4 Schutz religiöser Neutralität Jegliche Form von religiöser Einflussnahme auf andere Spieler, Gruppen oder Fraktionen ist untersagt. Das Roleplay soll frei von religiösen Inhalten bleiben, um Konflikte, Provokationen oder Missverständnisse innerhalb der Community zu vermeiden. §42.5 Gleichbehandlung aller Glaubensrichtungen Diese Regelung gilt unabhängig von der jeweiligen Religion oder Weltanschauung. Es werden keine einzelnen Religionen gesondert behandelt; sämtliche religiösen Inhalte sind im Roleplay gleichermaßen untersagt. §42.6 Konsequenzen bei Verstößen Verstöße gegen diese Regelung können je nach Schwere des Vorfalls durch das Serverteam sanktioniert werden. Mögliche Maßnahmen reichen von Verwarnungen bis hin zu temporären oder permanenten Ausschlüssen vom Server. §42.7 Verbot realer Kriege und Konflikte Das Darstellen, Ausspielen oder Thematisieren realer militärischer Konflikte und Kriege im Roleplay ist untersagt. Hierzu zählen unter anderem aktuelle oder vergangene Konflikte zwischen realen Staaten oder Regionen. §42.8 Bezug auf aktuelle geopolitische Ereignisse Die Erwähnung, Darstellung oder Nachstellung aktueller geopolitischer Ereignisse innerhalb des Roleplays ist nicht gestattet. Der Server soll frei von realpolitischen Spannungen und Konflikten bleiben. §42.9 Politische Neutralität Innerhalb des Roleplays ist eine strikt neutrale Haltung gegenüber politischen Themen verpflichtend. Politische Diskussionen, Aussagen oder Darstellungen sind im Roleplay nicht erwünscht. §42.10 Verbot politischer Parteien und Ideologien Das Darstellen, Unterstützen oder Erwähnen realer politischer Parteien, Bewegungen oder Ideologien ist im Roleplay untersagt. Hierzu zählen beispielsweise Parteien, politische Gruppierungen oder vergleichbare Organisationen. §42.11 Politische Parolen und Symbole Politische Parolen, Symbole, Flaggen oder vergleichbare Darstellungen, welche eine politische Position oder Ideologie ausdrücken, dürfen im Roleplay weder verwendet noch gezeigt werden. §42.12 Einflussnahme durch politische Inhalte Jegliche Form von politischer Einflussnahme, Propaganda oder politischer Überzeugungsarbeit gegenüber anderen Spielern ist im Roleplay untersagt, um eine neutrale und konfliktfreie Spielumgebung zu gewährleisten.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-43', 'main-43', 'main-43', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§43 Charakterregelung', 43, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-43-v1', 'rule-main-43', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§43.1 – Ein Charakter pro Fraktion"},{"type":"text","text":"Jeder Spieler darf innerhalb einer Fraktion ausschließlich"},{"type":"text","text":"einen festen Charakter"},{"type":"text","text":"führen. Mehrere Charaktere innerhalb derselben Fraktion sind nicht gestattet."}]},{"type":"paragraph","content":[{"type":"text","text":"§43.2 – Trennung von Charakteren"},{"type":"text","text":"Das gleichzeitige oder abwechselnde Spielen mehrerer Charaktere in derselben Fraktion, um sich Vorteile zu verschaffen oder Rollen zu umgehen, ist untersagt."}]},{"type":"paragraph","content":[{"type":"text","text":"§43.3 – Fraktionsübergreifende Charaktere"},{"type":"text","text":"Es ist erlaubt, unterschiedliche Charaktere in"},{"type":"text","text":"verschiedenen Fraktionen"},{"type":"text","text":"zu spielen, sofern diese strikt voneinander getrennt sind und keine Informationen oder Vorteile übertragen werden."}]},{"type":"paragraph","content":[{"type":"text","text":"§43.4 – Verbot von Charakter-Missbrauch"},{"type":"text","text":"Das Erstellen oder Nutzen mehrerer Charaktere innerhalb einer Fraktion zur Umgehung von Regeln, Rangsystemen oder Konsequenzen gilt als Missbrauch und ist untersagt."}]},{"type":"paragraph","content":[{"type":"text","text":"§43.5 – Realistische Charakterführung"},{"type":"text","text":"Jeder Charakter ist eigenständig und realistisch auszuspielen. Ein häufiger oder unlogischer Wechsel zwischen Charakteren innerhalb einer Fraktion ist nicht zulässig."}]},{"type":"paragraph","content":[{"type":"text","text":"§43.6 – Konsequenzen bei Verstößen"},{"type":"text","text":"Verstöße gegen diese Regelung werden sanktioniert. Maßnahmen können je nach Schwere des Verstoßes von Verwarnungen über Fraktionsausschlüsse bis hin zu temporären oder permanenten Sperren führen."}]}]}'::jsonb, '§43 Charakterregelung §43.1 – Ein Charakter pro Fraktion Jeder Spieler darf innerhalb einer Fraktion ausschließlich einen festen Charakter führen. Mehrere Charaktere innerhalb derselben Fraktion sind nicht gestattet. §43.2 – Trennung von Charakteren Das gleichzeitige oder abwechselnde Spielen mehrerer Charaktere in derselben Fraktion, um sich Vorteile zu verschaffen oder Rollen zu umgehen, ist untersagt. §43.3 – Fraktionsübergreifende Charaktere Es ist erlaubt, unterschiedliche Charaktere in verschiedenen Fraktionen zu spielen, sofern diese strikt voneinander getrennt sind und keine Informationen oder Vorteile übertragen werden. §43.4 – Verbot von Charakter-Missbrauch Das Erstellen oder Nutzen mehrerer Charaktere innerhalb einer Fraktion zur Umgehung von Regeln, Rangsystemen oder Konsequenzen gilt als Missbrauch und ist untersagt. §43.5 – Realistische Charakterführung Jeder Charakter ist eigenständig und realistisch auszuspielen. Ein häufiger oder unlogischer Wechsel zwischen Charakteren innerhalb einer Fraktion ist nicht zulässig. §43.6 – Konsequenzen bei Verstößen Verstöße gegen diese Regelung werden sanktioniert. Maßnahmen können je nach Schwere des Verstoßes von Verwarnungen über Fraktionsausschlüsse bis hin zu temporären oder permanenten Sperren führen.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-main-44', 'main-44', 'main-44', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk', 'Roleplay-Regelwerk', '§44 Drittpartei', 44, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-main-44-v1', 'rule-main-44', 'PUBLISHED', '{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"§44.1 Definition"}]},{"type":"paragraph","content":[{"type":"text","text":"Als Drittpartei gilt jede Person oder Fraktion, die"},{"type":"text","text":"nicht aktiv an einer laufenden RP-Situation beteiligt ist"},{"type":"text","text":", sich jedoch nachträglich in diese einmischt."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"§44.2 Grundsatz"}]},{"type":"paragraph","content":[{"type":"text","text":"Das Eingreifen als Drittpartei ist"},{"type":"text","text":"situationsabhängig geregelt"},{"type":"text","text":"und nicht pauschal verboten."},{"type":"text","text":"Dabei wird zwischen"},{"type":"text","text":"kleinen"},{"type":"text","text":"und"},{"type":"text","text":"großen RP-Situationen"},{"type":"text","text":"unterschieden."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"§44.3 Große RP-Situationen"}]},{"type":"paragraph","content":[{"type":"text","text":"Bei größeren, bereits laufenden Lagen ist das Eingreifen als Drittpartei"},{"type":"text","text":"grundsätzlich untersagt"},{"type":"text","text":"."}]},{"type":"paragraph","content":[{"type":"text","text":"Dazu zählen insbesondere:"}]},{"type":"paragraph","content":[{"type":"text","text":"Großunfälle"}]},{"type":"paragraph","content":[{"type":"text","text":"Geiselnahmen (z. B. Bank, Juwelier)"}]},{"type":"paragraph","content":[{"type":"text","text":"Großeinsatzlagen mit mehreren beteiligten Parteien"}]},{"type":"paragraph","content":[{"type":"text","text":"koordinierte oder geplante Events"}]},{"type":"paragraph","content":[{"type":"text","text":"In solchen Situationen dürfen"},{"type":"text","text":"keine weiteren Parteien ohne klare Einbindung"},{"type":"text","text":"eingreifen, um Chaos, Unfairness und Eskalationen zu verhindern."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"§44.4 Kleine RP-Situationen"}]},{"type":"paragraph","content":[{"type":"text","text":"Bei kleineren, überschaubaren Situationen ist eine Einmischung als Drittpartei"},{"type":"text","text":"grundsätzlich erlaubt"},{"type":"text","text":", sofern diese"},{"type":"text","text":"realistisch und nachvollziehbar"},{"type":"text","text":"erfolgt."}]},{"type":"paragraph","content":[{"type":"text","text":"Dazu zählen insbesondere:"}]},{"type":"paragraph","content":[{"type":"text","text":"Verkehrskontrollen"}]},{"type":"paragraph","content":[{"type":"text","text":"Personenkontrollen oder Gespräche"}]},{"type":"paragraph","content":[{"type":"text","text":"kleinere Einzel- oder Alltagssituationen"}]},{"type":"paragraph","content":[{"type":"text","text":"In diesen Fällen ist es erlaubt:"}]},{"type":"paragraph","content":[{"type":"text","text":"sich in das Geschehen einzubringen"}]},{"type":"paragraph","content":[{"type":"text","text":"Situationen zu beeinflussen oder zu erweitern"}]},{"type":"paragraph","content":[{"type":"text","text":"unter Umständen auch Geiselnahmen oder ähnliche Handlungen einzuleiten"}]},{"type":"paragraph","content":[{"type":"text","text":"Voraussetzung ist immer, dass das Eingreifen"},{"type":"text","text":"sauber ausgespielt und logisch begründet"},{"type":"text","text":"ist."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"§44.5 Einschränkungen"}]},{"type":"paragraph","content":[{"type":"text","text":"Auch bei erlaubter Einmischung gilt:"}]},{"type":"paragraph","content":[{"type":"text","text":"Kein unrealistisches oder erzwungenes Verhalten"}]},{"type":"paragraph","content":[{"type":"text","text":"Keine massenhaften Eingriffe ohne RP-Grund"}]},{"type":"paragraph","content":[{"type":"text","text":"Kein gezieltes Stören oder „Zerstören“ von laufendem RP"}]}]}'::jsonb, '§44 Drittpartei §44.1 Definition Als Drittpartei gilt jede Person oder Fraktion, die nicht aktiv an einer laufenden RP-Situation beteiligt ist , sich jedoch nachträglich in diese einmischt. §44.2 Grundsatz Das Eingreifen als Drittpartei ist situationsabhängig geregelt und nicht pauschal verboten. Dabei wird zwischen kleinen und großen RP-Situationen unterschieden. §44.3 Große RP-Situationen Bei größeren, bereits laufenden Lagen ist das Eingreifen als Drittpartei grundsätzlich untersagt . Dazu zählen insbesondere: Großunfälle Geiselnahmen (z. B. Bank, Juwelier) Großeinsatzlagen mit mehreren beteiligten Parteien koordinierte oder geplante Events In solchen Situationen dürfen keine weiteren Parteien ohne klare Einbindung eingreifen, um Chaos, Unfairness und Eskalationen zu verhindern. §44.4 Kleine RP-Situationen Bei kleineren, überschaubaren Situationen ist eine Einmischung als Drittpartei grundsätzlich erlaubt , sofern diese realistisch und nachvollziehbar erfolgt. Dazu zählen insbesondere: Verkehrskontrollen Personenkontrollen oder Gespräche kleinere Einzel- oder Alltagssituationen In diesen Fällen ist es erlaubt: sich in das Geschehen einzubringen Situationen zu beeinflussen oder zu erweitern unter Umständen auch Geiselnahmen oder ähnliche Handlungen einzuleiten Voraussetzung ist immer, dass das Eingreifen sauber ausgespielt und logisch begründet ist. §44.5 Einschränkungen Auch bei erlaubter Einmischung gilt: Kein unrealistisches oder erzwungenes Verhalten Keine massenhaften Eingriffe ohne RP-Grund Kein gezieltes Stören oder „Zerstören“ von laufendem RP', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-faction-1', 'faction-1', 'faction-1', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk/fraktionsregelwerk', 'Fraktionsregelwerk', '§1 – Grundlagen & Begriffsdefinitionen', 1, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-faction-1-v1', 'rule-faction-1', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§1.1 Begriffserklärung"}]},{"type":"paragraph","content":[{"type":"text","text":"a) Hauptfraktionen: Hauptfraktionen sind die zentralen Organisationen des Servers, welche die Grundversorgung des Roleplays sicherstellen (z. B. Polizei, Feuerwehr, Rettungsdienst). Aufgrund ihrer tragenden Rolle für Sicherheit und Ordnung gelten für sie und ihre Mitglieder verschärfte Anforderungen an Aktivität, Serverpräsenz und vorbildliches Verhalten."}]},{"type":"paragraph","content":[{"type":"text","text":"b) Nebenfraktionen: Nebenfraktionen sind kleinere, spezialisierte oder private Organisationen (z. B. das Department of Transportation, eingetragene Unternehmen oder Gangs/Maffien), die das Roleplay ergänzen. Sie besitzen keinen vergleichbaren behördlichen Einfluss wie Hauptfraktionen. Die finale Einstufung erfolgt ausschließlich durch das Fraktionsmanagement (FM)."}]},{"type":"paragraph","content":[{"type":"text","text":"c) Legale und illegale Fraktionen:"},{"type":"text","text":"Legale Fraktionen agieren strikt im Rahmen der geltenden Gesetze und verfolgen behördliche, zivile oder wirtschaftliche Ziele.Illegale Fraktionen (z. B. Banden, Kartelle) sind auf kriminelles Roleplay ausgelegt und agieren dauerhaft außerhalb des Gesetzes."}]},{"type":"paragraph","content":[{"type":"text","text":"Legale Fraktionen agieren strikt im Rahmen der geltenden Gesetze und verfolgen behördliche, zivile oder wirtschaftliche Ziele."}]},{"type":"paragraph","content":[{"type":"text","text":"Illegale Fraktionen (z. B. Banden, Kartelle) sind auf kriminelles Roleplay ausgelegt und agieren dauerhaft außerhalb des Gesetzes."}]},{"type":"paragraph","content":[{"type":"text","text":"d) Fraktions-Discords & Kompetenzen: Die übergeordnete Verwaltung aller Fraktionen obliegt dem Fraktionsmanagement und dem Director. Für alle offiziellen Fraktions-Discord-Server gilt:"},{"type":"text","text":"Das FM muss jederzeit vollen Lese- und Kontrollzugriff (mindestens Audit-Log-Einsicht) besitzen. Dh das FM MUSS in alle channels reinschauen können zur Kontrolle.Fraktionsleitungen dürfen ihren Mitgliedern keine administrativen Rechte (z. B. \"Server verwalten\", \"Rollen verwalten\", \"Administrator\") auf den Fraktions-Discords geben, um Missbrauch vorzubeugen. Admin-Rechte liegen exklusiv beim FM/Serverleitung."}]},{"type":"paragraph","content":[{"type":"text","text":"Das FM muss jederzeit vollen Lese- und Kontrollzugriff (mindestens Audit-Log-Einsicht) besitzen. Dh das FM MUSS in alle channels reinschauen können zur Kontrolle."}]},{"type":"paragraph","content":[{"type":"text","text":"Fraktionsleitungen dürfen ihren Mitgliedern keine administrativen Rechte (z. B. \"Server verwalten\", \"Rollen verwalten\", \"Administrator\") auf den Fraktions-Discords geben, um Missbrauch vorzubeugen. Admin-Rechte liegen exklusiv beim FM/Serverleitung."}]},{"type":"paragraph","content":[{"type":"text","text":"§1.2 Verantwortlichkeiten"}]},{"type":"paragraph","content":[{"type":"text","text":"Fraktionsleitung: Ist vollumfänglich für die interne Organisation, die Aktivitätskontrolle, das Fehlverhalten ihrer Mitglieder sowie die Durchsetzung des Regelwerks innerhalb der Fraktion verantwortlich."}]},{"type":"paragraph","content":[{"type":"text","text":"Fraktionsmanagement (FM): Überwacht die Fraktionslandschaft, agiert als neutrale Beschwerdestelle, greift bei Missständen ein und sorgt für ein faires Balancing im Gesamt-RP."}]},{"type":"paragraph","content":[{"type":"text","text":"Fraktionsmitglieder: Sind zur aktiven Teilnahme am Fraktions-RP sowie zur lückenlosen Einhaltung dieses Regelwerks verpflichtet. Fehlverhalten spiegelt sich immer auch auf die gesamte Fraktion wider."}]}]}'::jsonb, '§1 – Grundlagen & Begriffsdefinitionen §1.1 Begriffserklärung a) Hauptfraktionen: Hauptfraktionen sind die zentralen Organisationen des Servers, welche die Grundversorgung des Roleplays sicherstellen (z. B. Polizei, Feuerwehr, Rettungsdienst). Aufgrund ihrer tragenden Rolle für Sicherheit und Ordnung gelten für sie und ihre Mitglieder verschärfte Anforderungen an Aktivität, Serverpräsenz und vorbildliches Verhalten. b) Nebenfraktionen: Nebenfraktionen sind kleinere, spezialisierte oder private Organisationen (z. B. das Department of Transportation, eingetragene Unternehmen oder Gangs/Maffien), die das Roleplay ergänzen. Sie besitzen keinen vergleichbaren behördlichen Einfluss wie Hauptfraktionen. Die finale Einstufung erfolgt ausschließlich durch das Fraktionsmanagement (FM). c) Legale und illegale Fraktionen: Legale Fraktionen agieren strikt im Rahmen der geltenden Gesetze und verfolgen behördliche, zivile oder wirtschaftliche Ziele.Illegale Fraktionen (z. B. Banden, Kartelle) sind auf kriminelles Roleplay ausgelegt und agieren dauerhaft außerhalb des Gesetzes. Legale Fraktionen agieren strikt im Rahmen der geltenden Gesetze und verfolgen behördliche, zivile oder wirtschaftliche Ziele. Illegale Fraktionen (z. B. Banden, Kartelle) sind auf kriminelles Roleplay ausgelegt und agieren dauerhaft außerhalb des Gesetzes. d) Fraktions-Discords & Kompetenzen: Die übergeordnete Verwaltung aller Fraktionen obliegt dem Fraktionsmanagement und dem Director. Für alle offiziellen Fraktions-Discord-Server gilt: Das FM muss jederzeit vollen Lese- und Kontrollzugriff (mindestens Audit-Log-Einsicht) besitzen. Dh das FM MUSS in alle channels reinschauen können zur Kontrolle.Fraktionsleitungen dürfen ihren Mitgliedern keine administrativen Rechte (z. B. "Server verwalten", "Rollen verwalten", "Administrator") auf den Fraktions-Discords geben, um Missbrauch vorzubeugen. Admin-Rechte liegen exklusiv beim FM/Serverleitung. Das FM muss jederzeit vollen Lese- und Kontrollzugriff (mindestens Audit-Log-Einsicht) besitzen. Dh das FM MUSS in alle channels reinschauen können zur Kontrolle. Fraktionsleitungen dürfen ihren Mitgliedern keine administrativen Rechte (z. B. "Server verwalten", "Rollen verwalten", "Administrator") auf den Fraktions-Discords geben, um Missbrauch vorzubeugen. Admin-Rechte liegen exklusiv beim FM/Serverleitung. §1.2 Verantwortlichkeiten Fraktionsleitung: Ist vollumfänglich für die interne Organisation, die Aktivitätskontrolle, das Fehlverhalten ihrer Mitglieder sowie die Durchsetzung des Regelwerks innerhalb der Fraktion verantwortlich. Fraktionsmanagement (FM): Überwacht die Fraktionslandschaft, agiert als neutrale Beschwerdestelle, greift bei Missständen ein und sorgt für ein faires Balancing im Gesamt-RP. Fraktionsmitglieder: Sind zur aktiven Teilnahme am Fraktions-RP sowie zur lückenlosen Einhaltung dieses Regelwerks verpflichtet. Fehlverhalten spiegelt sich immer auch auf die gesamte Fraktion wider.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-faction-2', 'faction-2', 'faction-2', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk/fraktionsregelwerk', 'Fraktionsregelwerk', '§2 – Verantwortungsstruktur & Moderation', 2, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-faction-2-v1', 'rule-faction-2', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§2.1 Eigenverantwortung der Fraktionen"}]},{"type":"paragraph","content":[{"type":"text","text":"Fraktionen genießen administrative Autonomie und organisieren sich intern selbstständig."}]},{"type":"paragraph","content":[{"type":"text","text":"Interne Richtlinien: Eigene Fraktionsordnungen und Dienstvorschriften sind erlaubt, dürfen jedoch niemals das übergeordnete Serverregelwerk aushebeln."}]},{"type":"paragraph","content":[{"type":"text","text":"Dienstweg: Konflikte oder Probleme sind zwingend zuerst intern über die Fraktionsleitung zu klären, bevor das Fraktionsmanagement (FM) eingeschaltet wird."}]},{"type":"paragraph","content":[{"type":"text","text":"Meldepflicht: Schwere Verstöße (z. B. Korruption ohne Absprache, Fail-RP im großen Stil, Beleidigungen) müssen von der Leitung sofort an das FM gemeldet werden."}]},{"type":"paragraph","content":[{"type":"text","text":"Discord- & Serverpflicht: Jedes Fraktionsmitglied muss sowohl auf dem Haupt-Discord des Servers als auch auf dem jeweiligen Fraktions-Discord registriert sein. Spieler ohne Discord-Präsenz dürfen nicht in der Fraktion verbleiben."}]},{"type":"paragraph","content":[{"type":"text","text":"§2.2 Aufgaben des Fraktionsmanagements (FM)"}]},{"type":"paragraph","content":[{"type":"text","text":"Das FM agiert als Aufsichtsbehörde und greift nach dem Prinzip „Sanktion als letztes Mittel“ ein."}]},{"type":"paragraph","content":[{"type":"text","text":"Aufgaben: Beratung der Leitungen, Überwachung der RP-Qualität und finale Schlichtung bei Konflikten zwischen verschiedenen Fraktionen."}]},{"type":"paragraph","content":[{"type":"text","text":"Sanktionsstufen bei Fehlverhalten:"},{"type":"text","text":"Mündliche/Schriftliche Verwarnung der Fraktion.Temporäre Einschränkung von Fraktionsrechten (z. B. Beschränkung von Mitgliederzahlen, Sperre für bestimmte RP-Aktionen).Administrative Entlassung einzelner Mitglieder/Leiter.Komplette Auflösung der Fraktion (Unfraktionierung)."}]},{"type":"paragraph","content":[{"type":"text","text":"Mündliche/Schriftliche Verwarnung der Fraktion."}]},{"type":"paragraph","content":[{"type":"text","text":"Temporäre Einschränkung von Fraktionsrechten (z. B. Beschränkung von Mitgliederzahlen, Sperre für bestimmte RP-Aktionen)."}]},{"type":"paragraph","content":[{"type":"text","text":"Administrative Entlassung einzelner Mitglieder/Leiter."}]},{"type":"paragraph","content":[{"type":"text","text":"Komplette Auflösung der Fraktion (Unfraktionierung)."}]},{"type":"paragraph","content":[{"type":"text","text":"§2.3 Fraktionsübergreifende Leitungsverbote"}]},{"type":"paragraph","content":[{"type":"text","text":"Eine Person darf maximal eine Fraktion oder Gang als Leitung (Leader/Co-Leader) führen."}]},{"type":"paragraph","content":[{"type":"text","text":"Interessenkonflikte: Um Metagaming und unfaire Machtkonzentrationen zu verhindern, ist es Mitgliedern der Chefetage (High-Command) einer Hauptfraktion (z.B. Polizei-Leitung) untersagt, zeitgleich eine tragende Rolle (z. B. Ranghöherer, Planer) in einer illegalen Fraktion einzunehmen."}]},{"type":"paragraph","content":[{"type":"text","text":"§2.4 Machtbalance"}]},{"type":"paragraph","content":[{"type":"text","text":"Das FM behält sich das Recht vor, Fraktionsentscheidungen (z. B. ungerechtfertigte Massenentlassungen, unfaire Bündnisse oder Kriege) zu annullieren, wenn sie das Balancing des Servers gefährden. Kein Bündnis und keine Fraktion darf das Server-RP dauerhaft diktieren oder monopolisieren."}]},{"type":"paragraph","content":[{"type":"text","text":"§2.5 Aktivitätslogs & Fristen"}]},{"type":"paragraph","content":[{"type":"text","text":"Jede Fraktion ist zur lückenlosen Führung eines Aktivitätslogs (nach Vorgabe des FM) verpflichtet."}]},{"type":"paragraph","content":[{"type":"text","text":"Abgabefrist: Wöchentlich bis Samstag um 20:00 Uhr. Nachreichungen werden nicht akzeptiert und als \"nicht abgegeben\" gewertet."}]},{"type":"paragraph","content":[{"type":"text","text":"Inaktivitäts-Strafen:"},{"type":"text","text":"1 Woche unentschuldigt inaktiv / kein Log: Schriftlicher Hinweis an die Leitung.2 Wochen unentschuldigt inaktiv / kein Log: Erteilung eines Fraktions-Strikes.3 Strikes: Bei Erreichen des dritten Strikes wird die Fraktion automatisch aufgelöst oder die Leitung komplett ausgetauscht."}]},{"type":"paragraph","content":[{"type":"text","text":"1 Woche unentschuldigt inaktiv / kein Log: Schriftlicher Hinweis an die Leitung."}]},{"type":"paragraph","content":[{"type":"text","text":"2 Wochen unentschuldigt inaktiv / kein Log: Erteilung eines Fraktions-Strikes."}]},{"type":"paragraph","content":[{"type":"text","text":"3 Strikes: Bei Erreichen des dritten Strikes wird die Fraktion automatisch aufgelöst oder die Leitung komplett ausgetauscht."}]}]}'::jsonb, '§2 – Verantwortungsstruktur & Moderation §2.1 Eigenverantwortung der Fraktionen Fraktionen genießen administrative Autonomie und organisieren sich intern selbstständig. Interne Richtlinien: Eigene Fraktionsordnungen und Dienstvorschriften sind erlaubt, dürfen jedoch niemals das übergeordnete Serverregelwerk aushebeln. Dienstweg: Konflikte oder Probleme sind zwingend zuerst intern über die Fraktionsleitung zu klären, bevor das Fraktionsmanagement (FM) eingeschaltet wird. Meldepflicht: Schwere Verstöße (z. B. Korruption ohne Absprache, Fail-RP im großen Stil, Beleidigungen) müssen von der Leitung sofort an das FM gemeldet werden. Discord- & Serverpflicht: Jedes Fraktionsmitglied muss sowohl auf dem Haupt-Discord des Servers als auch auf dem jeweiligen Fraktions-Discord registriert sein. Spieler ohne Discord-Präsenz dürfen nicht in der Fraktion verbleiben. §2.2 Aufgaben des Fraktionsmanagements (FM) Das FM agiert als Aufsichtsbehörde und greift nach dem Prinzip „Sanktion als letztes Mittel“ ein. Aufgaben: Beratung der Leitungen, Überwachung der RP-Qualität und finale Schlichtung bei Konflikten zwischen verschiedenen Fraktionen. Sanktionsstufen bei Fehlverhalten: Mündliche/Schriftliche Verwarnung der Fraktion.Temporäre Einschränkung von Fraktionsrechten (z. B. Beschränkung von Mitgliederzahlen, Sperre für bestimmte RP-Aktionen).Administrative Entlassung einzelner Mitglieder/Leiter.Komplette Auflösung der Fraktion (Unfraktionierung). Mündliche/Schriftliche Verwarnung der Fraktion. Temporäre Einschränkung von Fraktionsrechten (z. B. Beschränkung von Mitgliederzahlen, Sperre für bestimmte RP-Aktionen). Administrative Entlassung einzelner Mitglieder/Leiter. Komplette Auflösung der Fraktion (Unfraktionierung). §2.3 Fraktionsübergreifende Leitungsverbote Eine Person darf maximal eine Fraktion oder Gang als Leitung (Leader/Co-Leader) führen. Interessenkonflikte: Um Metagaming und unfaire Machtkonzentrationen zu verhindern, ist es Mitgliedern der Chefetage (High-Command) einer Hauptfraktion (z.B. Polizei-Leitung) untersagt, zeitgleich eine tragende Rolle (z. B. Ranghöherer, Planer) in einer illegalen Fraktion einzunehmen. §2.4 Machtbalance Das FM behält sich das Recht vor, Fraktionsentscheidungen (z. B. ungerechtfertigte Massenentlassungen, unfaire Bündnisse oder Kriege) zu annullieren, wenn sie das Balancing des Servers gefährden. Kein Bündnis und keine Fraktion darf das Server-RP dauerhaft diktieren oder monopolisieren. §2.5 Aktivitätslogs & Fristen Jede Fraktion ist zur lückenlosen Führung eines Aktivitätslogs (nach Vorgabe des FM) verpflichtet. Abgabefrist: Wöchentlich bis Samstag um 20:00 Uhr. Nachreichungen werden nicht akzeptiert und als "nicht abgegeben" gewertet. Inaktivitäts-Strafen: 1 Woche unentschuldigt inaktiv / kein Log: Schriftlicher Hinweis an die Leitung.2 Wochen unentschuldigt inaktiv / kein Log: Erteilung eines Fraktions-Strikes.3 Strikes: Bei Erreichen des dritten Strikes wird die Fraktion automatisch aufgelöst oder die Leitung komplett ausgetauscht. 1 Woche unentschuldigt inaktiv / kein Log: Schriftlicher Hinweis an die Leitung. 2 Wochen unentschuldigt inaktiv / kein Log: Erteilung eines Fraktions-Strikes. 3 Strikes: Bei Erreichen des dritten Strikes wird die Fraktion automatisch aufgelöst oder die Leitung komplett ausgetauscht.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-faction-3', 'faction-3', 'faction-3', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk/fraktionsregelwerk', 'Fraktionsregelwerk', '§3 – Organisation & Technische Sicherheit', 3, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-faction-3-v1', 'rule-faction-3', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§3.1 Discord-Sicherheit & Bot-Richtlinien"}]},{"type":"paragraph","content":[{"type":"text","text":"Um die Sicherheit der Community vor Raids, Datenklau oder schadhaften Verlinkungen zu schützen, gelten für alle Fraktions-Discords strenge Sicherheitsauflagen."}]},{"type":"paragraph","content":[{"type":"text","text":"Zugelassene Bots: Es dürfen ausschließlich weltweit bekannte, verifizierte und vom Fraktionsmanagement freigegebene Bots (z. B. Ticket-Bots, Musik-Bots) genutzt werden. Unverifizierte oder dubiose Public-Bots sind strengstens untersagt."}]},{"type":"paragraph","content":[{"type":"text","text":"Verbot von Fremd-Custom-Bots: Das Einladen von selbstprogrammierten Bots von Drittanbietern ist verboten. Ausgenommen sind lediglich offizielle Custom-Bots der Serverleitung."}]},{"type":"paragraph","content":[{"type":"text","text":"Verpflichtender Raid-Schutz: Jeder Fraktions-Discord muss zwingend über einen voll eingerichteten und aktiven Sicherheits-Bot (Standard: Wick-Bot) verfügen."}]},{"type":"paragraph","content":[{"type":"text","text":"Ablauf der Genehmigung: Eine Fraktion darf ihren Discord erst nach der offiziellen Zusage des FM erstellen. Nach der Erstellung hat die Leitung 24 Stunden Zeit, den Sicherheits-Bot (Wick) vollständig einzurichten und dem FM den Kontrollzugriff zu gewähren. Erst nach erfolgreicher technischer Abnahme durch das FM wird die Fraktion für den Spielbetrieb freigegeben."}]},{"type":"paragraph","content":[{"type":"text","text":"Rechte-Minimierung: Kein Bot (außer der verifizierte Sicherheits-Bot) darf über administrative Rechte (Administrator) verfügen."}]},{"type":"heading","attrs":{"level":1},"content":[{"type":"text","text":"Rechte und Pflichten der Fraktionsmitglieder"}]}]}'::jsonb, '§3 – Organisation & Technische Sicherheit §3.1 Discord-Sicherheit & Bot-Richtlinien Um die Sicherheit der Community vor Raids, Datenklau oder schadhaften Verlinkungen zu schützen, gelten für alle Fraktions-Discords strenge Sicherheitsauflagen. Zugelassene Bots: Es dürfen ausschließlich weltweit bekannte, verifizierte und vom Fraktionsmanagement freigegebene Bots (z. B. Ticket-Bots, Musik-Bots) genutzt werden. Unverifizierte oder dubiose Public-Bots sind strengstens untersagt. Verbot von Fremd-Custom-Bots: Das Einladen von selbstprogrammierten Bots von Drittanbietern ist verboten. Ausgenommen sind lediglich offizielle Custom-Bots der Serverleitung. Verpflichtender Raid-Schutz: Jeder Fraktions-Discord muss zwingend über einen voll eingerichteten und aktiven Sicherheits-Bot (Standard: Wick-Bot) verfügen. Ablauf der Genehmigung: Eine Fraktion darf ihren Discord erst nach der offiziellen Zusage des FM erstellen. Nach der Erstellung hat die Leitung 24 Stunden Zeit, den Sicherheits-Bot (Wick) vollständig einzurichten und dem FM den Kontrollzugriff zu gewähren. Erst nach erfolgreicher technischer Abnahme durch das FM wird die Fraktion für den Spielbetrieb freigegeben. Rechte-Minimierung: Kein Bot (außer der verifizierte Sicherheits-Bot) darf über administrative Rechte (Administrator) verfügen. Rechte und Pflichten der Fraktionsmitglieder', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-faction-4', 'faction-4', 'faction-4', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk/fraktionsregelwerk', 'Fraktionsregelwerk', '§4 – Rechte und Pflichten der Fraktionsmitglieder', 4, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-faction-4-v1', 'rule-faction-4', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Mitglieder einer Fraktion tragen Verantwortung, genießen aber auch Privilegien. Dieser Abschnitt regelt, was ihnen zusteht – und wofür sie im Gegenzug einstehen müssen. Nur durch ein Gleichgewicht zwischen Rechten und Pflichten kann ein fairer und lebendiger Fraktionsalltag entstehen."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"§4.1"},{"type":"text","text":"–"},{"type":"text","text":"Rechte der Mitglieder"}]},{"type":"paragraph","content":[{"type":"text","text":"Teilnahme am Rollenspiel: Jedes Mitglied hat das grundsätzliche Recht, aktiv am RP teilzunehmen. Dabei sollen alle die Möglichkeit haben, sich mit eigenen Ideen und Charakterzügen in die Fraktion einzubringen. Kreativität und Engagement sind ausdrücklich erwünscht."}]},{"type":"paragraph","content":[{"type":"text","text":"Zugriff auf Ressourcen: Mitglieder erhalten Zugang zu den für die Fraktion vorgesehenen Ressourcen – darunter Fahrzeuge, Ausrüstung und ggf. spezielle Discord-Channels oder Tools. Der Umfang dieses Zugriffs orientiert sich dabei an der jeweiligen Rolle und dem Rang innerhalb der Fraktion."}]},{"type":"paragraph","content":[{"type":"text","text":"Mitspracherecht: Die Meinung jedes Mitglieds zählt. Je nach Hierarchiestufe besteht ein Mitspracherecht bei fraktionsinternen Entscheidungen – ob bei der Planung von Einsätzen, internen Umstrukturierungen oder Regelanpassungen. In Hauptfraktionen sowie auf Bundesebene gilt außerdem: Auch bei Nebenfraktionen kann in bestimmten Fällen ein Mitspracherecht bestehen, sofern dies die Struktur oder das Zusammenspiel im RP betrifft."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"§4.2"},{"type":"text","text":"–"},{"type":"text","text":"Pflichten der Mitglieder"}]},{"type":"paragraph","content":[{"type":"text","text":"Einhaltung aller Regeln: Jedes Mitglied ist verpflichtet, sich an die geltenden Fraktionsregeln sowie an die allgemeinen Serverregeln zu halten. Das umfasst sowohl RP-relevante Inhalte als auch den respektvollen Umgang miteinander – auf dem Server und im Discord. Für dem Team auch das Team Regelwerk."}]},{"type":"paragraph","content":[{"type":"text","text":"Teilnahme an Schulungen: Für Mitglieder der Hauptfraktionen besteht die Pflicht, regelmäßig an Schulungen teilzunehmen. Diese fördern nicht nur die RP-Qualität, sondern sind auch Voraussetzung für Beförderungen oder Spezialisierungen innerhalb der Fraktion."}]},{"type":"paragraph","content":[{"type":"text","text":"Loyalität gegenüber der Fraktion: Mitglieder sollten sich mit ihrer Fraktion identifizieren und deren Werte vertreten. Ein fairer, engagierter und verantwortungsvoller Umgang mit den Aufgaben und Mitspielern stärkt nicht nur das Miteinander, sondern auch das Ansehen der Fraktion im Servergeschehen."}]},{"type":"paragraph","content":[{"type":"text","text":"Respektvolles Verhalten: Egal ob im RP oder im OOC-Bereich – ein höflicher und respektvoller Umgang ist Pflicht. Beleidigungen, Diskriminierung oder toxisches Verhalten haben in einer funktionierenden Fraktion keinen Platz. Auch bei Konflikten ist der ruhige Dialog stets der erste Weg."}]},{"type":"paragraph","content":[{"type":"text","text":"Neutralität medizinischer Fraktionen: Fraktionen wie das DRK oder andere medizinische Dienste haben eine besondere Verantwortung: Sie müssen im RP neutral agieren und dürfen sich nicht in politische oder kriminelle Strukturen einmischen. Bevorzugung einzelner Fraktionen ist untersagt – medizinische Hilfe gilt allen gleichermaßen."}]},{"type":"paragraph","content":[{"type":"text","text":"Teilnahme am Roleplay"}]},{"type":"paragraph","content":[{"type":"text","text":"Fraktionsbesitzer sowie sämtliche Mitglieder einer Fraktion sind verpflichtet, aktiv am Roleplay teilzunehmen und regelmäßig ingame Aktivität zu zeigen."}]},{"type":"paragraph","content":[{"type":"text","text":"Eine Fraktion soll das Server-RP aktiv bereichern und darf nicht lediglich auf dem Papier existieren. Dazu gehört insbesondere die Teilnahme an Einsätzen, Situationen, internen Abläufen sowie allgemeinen RP-Handlungen im Alltag des Servers."}]},{"type":"paragraph","content":[{"type":"text","text":"Dauerhafte Inaktivität, fehlende Beteiligung am Roleplay oder das bloße Besitzen einer Fraktion ohne erkennbare Aktivität widersprechen dem Zweck einer Fraktion und können durch das Fraktionsmanagement überprüft sowie entsprechend sanktioniert werden."}]},{"type":"heading","attrs":{"level":1},"content":[{"type":"text","text":"Deaktivierung einer Fraktion durch RP geschehnisse"}]}]}'::jsonb, '§4 – Rechte und Pflichten der Fraktionsmitglieder Mitglieder einer Fraktion tragen Verantwortung, genießen aber auch Privilegien. Dieser Abschnitt regelt, was ihnen zusteht – und wofür sie im Gegenzug einstehen müssen. Nur durch ein Gleichgewicht zwischen Rechten und Pflichten kann ein fairer und lebendiger Fraktionsalltag entstehen. §4.1 – Rechte der Mitglieder Teilnahme am Rollenspiel: Jedes Mitglied hat das grundsätzliche Recht, aktiv am RP teilzunehmen. Dabei sollen alle die Möglichkeit haben, sich mit eigenen Ideen und Charakterzügen in die Fraktion einzubringen. Kreativität und Engagement sind ausdrücklich erwünscht. Zugriff auf Ressourcen: Mitglieder erhalten Zugang zu den für die Fraktion vorgesehenen Ressourcen – darunter Fahrzeuge, Ausrüstung und ggf. spezielle Discord-Channels oder Tools. Der Umfang dieses Zugriffs orientiert sich dabei an der jeweiligen Rolle und dem Rang innerhalb der Fraktion. Mitspracherecht: Die Meinung jedes Mitglieds zählt. Je nach Hierarchiestufe besteht ein Mitspracherecht bei fraktionsinternen Entscheidungen – ob bei der Planung von Einsätzen, internen Umstrukturierungen oder Regelanpassungen. In Hauptfraktionen sowie auf Bundesebene gilt außerdem: Auch bei Nebenfraktionen kann in bestimmten Fällen ein Mitspracherecht bestehen, sofern dies die Struktur oder das Zusammenspiel im RP betrifft. §4.2 – Pflichten der Mitglieder Einhaltung aller Regeln: Jedes Mitglied ist verpflichtet, sich an die geltenden Fraktionsregeln sowie an die allgemeinen Serverregeln zu halten. Das umfasst sowohl RP-relevante Inhalte als auch den respektvollen Umgang miteinander – auf dem Server und im Discord. Für dem Team auch das Team Regelwerk. Teilnahme an Schulungen: Für Mitglieder der Hauptfraktionen besteht die Pflicht, regelmäßig an Schulungen teilzunehmen. Diese fördern nicht nur die RP-Qualität, sondern sind auch Voraussetzung für Beförderungen oder Spezialisierungen innerhalb der Fraktion. Loyalität gegenüber der Fraktion: Mitglieder sollten sich mit ihrer Fraktion identifizieren und deren Werte vertreten. Ein fairer, engagierter und verantwortungsvoller Umgang mit den Aufgaben und Mitspielern stärkt nicht nur das Miteinander, sondern auch das Ansehen der Fraktion im Servergeschehen. Respektvolles Verhalten: Egal ob im RP oder im OOC-Bereich – ein höflicher und respektvoller Umgang ist Pflicht. Beleidigungen, Diskriminierung oder toxisches Verhalten haben in einer funktionierenden Fraktion keinen Platz. Auch bei Konflikten ist der ruhige Dialog stets der erste Weg. Neutralität medizinischer Fraktionen: Fraktionen wie das DRK oder andere medizinische Dienste haben eine besondere Verantwortung: Sie müssen im RP neutral agieren und dürfen sich nicht in politische oder kriminelle Strukturen einmischen. Bevorzugung einzelner Fraktionen ist untersagt – medizinische Hilfe gilt allen gleichermaßen. Teilnahme am Roleplay Fraktionsbesitzer sowie sämtliche Mitglieder einer Fraktion sind verpflichtet, aktiv am Roleplay teilzunehmen und regelmäßig ingame Aktivität zu zeigen. Eine Fraktion soll das Server-RP aktiv bereichern und darf nicht lediglich auf dem Papier existieren. Dazu gehört insbesondere die Teilnahme an Einsätzen, Situationen, internen Abläufen sowie allgemeinen RP-Handlungen im Alltag des Servers. Dauerhafte Inaktivität, fehlende Beteiligung am Roleplay oder das bloße Besitzen einer Fraktion ohne erkennbare Aktivität widersprechen dem Zweck einer Fraktion und können durch das Fraktionsmanagement überprüft sowie entsprechend sanktioniert werden. Deaktivierung einer Fraktion durch RP geschehnisse', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-faction-6', 'faction-6', 'faction-6', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk/fraktionsregelwerk', 'Fraktionsregelwerk', '§6 – Vorübergehende Deaktivierung von Fraktionen', 5, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-faction-6-v1', 'rule-faction-6', 'PUBLISHED', '{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"§6.1 Voraussetzungen"}]},{"type":"paragraph","content":[{"type":"text","text":"Eine Fraktion kann durch das Fraktionsmanagement vorübergehend deaktiviert oder eingeschränkt werden, wenn schwerwiegende RP-Ereignisse die Handlungsfähigkeit der Fraktion erheblich beeinträchtigen."}]},{"type":"paragraph","content":[{"type":"text","text":"Dies ist insbesondere der Fall, wenn:"}]},{"type":"paragraph","content":[{"type":"text","text":"ein erheblicher Teil der Fraktionsmitglieder im Rahmen eines nachvollziehbaren RP-Verfahrens festgenommen wurde"}]},{"type":"paragraph","content":[{"type":"text","text":"die Fraktionsleitung oder mehrere Führungspersonen dauerhaft handlungsunfähig sind"}]},{"type":"paragraph","content":[{"type":"text","text":"die Fraktion ihre organisatorischen Aufgaben nicht mehr erfüllen kann"}]},{"type":"paragraph","content":[{"type":"text","text":"umstrukturierung einer Fraktion / Gang erforderlich ist."}]},{"type":"paragraph","content":[{"type":"text","text":"Die Entscheidung über eine Deaktivierung erfolgt ausschließlich durch das Fraktionsmanagement."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"§6.2 Konsequenzen"}]},{"type":"paragraph","content":[{"type":"text","text":"Während einer Deaktivierung oder Einschränkung kann das Fraktionsmanagement:"}]},{"type":"paragraph","content":[{"type":"text","text":"Fraktionsaktivitäten untersagen"}]},{"type":"paragraph","content":[{"type":"text","text":"Fahrzeuge oder Ressourcen sperren"}]},{"type":"paragraph","content":[{"type":"text","text":"Rechte temporär einschränken"}]},{"type":"paragraph","content":[{"type":"text","text":"organisatorische Maßnahmen anordnen"}]},{"type":"paragraph","content":[{"type":"text","text":"Die Maßnahmen richten sich nach der Schwere des Vorfalls."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"§6.3 Dauer"}]},{"type":"paragraph","content":[{"type":"text","text":"Die Dauer einer Deaktivierung wird individuell durch das Fraktionsmanagement festgelegt."}]},{"type":"paragraph","content":[{"type":"text","text":"Dabei werden insbesondere berücksichtigt:"}]},{"type":"paragraph","content":[{"type":"text","text":"Schwere der Situation"}]},{"type":"paragraph","content":[{"type":"text","text":"verbleibende Handlungsfähigkeit"}]},{"type":"paragraph","content":[{"type":"text","text":"Verhalten der Fraktion"}]},{"type":"paragraph","content":[{"type":"text","text":"Auswirkungen auf das Server-RP"}]},{"type":"paragraph","content":[{"type":"text","text":"Nach Ablauf erfolgt eine erneute Überprüfung."}]},{"type":"heading","attrs":{"level":1},"content":[{"type":"text","text":"Fraktionsgebiete"}]}]}'::jsonb, '§6 – Vorübergehende Deaktivierung von Fraktionen §6.1 Voraussetzungen Eine Fraktion kann durch das Fraktionsmanagement vorübergehend deaktiviert oder eingeschränkt werden, wenn schwerwiegende RP-Ereignisse die Handlungsfähigkeit der Fraktion erheblich beeinträchtigen. Dies ist insbesondere der Fall, wenn: ein erheblicher Teil der Fraktionsmitglieder im Rahmen eines nachvollziehbaren RP-Verfahrens festgenommen wurde die Fraktionsleitung oder mehrere Führungspersonen dauerhaft handlungsunfähig sind die Fraktion ihre organisatorischen Aufgaben nicht mehr erfüllen kann umstrukturierung einer Fraktion / Gang erforderlich ist. Die Entscheidung über eine Deaktivierung erfolgt ausschließlich durch das Fraktionsmanagement. §6.2 Konsequenzen Während einer Deaktivierung oder Einschränkung kann das Fraktionsmanagement: Fraktionsaktivitäten untersagen Fahrzeuge oder Ressourcen sperren Rechte temporär einschränken organisatorische Maßnahmen anordnen Die Maßnahmen richten sich nach der Schwere des Vorfalls. §6.3 Dauer Die Dauer einer Deaktivierung wird individuell durch das Fraktionsmanagement festgelegt. Dabei werden insbesondere berücksichtigt: Schwere der Situation verbleibende Handlungsfähigkeit Verhalten der Fraktion Auswirkungen auf das Server-RP Nach Ablauf erfolgt eine erneute Überprüfung. Fraktionsgebiete', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-faction-7', 'faction-7', 'faction-7', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk/fraktionsregelwerk', 'Fraktionsregelwerk', '§7.1 Definition', 6, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-faction-7-v1', 'rule-faction-7', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Ausgeschlossene Gebiete sind staatliche Dienststellen und öffentliche Einrichtungen, die aufgrund ihrer zentralen Bedeutung für das Rollenspiel von jeglichen Gebietsansprüchen oder dauerhaften Belagerungen durch kriminelle Fraktionen ausgenommen sind."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"§7.2 Betroffene Einrichtungen"}]},{"type":"paragraph","content":[{"type":"text","text":"Folgende Dienststellen sind von Fraktionsansprüchen ausgeschlossen:"}]},{"type":"paragraph","content":[{"type":"text","text":"DOT (Department of Transportation)"}]},{"type":"paragraph","content":[{"type":"text","text":"FD Station 1 & 2 (Feuerwachen)"}]},{"type":"paragraph","content":[{"type":"text","text":"POL Wache (Police Department)"}]},{"type":"paragraph","content":[{"type":"text","text":"Ziviler Spawn"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"§7.3 Nutzungsbestimmungen"}]},{"type":"paragraph","content":[{"type":"text","text":"a) Zweckgebundene Nutzung: Die Einrichtungen stehen den jeweils dort ansässigen staatlichen Fraktionen (z.B. POL, FD, DOT) für ihren regulären Dienstbetrieb zur Verfügung."}]},{"type":"paragraph","content":[{"type":"text","text":"b) Neutralität & Schutzzone: Diese Gebiete gelten als neutrale Safezones vor Fraktionskriegen. Sie dürfen von illegalen Fraktionen weder besetzt, als „eigenes Territorium“ deklariert, noch für Fraktionsaktivitäten (z. B. Geiselnahmen, Razzien ohne RP-Hintergrund) missbraucht werden."}]},{"type":"paragraph","content":[{"type":"text","text":"c) Fraktions- und Ganggebiete dürfen nicht durch Zäune, Barrikaden, Bauwerke oder andere Objekte dauerhaft abgesperrt, verbaut oder befestigt werden. Ebenso ist es untersagt, durch bauliche Maßnahmen oder die Gestaltung des Gebiets einen unfairen spielerischen Vorteil gegenüber anderen Spielern oder Fraktionen zu erlangen."}]},{"type":"heading","attrs":{"level":1},"content":[{"type":"text","text":"Unterfraktionen"}]}]}'::jsonb, '§7.1 Definition Ausgeschlossene Gebiete sind staatliche Dienststellen und öffentliche Einrichtungen, die aufgrund ihrer zentralen Bedeutung für das Rollenspiel von jeglichen Gebietsansprüchen oder dauerhaften Belagerungen durch kriminelle Fraktionen ausgenommen sind. §7.2 Betroffene Einrichtungen Folgende Dienststellen sind von Fraktionsansprüchen ausgeschlossen: DOT (Department of Transportation) FD Station 1 & 2 (Feuerwachen) POL Wache (Police Department) Ziviler Spawn §7.3 Nutzungsbestimmungen a) Zweckgebundene Nutzung: Die Einrichtungen stehen den jeweils dort ansässigen staatlichen Fraktionen (z.B. POL, FD, DOT) für ihren regulären Dienstbetrieb zur Verfügung. b) Neutralität & Schutzzone: Diese Gebiete gelten als neutrale Safezones vor Fraktionskriegen. Sie dürfen von illegalen Fraktionen weder besetzt, als „eigenes Territorium“ deklariert, noch für Fraktionsaktivitäten (z. B. Geiselnahmen, Razzien ohne RP-Hintergrund) missbraucht werden. c) Fraktions- und Ganggebiete dürfen nicht durch Zäune, Barrikaden, Bauwerke oder andere Objekte dauerhaft abgesperrt, verbaut oder befestigt werden. Ebenso ist es untersagt, durch bauliche Maßnahmen oder die Gestaltung des Gebiets einen unfairen spielerischen Vorteil gegenüber anderen Spielern oder Fraktionen zu erlangen. Unterfraktionen', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-faction-8', 'faction-8', 'faction-8', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk/fraktionsregelwerk', 'Fraktionsregelwerk', '§8 Unterfraktionen', 7, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-faction-8-v1', 'rule-faction-8', 'PUBLISHED', '{"type":"doc","content":[{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"§8.1 Definition"}]},{"type":"paragraph","content":[{"type":"text","text":"Unterfraktionen sind spezialisierte Einheiten innerhalb einer Haupt- oder Nebenfraktion. Sie haben spezifische Aufgaben, die zum Gesamtbild der übergeordneten Fraktion beitragen. Sie genießen eine gewisse Autonomie, sind aber an die Regeln und Ziele der übergeordneten Fraktion gebunden."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"§8.2 Vorgaben"}]},{"type":"paragraph","content":[{"type":"text","text":"a)"},{"type":"text","text":"Zugehörigkeit:"},{"type":"text","text":"Unterfraktionen gehören zur übergeordneten Fraktion. Sie können auf deren Discord-Server organisiert sein oder einen eigenen Server betreiben."}]},{"type":"paragraph","content":[{"type":"text","text":"b)"},{"type":"text","text":"Autonomie und Abhängigkeit:"},{"type":"text","text":"Unterfraktionen dürfen ihre internen Abläufe eigenständig gestalten, sind jedoch an die Richtlinien der übergeordneten Fraktion sowie an das Fraktionsregelwerk gebunden."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"§8.3 Gründung, Ablehnung und Auflösung"}]},{"type":"paragraph","content":[{"type":"text","text":"a)"},{"type":"text","text":"Antragspflicht:"},{"type":"text","text":"Für jede Unterfraktion besteht eine Antragspflicht beim Fraktionsmanagement. Ohne vorherige Genehmigung durch das FM darf keine Unterfraktion errichtet oder betrieben werden."}]},{"type":"paragraph","content":[{"type":"text","text":"b)"},{"type":"text","text":"Entscheidungskompetenz:"},{"type":"text","text":"Das FM entscheidet über die Gründung, Ablehnung und Auflösung von Unterfraktionen. Die übergeordnete Fraktion wird im Verfahren angehört."}]},{"type":"paragraph","content":[{"type":"text","text":"c)"},{"type":"text","text":"Auflösungsgründe:"},{"type":"text","text":"Eine Unterfraktion kann insbesondere aufgelöst werden, wenn sie ihre Aufgaben nicht erfüllt, gegen Regeln verstößt oder keinen erkennbaren Mehrwert für das RP bietet. Die übergeordnete Fraktion kann eine Auflösung beim FM beantragen."}]},{"type":"paragraph","content":[{"type":"text","text":"d)"},{"type":"text","text":"Anzahl:"},{"type":"text","text":"Die Anzahl der zulässigen Unterfraktionen einer Fraktion liegt im Ermessen des FMs."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"§8.4 Sanktionen"}]},{"type":"paragraph","content":[{"type":"text","text":"a)"},{"type":"text","text":"Primäre Sanktionen:"},{"type":"text","text":"Bei Regelverstößen durch Mitglieder einer Unterfraktion wird die Unterfraktion direkt sanktioniert. In schwerwiegenden Fällen kann die übergeordnete Fraktion zur Verantwortung gezogen werden."}]},{"type":"paragraph","content":[{"type":"text","text":"b)"},{"type":"text","text":"Sekundäre Sanktionen:"},{"type":"text","text":"Unterfraktionen sind für das Verhalten ihrer Mitglieder verantwortlich und können bei schweren Verstößen sanktioniert werden (z.B. Ressourcenbeschränkung, Privilegienverlust, Auflösung)."}]},{"type":"heading","attrs":{"level":1},"content":[{"type":"text","text":"Auflösung und Neugründung von Fraktionen"}]}]}'::jsonb, '§8 Unterfraktionen §8.1 Definition Unterfraktionen sind spezialisierte Einheiten innerhalb einer Haupt- oder Nebenfraktion. Sie haben spezifische Aufgaben, die zum Gesamtbild der übergeordneten Fraktion beitragen. Sie genießen eine gewisse Autonomie, sind aber an die Regeln und Ziele der übergeordneten Fraktion gebunden. §8.2 Vorgaben a) Zugehörigkeit: Unterfraktionen gehören zur übergeordneten Fraktion. Sie können auf deren Discord-Server organisiert sein oder einen eigenen Server betreiben. b) Autonomie und Abhängigkeit: Unterfraktionen dürfen ihre internen Abläufe eigenständig gestalten, sind jedoch an die Richtlinien der übergeordneten Fraktion sowie an das Fraktionsregelwerk gebunden. §8.3 Gründung, Ablehnung und Auflösung a) Antragspflicht: Für jede Unterfraktion besteht eine Antragspflicht beim Fraktionsmanagement. Ohne vorherige Genehmigung durch das FM darf keine Unterfraktion errichtet oder betrieben werden. b) Entscheidungskompetenz: Das FM entscheidet über die Gründung, Ablehnung und Auflösung von Unterfraktionen. Die übergeordnete Fraktion wird im Verfahren angehört. c) Auflösungsgründe: Eine Unterfraktion kann insbesondere aufgelöst werden, wenn sie ihre Aufgaben nicht erfüllt, gegen Regeln verstößt oder keinen erkennbaren Mehrwert für das RP bietet. Die übergeordnete Fraktion kann eine Auflösung beim FM beantragen. d) Anzahl: Die Anzahl der zulässigen Unterfraktionen einer Fraktion liegt im Ermessen des FMs. §8.4 Sanktionen a) Primäre Sanktionen: Bei Regelverstößen durch Mitglieder einer Unterfraktion wird die Unterfraktion direkt sanktioniert. In schwerwiegenden Fällen kann die übergeordnete Fraktion zur Verantwortung gezogen werden. b) Sekundäre Sanktionen: Unterfraktionen sind für das Verhalten ihrer Mitglieder verantwortlich und können bei schweren Verstößen sanktioniert werden (z.B. Ressourcenbeschränkung, Privilegienverlust, Auflösung). Auflösung und Neugründung von Fraktionen', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-faction-9', 'faction-9', 'faction-9', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk/fraktionsregelwerk', 'Fraktionsregelwerk', '§9 – Auflösung und Neugründung von Fraktionen', 8, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-faction-9-v1', 'rule-faction-9', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§9.1 Gründe für eine Auflösung"}]},{"type":"paragraph","content":[{"type":"text","text":"a) Inaktivität: Eine Fraktion gilt als inaktiv, wenn sie über einen Zeitraum von 14 Tagen keinerlei messbare Aktivität im Roleplay zeigt und die Fraktionsleitung unentschuldigt nicht erreichbar ist."},{"type":"text","text":"Ausnahme: Nachvollziehbare Reallife-Gründe (z. B. Urlaub, Krankheit, Klausurenphasen) müssen dem FM vorab gemeldet werden.Sonderregelung: Für rein zivile Fraktionen (z. B. Shops, Werkstätten, Restaurants) gilt eine verlängerte Inaktivitätsfrist von 30 Tagen."}]},{"type":"paragraph","content":[{"type":"text","text":"Ausnahme: Nachvollziehbare Reallife-Gründe (z. B. Urlaub, Krankheit, Klausurenphasen) müssen dem FM vorab gemeldet werden."}]},{"type":"paragraph","content":[{"type":"text","text":"Sonderregelung: Für rein zivile Fraktionen (z. B. Shops, Werkstätten, Restaurants) gilt eine verlängerte Inaktivitätsfrist von 30 Tagen."}]},{"type":"paragraph","content":[{"type":"text","text":"b) Regelwidriges Verhalten: Wiederholte oder schwere Verstöße gegen das Server- oder Fraktionsregelwerk, die das RP anderer Spieler massiv schädigen, den Serverbetrieb gefährden oder das Image des Servers belasten, können zur administrativen Auflösung führen."}]},{"type":"paragraph","content":[{"type":"text","text":"§9.2 Verfahren zur Auflösung (Ablauf)"}]},{"type":"paragraph","content":[{"type":"text","text":"(Hinweis: Automatische Inaktivitäts-Strikes nach §2.5 sind von diesem bürokratischen Ablauf ausgenommen)."}]},{"type":"paragraph","content":[{"type":"text","text":"a) Verwarnung / Abmahnung: Bei verhaltensbedingten Problemen erhält die Fraktionsleitung zunächst eine offizielle schriftliche Abmahnung durch das FM. Diese listet die Missstände und die geforderten Änderungen auf."}]},{"type":"paragraph","content":[{"type":"text","text":"b) Schriftliches Einspruchsrecht & Gehör: Um administrative Prozesse sachlich zu halten und das Team vor Beeinflussung zu schützen, gilt folgendes Verfahren:"},{"type":"text","text":"Reine Schriftform: Eine Stellungnahme der Fraktionsleitung ist ausschließlich schriftlich über das Ticket-System einzureichen.Keine spontanen Support-Talks: Mündliche Anhörungen im Voice-Chat finden zu laufenden Verfahren nicht spontan statt. Ein Gespräch wird nur geführt, wenn das FM dies ausdrücklich für notwendig erachtet.Terminbindung: Sollte ein Gespräch angesetzt werden, wird dieses im Ticket fest terminiert. Spontane Diskussionen oder das Abfangen von Teammitgliedern im Support sind untersagt."}]},{"type":"paragraph","content":[{"type":"text","text":"Reine Schriftform: Eine Stellungnahme der Fraktionsleitung ist ausschließlich schriftlich über das Ticket-System einzureichen."}]},{"type":"paragraph","content":[{"type":"text","text":"Keine spontanen Support-Talks: Mündliche Anhörungen im Voice-Chat finden zu laufenden Verfahren nicht spontan statt. Ein Gespräch wird nur geführt, wenn das FM dies ausdrücklich für notwendig erachtet."}]},{"type":"paragraph","content":[{"type":"text","text":"Terminbindung: Sollte ein Gespräch angesetzt werden, wird dieses im Ticket fest terminiert. Spontane Diskussionen oder das Abfangen von Teammitgliedern im Support sind untersagt."}]},{"type":"paragraph","content":[{"type":"text","text":"c) Entscheidung und Umsetzung: Das Server-Team trifft die finale Entscheidung auf Basis der Fakten und der schriftlichen Stellungnahme. Wird die Auflösung vollzogen, werden alle Discord-Kanäle archiviert/gelöscht, Rollen entzogen und die Fraktion in-game aufgelöst."}]},{"type":"paragraph","content":[{"type":"text","text":"§9.3 Neugründung von Fraktionen"}]},{"type":"paragraph","content":[{"type":"text","text":"a) Sperrfrist nach Auflösung: Wurde eine Fraktion wegen schweren Fehlverhaltens oder Toxizität aufgelöst, gilt für die beteiligte Leitung und die Kernmitglieder eine Sperrfrist von mindestens 30 Tagen, bevor sie einen neuen Fraktionsantrag einreichen dürfen."}]},{"type":"paragraph","content":[{"type":"text","text":"b) Verpflichtung zur Regelkonformität: Bei einer Neugründung muss sich die Gruppierung schriftlich im Antrag zur strikten Einhaltung aller Regeln bekennen. Alte Verhaltensmuster dürfen nicht wiederholt werden."}]},{"type":"paragraph","content":[{"type":"text","text":"c) Anforderungen an den Antrag: Der schriftliche Antrag ans FM muss enthalten:"},{"type":"text","text":"Ausgearbeitetes Konzept, Ziele und interne Struktur.Mehrwert/Nutzen für das gesamte Server-RP.Konzepte zur internen Konfliktlösung und Aktivitätsförderung."}]},{"type":"paragraph","content":[{"type":"text","text":"Ausgearbeitetes Konzept, Ziele und interne Struktur."}]},{"type":"paragraph","content":[{"type":"text","text":"Mehrwert/Nutzen für das gesamte Server-RP."}]},{"type":"paragraph","content":[{"type":"text","text":"Konzepte zur internen Konfliktlösung und Aktivitätsförderung."}]},{"type":"paragraph","content":[{"type":"text","text":"d) Genehmigung: Das FM prüft das Konzept sowie die administrative Vorgeschichte (Warns/Bans) der Antragsteller. Es besteht kein Anspruch auf die Genehmigung einer Fraktion."}]},{"type":"heading","attrs":{"level":1},"content":[{"type":"text","text":"Verfahren zur Gründung"}]}]}'::jsonb, '§9 – Auflösung und Neugründung von Fraktionen §9.1 Gründe für eine Auflösung a) Inaktivität: Eine Fraktion gilt als inaktiv, wenn sie über einen Zeitraum von 14 Tagen keinerlei messbare Aktivität im Roleplay zeigt und die Fraktionsleitung unentschuldigt nicht erreichbar ist. Ausnahme: Nachvollziehbare Reallife-Gründe (z. B. Urlaub, Krankheit, Klausurenphasen) müssen dem FM vorab gemeldet werden.Sonderregelung: Für rein zivile Fraktionen (z. B. Shops, Werkstätten, Restaurants) gilt eine verlängerte Inaktivitätsfrist von 30 Tagen. Ausnahme: Nachvollziehbare Reallife-Gründe (z. B. Urlaub, Krankheit, Klausurenphasen) müssen dem FM vorab gemeldet werden. Sonderregelung: Für rein zivile Fraktionen (z. B. Shops, Werkstätten, Restaurants) gilt eine verlängerte Inaktivitätsfrist von 30 Tagen. b) Regelwidriges Verhalten: Wiederholte oder schwere Verstöße gegen das Server- oder Fraktionsregelwerk, die das RP anderer Spieler massiv schädigen, den Serverbetrieb gefährden oder das Image des Servers belasten, können zur administrativen Auflösung führen. §9.2 Verfahren zur Auflösung (Ablauf) (Hinweis: Automatische Inaktivitäts-Strikes nach §2.5 sind von diesem bürokratischen Ablauf ausgenommen). a) Verwarnung / Abmahnung: Bei verhaltensbedingten Problemen erhält die Fraktionsleitung zunächst eine offizielle schriftliche Abmahnung durch das FM. Diese listet die Missstände und die geforderten Änderungen auf. b) Schriftliches Einspruchsrecht & Gehör: Um administrative Prozesse sachlich zu halten und das Team vor Beeinflussung zu schützen, gilt folgendes Verfahren: Reine Schriftform: Eine Stellungnahme der Fraktionsleitung ist ausschließlich schriftlich über das Ticket-System einzureichen.Keine spontanen Support-Talks: Mündliche Anhörungen im Voice-Chat finden zu laufenden Verfahren nicht spontan statt. Ein Gespräch wird nur geführt, wenn das FM dies ausdrücklich für notwendig erachtet.Terminbindung: Sollte ein Gespräch angesetzt werden, wird dieses im Ticket fest terminiert. Spontane Diskussionen oder das Abfangen von Teammitgliedern im Support sind untersagt. Reine Schriftform: Eine Stellungnahme der Fraktionsleitung ist ausschließlich schriftlich über das Ticket-System einzureichen. Keine spontanen Support-Talks: Mündliche Anhörungen im Voice-Chat finden zu laufenden Verfahren nicht spontan statt. Ein Gespräch wird nur geführt, wenn das FM dies ausdrücklich für notwendig erachtet. Terminbindung: Sollte ein Gespräch angesetzt werden, wird dieses im Ticket fest terminiert. Spontane Diskussionen oder das Abfangen von Teammitgliedern im Support sind untersagt. c) Entscheidung und Umsetzung: Das Server-Team trifft die finale Entscheidung auf Basis der Fakten und der schriftlichen Stellungnahme. Wird die Auflösung vollzogen, werden alle Discord-Kanäle archiviert/gelöscht, Rollen entzogen und die Fraktion in-game aufgelöst. §9.3 Neugründung von Fraktionen a) Sperrfrist nach Auflösung: Wurde eine Fraktion wegen schweren Fehlverhaltens oder Toxizität aufgelöst, gilt für die beteiligte Leitung und die Kernmitglieder eine Sperrfrist von mindestens 30 Tagen, bevor sie einen neuen Fraktionsantrag einreichen dürfen. b) Verpflichtung zur Regelkonformität: Bei einer Neugründung muss sich die Gruppierung schriftlich im Antrag zur strikten Einhaltung aller Regeln bekennen. Alte Verhaltensmuster dürfen nicht wiederholt werden. c) Anforderungen an den Antrag: Der schriftliche Antrag ans FM muss enthalten: Ausgearbeitetes Konzept, Ziele und interne Struktur.Mehrwert/Nutzen für das gesamte Server-RP.Konzepte zur internen Konfliktlösung und Aktivitätsförderung. Ausgearbeitetes Konzept, Ziele und interne Struktur. Mehrwert/Nutzen für das gesamte Server-RP. Konzepte zur internen Konfliktlösung und Aktivitätsförderung. d) Genehmigung: Das FM prüft das Konzept sowie die administrative Vorgeschichte (Warns/Bans) der Antragsteller. Es besteht kein Anspruch auf die Genehmigung einer Fraktion. Verfahren zur Gründung', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-faction-10', 'faction-10', 'faction-10', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk/fraktionsregelwerk', 'Fraktionsregelwerk', '§10 – Gründung und Testphase neuer Fraktionen', 9, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-faction-10-v1', 'rule-faction-10', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Antragstellung:"},{"type":"text","text":"Fraktionen können ausschließlich über ein Fraktions-Ticket beim Fraktionsmanagement beantragt werden."}]},{"type":"paragraph","content":[{"type":"text","text":"Gründungsberechtigung:"},{"type":"text","text":"Die Eröffnung und Einrichtung von Fraktionen erfolgt ausschließlich durch das Fraktionsmanagement. Eine eigenständige Gründung durch Spieler ist nicht gestattet."}]},{"type":"paragraph","content":[{"type":"text","text":"Verfahren:"},{"type":"text","text":"Nach Einreichung des Antrags prüft das FM die Voraussetzungen und entscheidet über die Genehmigung. Alle weiteren Schritte werden vom FM begleitet und durchgeführt."}]},{"type":"paragraph","content":[{"type":"text","text":"Das Verfahren wird nur über ein internes Handbuch festgelegt."}]},{"type":"paragraph","content":[{"type":"text","text":"Testphase:"},{"type":"text","text":"Jede Fraktion / Gang besitzt nach \"Ankündigung zur Annahme\" eine 2 Wöchige Testphase. Diese Kann bei bedarf durchs FM auch verlängert werden."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"§10.1 -"},{"type":"text","text":"Strike-System"},{"type":"text","text":"Jede Strafe wird mittels einer FM-Internen Abstimmung beschlossen je nach Schwere können folgende Strafe gegeben werden."}]},{"type":"paragraph","content":[{"type":"text","text":"Frak-Ermahnung"}]},{"type":"paragraph","content":[{"type":"text","text":"Frak Strike"}]},{"type":"paragraph","content":[{"type":"text","text":"Leitungswechsel"}]},{"type":"paragraph","content":[{"type":"text","text":"Frak Auflösung"}]},{"type":"paragraph","content":[{"type":"text","text":"§10.2 - Strike Info´s"}]},{"type":"paragraph","content":[{"type":"text","text":"Erhälte eine Fraktion innerhalb der Test-Phase einen Strike wird sie sofort aufgelöst."}]},{"type":"paragraph","content":[{"type":"text","text":"Sollte eine Fraktion 3 Striks erhalten wird diese ebenfalls Aufgelöst / Leitungswechsel."}]},{"type":"paragraph","content":[{"type":"text","text":"Das FM entscheidet jede Strafe Situativ und jede Strafe kann Individuell getroffen werden."}]},{"type":"heading","attrs":{"level":1},"content":[{"type":"text","text":"Blacklist"}]}]}'::jsonb, '§10 – Gründung und Testphase neuer Fraktionen Antragstellung: Fraktionen können ausschließlich über ein Fraktions-Ticket beim Fraktionsmanagement beantragt werden. Gründungsberechtigung: Die Eröffnung und Einrichtung von Fraktionen erfolgt ausschließlich durch das Fraktionsmanagement. Eine eigenständige Gründung durch Spieler ist nicht gestattet. Verfahren: Nach Einreichung des Antrags prüft das FM die Voraussetzungen und entscheidet über die Genehmigung. Alle weiteren Schritte werden vom FM begleitet und durchgeführt. Das Verfahren wird nur über ein internes Handbuch festgelegt. Testphase: Jede Fraktion / Gang besitzt nach "Ankündigung zur Annahme" eine 2 Wöchige Testphase. Diese Kann bei bedarf durchs FM auch verlängert werden. §10.1 - Strike-System Jede Strafe wird mittels einer FM-Internen Abstimmung beschlossen je nach Schwere können folgende Strafe gegeben werden. Frak-Ermahnung Frak Strike Leitungswechsel Frak Auflösung §10.2 - Strike Info´s Erhälte eine Fraktion innerhalb der Test-Phase einen Strike wird sie sofort aufgelöst. Sollte eine Fraktion 3 Striks erhalten wird diese ebenfalls Aufgelöst / Leitungswechsel. Das FM entscheidet jede Strafe Situativ und jede Strafe kann Individuell getroffen werden. Blacklist', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-faction-11', 'faction-11', 'faction-11', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk/fraktionsregelwerk', 'Fraktionsregelwerk', '§11 Definition', 10, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-faction-11-v1', 'rule-faction-11', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Als"},{"type":"text","text":"„Blacklisted Fraktionen“"},{"type":"text","text":"gelten Fraktionen, deren Existenz, Ausrichtung oder Aktivitäten in direktem Widerspruch zu geltendem Recht, den RP-Serverregeln oder ethischen Standards stehen. Eine Blacklistung bedeutet ein vollständiges Verbot dieser Fraktionen auf dem Server. Jegliche Neugründung, Darstellung oder Bezugnahme auf diese Gruppen ist untersagt."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"§11.1 Gründe für eine Blacklistung"}]},{"type":"paragraph","content":[{"type":"text","text":"Die Gründe für eine Aufnahme auf die Blacklist umfassen unter anderem:"}]},{"type":"paragraph","content":[{"type":"text","text":"Illegale Aktivitäten: Beteiligung an oder Verherrlichung von kriminellen Handlungen."}]},{"type":"paragraph","content":[{"type":"text","text":"Hasspropaganda: Diskriminierung, Hetze oder gezielte Ausgrenzung von Personen(gruppen)."}]},{"type":"paragraph","content":[{"type":"text","text":"Gewaltverherrlichung: Darstellung oder Befürwortung von Gewalt, Terrorismus oder radikalen Aktionen."}]},{"type":"paragraph","content":[{"type":"text","text":"Störung des Spielbetriebs: Dauerhafte Beeinträchtigung des Roleplay-Erlebnisses anderer Spieler durch unangemessenes Verhalten oder Konzept."}]},{"type":"paragraph","content":[{"type":"text","text":"Wiederholte Regelverstöße: Anhaltende oder schwerwiegende Verstöße gegen Server- oder Fraktionsrichtlinien."}]},{"type":"paragraph","content":[{"type":"text","text":"Geringer RP-Wert: Fraktionen, die keinen sinnvollen Beitrag zum RP leisten oder sich nicht in das Gesamtbild einfügen."}]},{"type":"paragraph","content":[{"type":"text","text":"Mehrfache Ablehnung durch das Fraktionsmanagement: Bei wiederholt eingereichten und abgelehnten Konzepten."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"§11.2 Allgemein verbotene Fraktionstypen"}]},{"type":"paragraph","content":[{"type":"text","text":"Die folgenden Fraktionstypen sind serverweit dauerhaft verboten:"}]},{"type":"paragraph","content":[{"type":"text","text":"Reale illegale Organisationen: z. B. Drogenkartelle (Sinaloa-Kartell), Terrororganisationen (IS, Al-Qaida), mafiöse Strukturen."}]},{"type":"paragraph","content":[{"type":"text","text":"Anti-Terror- und Drogen-Sondereinheiten (Realbezug): Aufgrund der realpolitischen Sensibilität, fehlender RP-Balance und häufiger Missbrauch dieser Fraktionen für Macht-RP."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"§11.3 Konkrete Blacklistete Fraktionen (inkl. Begründung)"}]},{"type":"paragraph","content":[{"type":"text","text":"Fraktion"}]},{"type":"paragraph","content":[{"type":"text","text":"Grund für die Blacklistung"}]},{"type":"paragraph","content":[{"type":"text","text":"Reale Gang´s"},{"type":"text","text":"Da DRP, keine echten Gangs und somit auch deren Gewalten fördern möchte."}]},{"type":"paragraph","content":[{"type":"text","text":"Bundes POL"}]},{"type":"paragraph","content":[{"type":"text","text":"Keinen Nutzen"}]},{"type":"paragraph","content":[{"type":"text","text":"Wasserpolizei"}]},{"type":"paragraph","content":[{"type":"text","text":"Kann nicht ausgespielt werden"}]},{"type":"paragraph","content":[{"type":"text","text":"Bundeswehr"}]},{"type":"paragraph","content":[{"type":"text","text":"Mehrere Regelverstöße und keinen Mehrwert."}]},{"type":"paragraph","content":[{"type":"text","text":"Kommando Delta (Delta D)"},{"type":"text","text":"Wiederholte Regelverstöße, kein ernsthaftes RP, Störung des Spielbetriebs, Gambo Truppe"}]},{"type":"paragraph","content":[{"type":"text","text":"Geheimdienste"},{"type":"text","text":"Zu geringe Relevanz im RP-Alltag, fehlender Spielmehrwert, wiederholt ohne Erfolg beantragt – kein erkennbarer RP-Nutzen."}]},{"type":"paragraph","content":[{"type":"text","text":"DLRG"}]},{"type":"paragraph","content":[{"type":"text","text":"Zu geringe Relevanz im RP-Alltag, kaum Spielbeteiligung, mehrfach ohne Erfolg beantragt, kein RP-Nutzen."}]},{"type":"paragraph","content":[{"type":"text","text":"Verfassungsschutz"}]},{"type":"paragraph","content":[{"type":"text","text":"Kein RP-Nutzen ohne tiefgreifende Sicherheitsmechanik."}]},{"type":"paragraph","content":[{"type":"text","text":"GSG9 / MEK"}]},{"type":"paragraph","content":[{"type":"text","text":"Unnötige Spezialeinheit + zu viel Gambo"}]},{"type":"paragraph","content":[{"type":"text","text":"Anti-Gang-Force /"},{"type":"text","text":"Anti-Tuning-Taskforce / Anti-RP-Crime-Unit"},{"type":"text","text":"Aufgaben gehören zur normalen Polizei"},{"type":"text","text":","},{"type":"text","text":"Reines Power-RP, Künstliche Rechtfertigung für Sonderrechte"}]},{"type":"paragraph","content":[{"type":"text","text":"BKA / LKA"},{"type":"text","text":"Unnötig und hat viele probleme gemacht"},{"type":"text","text":"Forstamt"},{"type":"text","text":"Keine richtigen aufgaben"},{"type":"text","text":"Fahrschule"},{"type":"text","text":"Da sie keinen nutzen hat"},{"type":"text","text":"Mehrfach-Fraktionen mit gleichem Zweck ("},{"type":"text","text":"zb 2 Feuerwehr, 2 Rettungsdienste)"}]},{"type":"paragraph","content":[{"type":"text","text":"Spaltet Spieler, Führt zu Unterbesetzung, Keine spielerischen Vorteile"}]},{"type":"paragraph","content":[{"type":"text","text":"Zentrale Unterstüzungsgruppe Zoll"}]},{"type":"paragraph","content":[{"type":"text","text":"unnötig da das SEK Exsistiert."},{"type":"text","text":"Zoll"},{"type":"text","text":"Unnötig, in ERLC keinen Zweck"}]},{"type":"paragraph","content":[{"type":"text","text":"Regierung / Ämter / Bundesregierung"},{"type":"text","text":"Unnötig, zu viel macht, nicht ausspielbar."}]},{"type":"paragraph","content":[{"type":"text","text":"Justiz"}]},{"type":"paragraph","content":[{"type":"text","text":"Aktuell zu wenig aufgaben, und unnötig durch das fehlende Gericht."}]},{"type":"paragraph","content":[{"type":"text","text":"Mitgliederbegrenzung"}]}]}'::jsonb, '§11 Definition Als „Blacklisted Fraktionen“ gelten Fraktionen, deren Existenz, Ausrichtung oder Aktivitäten in direktem Widerspruch zu geltendem Recht, den RP-Serverregeln oder ethischen Standards stehen. Eine Blacklistung bedeutet ein vollständiges Verbot dieser Fraktionen auf dem Server. Jegliche Neugründung, Darstellung oder Bezugnahme auf diese Gruppen ist untersagt. §11.1 Gründe für eine Blacklistung Die Gründe für eine Aufnahme auf die Blacklist umfassen unter anderem: Illegale Aktivitäten: Beteiligung an oder Verherrlichung von kriminellen Handlungen. Hasspropaganda: Diskriminierung, Hetze oder gezielte Ausgrenzung von Personen(gruppen). Gewaltverherrlichung: Darstellung oder Befürwortung von Gewalt, Terrorismus oder radikalen Aktionen. Störung des Spielbetriebs: Dauerhafte Beeinträchtigung des Roleplay-Erlebnisses anderer Spieler durch unangemessenes Verhalten oder Konzept. Wiederholte Regelverstöße: Anhaltende oder schwerwiegende Verstöße gegen Server- oder Fraktionsrichtlinien. Geringer RP-Wert: Fraktionen, die keinen sinnvollen Beitrag zum RP leisten oder sich nicht in das Gesamtbild einfügen. Mehrfache Ablehnung durch das Fraktionsmanagement: Bei wiederholt eingereichten und abgelehnten Konzepten. §11.2 Allgemein verbotene Fraktionstypen Die folgenden Fraktionstypen sind serverweit dauerhaft verboten: Reale illegale Organisationen: z. B. Drogenkartelle (Sinaloa-Kartell), Terrororganisationen (IS, Al-Qaida), mafiöse Strukturen. Anti-Terror- und Drogen-Sondereinheiten (Realbezug): Aufgrund der realpolitischen Sensibilität, fehlender RP-Balance und häufiger Missbrauch dieser Fraktionen für Macht-RP. §11.3 Konkrete Blacklistete Fraktionen (inkl. Begründung) Fraktion Grund für die Blacklistung Reale Gang´s Da DRP, keine echten Gangs und somit auch deren Gewalten fördern möchte. Bundes POL Keinen Nutzen Wasserpolizei Kann nicht ausgespielt werden Bundeswehr Mehrere Regelverstöße und keinen Mehrwert. Kommando Delta (Delta D) Wiederholte Regelverstöße, kein ernsthaftes RP, Störung des Spielbetriebs, Gambo Truppe Geheimdienste Zu geringe Relevanz im RP-Alltag, fehlender Spielmehrwert, wiederholt ohne Erfolg beantragt – kein erkennbarer RP-Nutzen. DLRG Zu geringe Relevanz im RP-Alltag, kaum Spielbeteiligung, mehrfach ohne Erfolg beantragt, kein RP-Nutzen. Verfassungsschutz Kein RP-Nutzen ohne tiefgreifende Sicherheitsmechanik. GSG9 / MEK Unnötige Spezialeinheit + zu viel Gambo Anti-Gang-Force / Anti-Tuning-Taskforce / Anti-RP-Crime-Unit Aufgaben gehören zur normalen Polizei , Reines Power-RP, Künstliche Rechtfertigung für Sonderrechte BKA / LKA Unnötig und hat viele probleme gemacht Forstamt Keine richtigen aufgaben Fahrschule Da sie keinen nutzen hat Mehrfach-Fraktionen mit gleichem Zweck ( zb 2 Feuerwehr, 2 Rettungsdienste) Spaltet Spieler, Führt zu Unterbesetzung, Keine spielerischen Vorteile Zentrale Unterstüzungsgruppe Zoll unnötig da das SEK Exsistiert. Zoll Unnötig, in ERLC keinen Zweck Regierung / Ämter / Bundesregierung Unnötig, zu viel macht, nicht ausspielbar. Justiz Aktuell zu wenig aufgaben, und unnötig durch das fehlende Gericht. Mitgliederbegrenzung', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-faction-12', 'faction-12', 'faction-12', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk/fraktionsregelwerk', 'Fraktionsregelwerk', '§12.1 Maximal zulässige Mitgliederanzahl auf dem Server (pro Fraktion)', 11, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-faction-12-v1', 'rule-faction-12', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Da auf dem Server"},{"type":"text","text":"maximal 39 Spieler gleichzeitig"},{"type":"text","text":"aktiv sein können, gelten folgende Regelungen für die Anzahl aktiver Mitglieder je Fraktion:"}]},{"type":"paragraph","content":[{"type":"text","text":"➤"},{"type":"text","text":"Gangs:"}]},{"type":"paragraph","content":[{"type":"text","text":"Es dürfen maximal 6 Mitglieder einer Gang gleichzeitig auf dem Server aktiv sein."}]},{"type":"paragraph","content":[{"type":"text","text":"➤"},{"type":"text","text":"Allgemein"},{"type":"text","text":":"}]},{"type":"paragraph","content":[{"type":"text","text":"Es kann mit einer Ankündigung Mitglieder eingeschränkt werden bei Dysbalancen:"},{"type":"text","text":"Die Einschränkungen umfassenVerwehrung der TeilhabeCommand Vollstreckung (:wanted)Einsprüche:Mitten in einer RP-Situation"}]},{"type":"paragraph","content":[{"type":"text","text":"Die Einschränkungen umfassen"},{"type":"text","text":"Verwehrung der TeilhabeCommand Vollstreckung (:wanted)"}]},{"type":"paragraph","content":[{"type":"text","text":"Verwehrung der Teilhabe"}]},{"type":"paragraph","content":[{"type":"text","text":"Command Vollstreckung (:wanted)"}]},{"type":"paragraph","content":[{"type":"text","text":"Einsprüche:"},{"type":"text","text":"Mitten in einer RP-Situation"}]},{"type":"paragraph","content":[{"type":"text","text":"Mitten in einer RP-Situation"}]},{"type":"heading","attrs":{"level":1},"content":[{"type":"text","text":"§12.2 Besondere Regelungen"}]},{"type":"paragraph","content":[{"type":"text","text":"Serverauslastung: Wenn der Server nahezu voll ist (über 35/39 Spielern), kann das Serverteam die aktiven Mitgliederzahlen der Fraktionen kurzfristig weiter begrenzen."}]},{"type":"paragraph","content":[{"type":"text","text":"Ereignisbasierte Ausnahmen: Bei offiziellen Server-Events, Großeinsätzen oder geplanten RP-Szenarien kann die Fraktionsleitung Sondergenehmigungen beim Serverteam beantragen."}]},{"type":"paragraph","content":[{"type":"text","text":"Verpflichtung zur Rotation: Fraktionsleitungen sind verpflichtet, bei hoher Serverauslastung eine faire Rotation ihrer Mitglieder zu organisieren, sodass möglichst viele Spieler die Chance haben, mitzuspielen.Fraktionen / Gang´s"}]}]}'::jsonb, '§12.1 Maximal zulässige Mitgliederanzahl auf dem Server (pro Fraktion) Da auf dem Server maximal 39 Spieler gleichzeitig aktiv sein können, gelten folgende Regelungen für die Anzahl aktiver Mitglieder je Fraktion: ➤ Gangs: Es dürfen maximal 6 Mitglieder einer Gang gleichzeitig auf dem Server aktiv sein. ➤ Allgemein : Es kann mit einer Ankündigung Mitglieder eingeschränkt werden bei Dysbalancen: Die Einschränkungen umfassenVerwehrung der TeilhabeCommand Vollstreckung (:wanted)Einsprüche:Mitten in einer RP-Situation Die Einschränkungen umfassen Verwehrung der TeilhabeCommand Vollstreckung (:wanted) Verwehrung der Teilhabe Command Vollstreckung (:wanted) Einsprüche: Mitten in einer RP-Situation Mitten in einer RP-Situation §12.2 Besondere Regelungen Serverauslastung: Wenn der Server nahezu voll ist (über 35/39 Spielern), kann das Serverteam die aktiven Mitgliederzahlen der Fraktionen kurzfristig weiter begrenzen. Ereignisbasierte Ausnahmen: Bei offiziellen Server-Events, Großeinsätzen oder geplanten RP-Szenarien kann die Fraktionsleitung Sondergenehmigungen beim Serverteam beantragen. Verpflichtung zur Rotation: Fraktionsleitungen sind verpflichtet, bei hoher Serverauslastung eine faire Rotation ihrer Mitglieder zu organisieren, sodass möglichst viele Spieler die Chance haben, mitzuspielen.Fraktionen / Gang´s', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-faction-13', 'faction-13', 'faction-13', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk/fraktionsregelwerk', 'Fraktionsregelwerk', '§13 – Regelungen zu Gangs', 12, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-faction-13-v1', 'rule-faction-13', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§13.1 Kennzeichnung von Gangs"},{"type":"text","text":"Möchte eine Gang optische Kennzeichnungen wie z. B. Fahrzeuglackierungen, Kleidung oder andere visuelle Merkmale ändern, so ist dies im Vorfeld mit dem Fraktionsmanagement abzusprechen und schriftlich genehmigen zu lassen. Eine eigenmächtige Änderung ist untersagt. Jede Gang muss beim Beantragen bekannt geben welche Farbe, Auto"},{"type":"text","text":"s etc sie verwenden."},{"type":"text","text":"§14 - Gangkriege"}]}]}'::jsonb, '§13 – Regelungen zu Gangs §13.1 Kennzeichnung von Gangs Möchte eine Gang optische Kennzeichnungen wie z. B. Fahrzeuglackierungen, Kleidung oder andere visuelle Merkmale ändern, so ist dies im Vorfeld mit dem Fraktionsmanagement abzusprechen und schriftlich genehmigen zu lassen. Eine eigenmächtige Änderung ist untersagt. Jede Gang muss beim Beantragen bekannt geben welche Farbe, Auto s etc sie verwenden. §14 - Gangkriege', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-faction-14', 'faction-14', 'faction-14', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk/fraktionsregelwerk', 'Fraktionsregelwerk', '§14.1 Allgemeine Regelungen', 13, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-faction-14-v1', 'rule-faction-14', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"An einem Gangkrieg dürfen höchstens 2 Gangs teilnehmen. Jeder Gangkrieg muss schriftlich in einem Fraktionsticket angefragt und abgeklärt werden. Sollte dies nicht geschehen, ist der Krieg ungültig und alle Handlungen können als Gambo RP und Massen RDM geahndet werden. Besondere Strafen gibt es in der Nähe vom Spawn und Medics. Diese Strafen werden in Form von Fraktionsstrikes ausgehändigt, auch wenn es nur wenige Personen waren. Es dürfen nur Aktive unde Gekenzeichnete Gangmitglieder angegriffen werden."},{"type":"text","text":"Ein Gangkrieg darf insgesamt eine Länge von einer 2 Tage beantragt werden, eine verlängerung ist möglich."}]},{"type":"paragraph","content":[{"type":"text","text":"§14.2 Verfahren während eines Gangkriegs"}]},{"type":"paragraph","content":[{"type":"text","text":"Während einem laufenden Gangkrieg darf sich keine weitere Gang in das Geschehen einmischen. Die einzig gültige Drittpartei ist die Polizei (und die Spezialeinheiten). Sollten diese eingreifen, so muss das RP gemäß ausgespielt werden, auch wenn der Krieg dadurch schnell vorbei wäre."},{"type":"text","text":"In der Kriegszeit darf die Spielerzahl einer Gang überschritten werden. Die Spielerzahl wird dann von 6 auf maximal 10 Spieler pro Gang erhöht."}]},{"type":"paragraph","content":[{"type":"text","text":"§14."},{"type":"text","text":"3"},{"type":"text","text":"Eingriffsrecht des FM"},{"type":"text","text":"Das Fraktionsmanagement behält sich vor, einen geplanten oder laufenden Gangkrieg jederzeit zu stoppen oder anzupassen, wenn das RP aus dem Ruder läuft oder unfair geführt wird."}]}]}'::jsonb, '§14.1 Allgemeine Regelungen An einem Gangkrieg dürfen höchstens 2 Gangs teilnehmen. Jeder Gangkrieg muss schriftlich in einem Fraktionsticket angefragt und abgeklärt werden. Sollte dies nicht geschehen, ist der Krieg ungültig und alle Handlungen können als Gambo RP und Massen RDM geahndet werden. Besondere Strafen gibt es in der Nähe vom Spawn und Medics. Diese Strafen werden in Form von Fraktionsstrikes ausgehändigt, auch wenn es nur wenige Personen waren. Es dürfen nur Aktive unde Gekenzeichnete Gangmitglieder angegriffen werden. Ein Gangkrieg darf insgesamt eine Länge von einer 2 Tage beantragt werden, eine verlängerung ist möglich. §14.2 Verfahren während eines Gangkriegs Während einem laufenden Gangkrieg darf sich keine weitere Gang in das Geschehen einmischen. Die einzig gültige Drittpartei ist die Polizei (und die Spezialeinheiten). Sollten diese eingreifen, so muss das RP gemäß ausgespielt werden, auch wenn der Krieg dadurch schnell vorbei wäre. In der Kriegszeit darf die Spielerzahl einer Gang überschritten werden. Die Spielerzahl wird dann von 6 auf maximal 10 Spieler pro Gang erhöht. §14. 3 Eingriffsrecht des FM Das Fraktionsmanagement behält sich vor, einen geplanten oder laufenden Gangkrieg jederzeit zu stoppen oder anzupassen, wenn das RP aus dem Ruder läuft oder unfair geführt wird.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-faction-15', 'faction-15', 'faction-15', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk/fraktionsregelwerk', 'Fraktionsregelwerk', '§15 – Gerichtsverfahren und anwaltliche Abläufe', 14, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-faction-15-v1', 'rule-faction-15', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§15.1 – Festnahme und Überstellung"},{"type":"text","text":"Nach einer Festnahme durch die Polizei ist die betroffene Person zur zuständigen Polizeidienststelle zu verbringen. Dort verbleibt sie bis zur weiteren Entscheidung über das weitere Vorgehen."}]},{"type":"paragraph","content":[{"type":"text","text":"§15.2 – Warten auf einen Richter"},{"type":"text","text":"An der Polizeidienststelle ist auf das Eintreffen eines Richters zu warten. Ist ein Richter verfügbar, wird die festgenommene Person zur Verhandlung vorgeführt."}]},{"type":"paragraph","content":[{"type":"text","text":"§15.3 – Kein Richter verfügbar"},{"type":"text","text":"Sollte innerhalb einer angemessenen Zeit kein Richter verfügbar sein, ist die festgenommene Person ohne weitere Verzögerung in das Gefängnis zu überstellen. Ein unnötiges Hinauszögern des Roleplays ist zu vermeiden."}]},{"type":"paragraph","content":[{"type":"text","text":"§15.4 – Ablauf der Verhandlung"},{"type":"text","text":"Sobald die festgenommene Person vor einem Richter steht, beginnt die Verhandlung. Diese ist strukturiert, sachlich und zielgerichtet durchzuführen."}]},{"type":"paragraph","content":[{"type":"text","text":"§15.5 – Zeitliche Begrenzung"},{"type":"text","text":"Die Dauer einer Verhandlung darf maximal 10 Minuten betragen. Ziel ist es, ein flüssiges und nicht überzogenes Roleplay zu gewährleisten."}]},{"type":"paragraph","content":[{"type":"text","text":"§15.6 – Überschreitung der Verhandlungsdauer"},{"type":"text","text":"Wird die maximale Verhandlungsdauer von 10 Minuten überschritten, ist die festgenommene Person unverzüglich freizulassen. Eine weitere Fortführung der Verhandlung ist in diesem Fall unzulässig."}]},{"type":"paragraph","content":[{"type":"text","text":"§15.7 – Rolle von Anwälten"},{"type":"text","text":"Anwälte dürfen im Rahmen der Verhandlung beratend und unterstützend tätig sein, haben sich jedoch an die vorgegebenen Abläufe sowie die zeitliche Begrenzung zu halten."}]},{"type":"paragraph","content":[{"type":"text","text":"§15.8 – Ziel der Regelung"},{"type":"text","text":"Diese Regelung dient dazu, langwierige oder unnötig komplizierte Gerichtsverfahren zu vermeiden und ein dynamisches sowie faires Roleplay für alle Beteiligten sicherzustellen."}]}]}'::jsonb, '§15 – Gerichtsverfahren und anwaltliche Abläufe §15.1 – Festnahme und Überstellung Nach einer Festnahme durch die Polizei ist die betroffene Person zur zuständigen Polizeidienststelle zu verbringen. Dort verbleibt sie bis zur weiteren Entscheidung über das weitere Vorgehen. §15.2 – Warten auf einen Richter An der Polizeidienststelle ist auf das Eintreffen eines Richters zu warten. Ist ein Richter verfügbar, wird die festgenommene Person zur Verhandlung vorgeführt. §15.3 – Kein Richter verfügbar Sollte innerhalb einer angemessenen Zeit kein Richter verfügbar sein, ist die festgenommene Person ohne weitere Verzögerung in das Gefängnis zu überstellen. Ein unnötiges Hinauszögern des Roleplays ist zu vermeiden. §15.4 – Ablauf der Verhandlung Sobald die festgenommene Person vor einem Richter steht, beginnt die Verhandlung. Diese ist strukturiert, sachlich und zielgerichtet durchzuführen. §15.5 – Zeitliche Begrenzung Die Dauer einer Verhandlung darf maximal 10 Minuten betragen. Ziel ist es, ein flüssiges und nicht überzogenes Roleplay zu gewährleisten. §15.6 – Überschreitung der Verhandlungsdauer Wird die maximale Verhandlungsdauer von 10 Minuten überschritten, ist die festgenommene Person unverzüglich freizulassen. Eine weitere Fortführung der Verhandlung ist in diesem Fall unzulässig. §15.7 – Rolle von Anwälten Anwälte dürfen im Rahmen der Verhandlung beratend und unterstützend tätig sein, haben sich jedoch an die vorgegebenen Abläufe sowie die zeitliche Begrenzung zu halten. §15.8 – Ziel der Regelung Diese Regelung dient dazu, langwierige oder unnötig komplizierte Gerichtsverfahren zu vermeiden und ein dynamisches sowie faires Roleplay für alle Beteiligten sicherzustellen.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-faction-16', 'faction-16', 'faction-16', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk/fraktionsregelwerk', 'Fraktionsregelwerk', '§16 Justiz- & Anwalts-RP (Fairness, Realismus & Zumutbarkeit)', 15, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-faction-16-v1', 'rule-faction-16', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§16.1 Beweisführung"},{"type":"text","text":"Aussagen allein gelten nicht als ausreichender Beweis."},{"type":"text","text":"Zulässige Beweismittel sind:"}]},{"type":"paragraph","content":[{"type":"text","text":"Videoaufnahmen / Clips"}]},{"type":"paragraph","content":[{"type":"text","text":"Screenshots"}]},{"type":"paragraph","content":[{"type":"text","text":"Nachvollziehbares Ingame-RP (z. B. sichtbare Handlungen, Logs sofern vorhanden)"}]},{"type":"paragraph","content":[{"type":"text","text":"Zeugenaussagen dürfen berücksichtigt werden, haben jedoch ohne zusätzliche Beweise nur eingeschränkte Aussagekraft."}]},{"type":"paragraph","content":[{"type":"text","text":"§16.2 Zumutbarkeit"},{"type":"text","text":"Jedes Justiz-RP muss für alle Beteiligten spielbar bleiben."},{"type":"text","text":"Nicht erlaubt sind:"}]},{"type":"paragraph","content":[{"type":"text","text":"unnötiges in die Länge ziehen von Verfahren"}]},{"type":"paragraph","content":[{"type":"text","text":"absichtliches Blockieren von Fraktionen durch RP"}]},{"type":"paragraph","content":[{"type":"text","text":"erzwungene Szenarien ohne Gegenreaktionsmöglichkeit"}]},{"type":"paragraph","content":[{"type":"text","text":"§16.3 Unzulässigkeit von Haft-Einheiten im Roleplay"}]},{"type":"paragraph","content":[{"type":"text","text":"Sogenannte „Haft-Einheiten“, eigenständige Gefängnis-Fraktionen oder vergleichbare Konstrukte sind im Roleplay nicht anerkannt und daher unzulässig."}]},{"type":"paragraph","content":[{"type":"text","text":"Freiheitsentziehende Maßnahmen dürfen ausschließlich durch dafür vorgesehene und realistisch eingebundene Fraktionen (z. B. Polizei) durchgeführt werden. Das eigenständige Betreiben, Verwalten oder Ausspielen von Haftanstalten durch nicht vorgesehene Einheiten ist untersagt."}]},{"type":"paragraph","content":[{"type":"text","text":"Untersagt sind insbesondere:"}]},{"type":"paragraph","content":[{"type":"text","text":"Gründung oder Betrieb von eigenen Gefängnis- oder Haft-Fraktionen"}]},{"type":"paragraph","content":[{"type":"text","text":"Eigenständiges Inhaftieren von Personen außerhalb polizeilicher Maßnahmen"}]},{"type":"paragraph","content":[{"type":"text","text":"Ausspielen von „privaten“ oder nicht autorisierten Haftstrukturen"}]},{"type":"paragraph","content":[{"type":"text","text":"Umgehen bestehender Systeme durch eigene Haftkonzepte"}]},{"type":"paragraph","content":[{"type":"text","text":"Diese Regel dient der Wahrung eines klaren, realistischen und fairen Roleplay-Ablaufs."}]},{"type":"paragraph","content":[{"type":"text","text":"Verstöße führen zur sofortigen Auflösung entsprechender Strukturen sowie zu Sanktionen gegen die beteiligten Personen."}]}]}'::jsonb, '§16 Justiz- & Anwalts-RP (Fairness, Realismus & Zumutbarkeit) §16.1 Beweisführung Aussagen allein gelten nicht als ausreichender Beweis. Zulässige Beweismittel sind: Videoaufnahmen / Clips Screenshots Nachvollziehbares Ingame-RP (z. B. sichtbare Handlungen, Logs sofern vorhanden) Zeugenaussagen dürfen berücksichtigt werden, haben jedoch ohne zusätzliche Beweise nur eingeschränkte Aussagekraft. §16.2 Zumutbarkeit Jedes Justiz-RP muss für alle Beteiligten spielbar bleiben. Nicht erlaubt sind: unnötiges in die Länge ziehen von Verfahren absichtliches Blockieren von Fraktionen durch RP erzwungene Szenarien ohne Gegenreaktionsmöglichkeit §16.3 Unzulässigkeit von Haft-Einheiten im Roleplay Sogenannte „Haft-Einheiten“, eigenständige Gefängnis-Fraktionen oder vergleichbare Konstrukte sind im Roleplay nicht anerkannt und daher unzulässig. Freiheitsentziehende Maßnahmen dürfen ausschließlich durch dafür vorgesehene und realistisch eingebundene Fraktionen (z. B. Polizei) durchgeführt werden. Das eigenständige Betreiben, Verwalten oder Ausspielen von Haftanstalten durch nicht vorgesehene Einheiten ist untersagt. Untersagt sind insbesondere: Gründung oder Betrieb von eigenen Gefängnis- oder Haft-Fraktionen Eigenständiges Inhaftieren von Personen außerhalb polizeilicher Maßnahmen Ausspielen von „privaten“ oder nicht autorisierten Haftstrukturen Umgehen bestehender Systeme durch eigene Haftkonzepte Diese Regel dient der Wahrung eines klaren, realistischen und fairen Roleplay-Ablaufs. Verstöße führen zur sofortigen Auflösung entsprechender Strukturen sowie zu Sanktionen gegen die beteiligten Personen.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "Rule" ("id", "slug", "sourceKey", "sourceUrl", "category", "title", "order", "version", "published", "createdAt", "updatedAt") VALUES
  ('rule-faction-17', 'faction-17', 'faction-17', 'https://sites.google.com/view/deutschland-rp-regelwerk/regelwerk/fraktionsregelwerk', 'Fraktionsregelwerk', '§17 Up- Downranks Fraktionen / Gangs', 16, 1, true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO "RuleRevision" ("id", "ruleId", "status", "content", "searchText", "createdAt", "updatedAt", "publishedAt") VALUES
  ('revision-faction-17-v1', 'rule-faction-17', 'PUBLISHED', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"§1"},{"type":"text","text":"7"},{"type":"text","text":".1 Upranks / Downranks"}]},{"type":"paragraph","content":[{"type":"text","text":"Willkürliche oder nicht nachvollziehbare Up- und Downranks sind vorab mit dem FM abzuklären. Eigenmächtige, unverhältnismäßige Einstufungen sind nicht gestattet."}]}]}'::jsonb, '§17 Up- Downranks Fraktionen / Gangs §1 7 .1 Upranks / Downranks Willkürliche oder nicht nachvollziehbare Up- und Downranks sind vorab mit dem FM abzuklären. Eigenmächtige, unverhältnismäßige Einstufungen sind nicht gestattet.', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
